import React, { useState, useEffect, useRef } from 'react';
import PropTypes from 'prop-types';
import { isDescendant } from './utils/tree-data-utils';
import classnames from './utils/classnames';
import { Manager, Reference } from 'react-popper';
import './node-renderer-default.css';
import Editor from './Editor';
import { useDrag } from 'react-dnd';
import FAWTooltip from "../../component-widget/FAWTooltip";
import { colors } from '../../../utils/designTokens';
import ExpandDownIcon from "@diligentcorp/atlas-react-icons/dist/esm/lens/ExpandDown.js";
import ExpandRightIcon from "@diligentcorp/atlas-react-icons/dist/esm/lens/ExpandRight.js";

function NodeRendererDefault(props) {
  const {
    scaffoldBlockPxWidth,
    toggleChildrenVisibility = null,
    isDragging,
    canDrop = false,
    canDrag = false,
    node,
    title = null,
    isTitleEditable = false,
    handleTitleChange = () => {},
    subtitle = null,
    draggedNode = null,
    path,
    treeIndex,
    isSearchMatch = false,
    isSearchFocus = false,
    buttons = [],
    className = '',
    style = {},
    didDrop,
    treeId,
    isOver,
    parentNode = null,
    rowDirection = 'ltr',
    handleNodeClick,
    dropdownMenu,
    openDropdownMenu,
    isMenuHidden: isMenuHiddenProp,
    currentNodeId,
    getNodeIcon,
    getHighLightStyle,
    getCustomNodeClass,
    isHighlighted,
    hasMenuOptions,
    ...otherProps
  } = props;

  const isMenuHidden = isMenuHiddenProp !== undefined ? isMenuHiddenProp : true;
  
  const finalIsMenuHidden = isMenuHidden;
  
  

  const nodeTitle = title || node.title;
  const rowDirectionClass = rowDirection === 'rtl' ? 'rst__rtl' : null;

  const dragRef = useRef(null);
  const previewRef = useRef(null);
  const [{ isDragging: dragState }, drag, preview] = useDrag({
    type: 'TREE_NODE',
    item: { node, path, treeIndex },
    collect: (monitor) => ({
      isDragging: monitor.isDragging(),
    }),
    canDrag: canDrag,
  });
  drag(dragRef);
  preview(previewRef);

  const getTaskTypeName = (type) => {
    switch (type) {
      case 'SECTION': return 'Section';
      case 'STEP': return 'Step';
      case 'ROUTE_TO': return 'Route To';
      case 'REVIEW': return 'Review';
      case 'ACTION': return 'Action';
      case 'NOTIFICATION': return 'Notification';
      case 'IF': return 'Conditional';
      case 'CLOSE': return 'Close';
      case 'EDIT': return 'Edit';
      case 'APPROVE': return 'Approve';
      case 'GO_TO': return 'Go To';
      case 'CONDITIONAL_SNIPPET': return 'Conditional Snippet';
      default: return 'Task';
    }
  };

  // Icons now have individual tooltips (status icon shows progress, type icon shows task type)
  // So we don't need the outer tooltip wrapper
  let handle = (
    <div className="rst__handle">
      {getNodeIcon(node)}
    </div>
  );
  if (canDrag) {
    if (typeof node.children === 'function' && node.expanded) {
      handle = (
        <div className="rst__handle rst__loadingHandle">
          <div className="rst__loadingCircle">
            {[...new Array(12)].map((_, index) => (
              <div
                key={index}
                className={classnames('rst__loadingCirclePoint', rowDirectionClass)}
              />
            ))}
          </div>
        </div>
      );
    } else {
      handle = (
        <div ref={dragRef} className="rst__handle rst__moveHandle">
          {getNodeIcon(node)}
        </div>
      );
    }
  }

  const isDraggedDescendant = draggedNode && isDescendant(draggedNode, node);
  const isLandingPadActive = !didDrop && dragState;

  let buttonStyle = { left: -0.5 * scaffoldBlockPxWidth };
  if (rowDirection === 'rtl') {
    buttonStyle = { right: -0.5 * scaffoldBlockPxWidth };
  }

  return (
    <div style={{ height: '100%' }} {...otherProps}>
      {toggleChildrenVisibility &&
        node.children &&
        (node.children.length > 0 || typeof node.children === 'function') && (
          <div>
            <button
              type="button"
              aria-label={node.expanded ? 'Collapse' : 'Expand'}
              className={classnames(
                'rst__expandCollapseButton',
                rowDirectionClass
              )}
              style={buttonStyle}
              onClick={() =>
                toggleChildrenVisibility({
                  node,
                  path,
                  treeIndex,
                })
              }
            >
              {node.expanded ? (
                <ExpandDownIcon size="lg" style={{ display: 'block', width: '20px', height: '20px' }} />
              ) : (
                <ExpandRightIcon size="lg" style={{ display: 'block', width: '20px', height: '20px' }} />
              )}
            </button>

          </div>
        )}

      <div className={classnames('rst__rowWrapper', rowDirectionClass)}>
        <div
          ref={previewRef}
          className={classnames(
            'rst__row',
            isLandingPadActive && 'rst__rowLandingPad',
            isLandingPadActive && !canDrop && 'rst__rowCancelPad',
            isSearchMatch && 'rst__rowSearchMatch',
            isSearchFocus && 'rst__rowSearchFocus',
            getCustomNodeClass && getCustomNodeClass(node),
            rowDirectionClass,
            className
          )}
          style={{
            opacity: isDraggedDescendant ? 0.5 : 1,
            ...style,
            ...(isHighlighted && isHighlighted(node) && getHighLightStyle(node)),
          }}
          id={`task__${node.id}`}
          data-tree-depth={path ? path.length : 0}
          data-tree-index={treeIndex}
          data-node-id={node.id}
          data-has-children={node.children && node.children.length > 0}
          data-children-count={node.children ? node.children.length : 0}
        >
          {handle}

          <div
            className={classnames(
              'rst__rowContents',
              !canDrag && 'rst__rowContentsDragDisabled',
              rowDirectionClass
            )}
            style={{ position: 'relative' }}
            onClick={() => handleNodeClick(props)}
          >
            <FAWTooltip title={nodeTitle} placement="top">
            <div className={classnames('rst__rowLabel', rowDirectionClass)}>
              <span
                className={classnames(
                  'rst__rowTitle'
                )}
              >
                {typeof nodeTitle === 'function' ? (
                  nodeTitle({
                    node,
                    path,
                    treeIndex,
                  })
                ) : isTitleEditable && currentNodeId === node.id ? (
                  <Editor
                    value={nodeTitle}
                    handleChange={({ value, prevValue }) =>
                      handleTitleChange({ value, prevValue, nodeId: node.id })
                    }
                  />
                ) : (
                  nodeTitle
                )}
              </span>
            </div>
            </FAWTooltip>
          </div>

          {/* Toolbar moved INSIDE the row to be part of flex layout */}
          {(() => {
            const shouldRenderToolbar = !!dropdownMenu && !!openDropdownMenu;
            
            
            return shouldRenderToolbar;
          })() ? (
            <div className="rst__rowToolbar rst__rowToolbar--outside-indent">
              {(() => {
                return null;
              })()}
              {buttons.map((btn, index) => (
                <div
                  key={index}
                  className="rst__toolbarButton"
                  onClick={(e) => {
                    e.stopPropagation();
                    openDropdownMenu(node);
                  }}
                >
                  {btn}
                </div>
              ))}
            </div>
          ) : null}
          
          {/* Render dropdown if this node should show it */}
          {(() => {
            if (dropdownMenu && !finalIsMenuHidden) {
              try {
                const props = { node: node };
                const dropdownComponent = dropdownMenu(props);
                return (
                  <div style={{
                    position: 'absolute',
                    top: '100%',
                    right: '0',
                    zIndex: 1000,
                    backgroundColor: colors.background.default || 'white',
                    border: `1px solid ${colors.ui.border.static || '#ccc'}`,
                    borderRadius: '4px',
                    boxShadow: '0 2px 8px rgba(0,0,0,0.15)',
                    minWidth: '200px'
                  }}>
                    {dropdownComponent}
                  </div>
                );
              } catch (error) {
                return null;
              }
            }
            return null;
          })()}
        </div>
      </div>
      
      {/* Toolbar is now inside the row as part of flex layout */}
    </div>
  );
}

NodeRendererDefault.propTypes = {
  node: PropTypes.shape({}).isRequired,
  title: PropTypes.oneOfType([PropTypes.func, PropTypes.node]),
  subtitle: PropTypes.oneOfType([PropTypes.func, PropTypes.node]),
  path: PropTypes.arrayOf(PropTypes.oneOfType([PropTypes.string, PropTypes.number])).isRequired,
};

export default NodeRendererDefault;
