const getTypeIconLocal = (type, node = null, isDefinitionMode = false) => {
  const normalizedType = type ? String(type).toUpperCase() : null;
  
  const iconProps = { size: "lg", style: { display: 'block', width: '24px', height: '24px' } };
  
  // In execution mode, show status icon before task type icon
  // Map all status codes to appropriate icons with colors
  const statusIcon = !isDefinitionMode && node && node.statusCode ? (() => {
    // Normalize statusCode to uppercase for comparison (backend may send in different cases)
    const statusCode = String(node.statusCode).toUpperCase();
    
    let iconComponent = null;
    let statusTooltip = '';
    
    switch (statusCode) {
      case WORK_ITEM_TASK_STATUS.COMPLETE:
        iconComponent = <CheckedCircleIcon style={{ width: '20px', height: '20px', fill: colors.status.success }} />;
        statusTooltip = 'Completed';
        break;
      case WORK_ITEM_TASK_STATUS.ACTIVE:
        iconComponent = <RefreshCircleIcon style={{ width: '20px', height: '20px', fill: colors.action.link.default }} />;
        statusTooltip = 'Active';
        break;
      case WORK_ITEM_TASK_STATUS.PENDING:
        iconComponent = <RefreshCircleIcon style={{ width: '20px', height: '20px', fill: colors.action.link.default }} />;
        statusTooltip = 'Pending';
        break;
      case WORK_ITEM_TASK_STATUS.REMOVED:
        iconComponent = <RemoveCircleIcon style={{ width: '20px', height: '20px', fill: colors.status.error }} />;
        statusTooltip = 'Removed';
        break;
      default:
        iconComponent = <CircleLineIcon style={{ width: '20px', height: '20px', fill: colors.type.tertiary }} />;
        statusTooltip = 'Unknown Status';
        break;
    }
    
    if (!iconComponent) {
      return null;
    }
    
    return (
      <FAWTooltip title={statusTooltip} placement="right">
        <span style={{ display: 'inline-flex', width: '20px', height: '20px', marginRight: '4px', flexShrink: 0, alignItems: 'center', justifyContent: 'center' }}>
          {iconComponent}
        </span>
      </FAWTooltip>
    );
  })() : null;
  
  // Get task type name for tooltip
  const getTaskTypeName = (type) => {
    switch (type) {
      case 'SECTION': return 'Section';
      case 'STEP': return 'Step';
      case 'ROUTE_TO': return 'Route To';
      case 'REVIEW': return 'Review';
      case 'ACTION': return 'Action';
      case 'NOTIFICATION': return 'Notification';
      case 'IF': return 'Conditional';
      case 'CLOSE': return 'Close';
      default: return 'Task';
    }
  };
  
  const typeName = getTaskTypeName(normalizedType);
  
  let typeIcon;
  switch (normalizedType) {
    case 'SECTION':
      typeIcon = <StackIcon {...iconProps} />;
      break;
    case 'STEP':
      typeIcon = <NextStepIcon {...iconProps} />;
      break;
    case 'ROUTE_TO':
      typeIcon = <ForkIcon {...iconProps} />;
      break;
    case 'REVIEW':
      typeIcon = <ReviewIcon {...iconProps} />;
      break;
    case 'ACTION':
      typeIcon = <FlagIcon {...iconProps} />;
      break;
    case 'NOTIFICATION':
      typeIcon = <AlertOnIcon {...iconProps} />;
      break;
    case 'IF':
      typeIcon = <FlowsIcon {...iconProps} />;
      break;
    case 'CLOSE':
      typeIcon = <ClearIcon {...iconProps} />;
      break;
    default:
      typeIcon = <NextStepIcon {...iconProps} />;
      break;
  }
  
  // Wrap type icon with tooltip
  const typeIconWithTooltip = (
    <FAWTooltip title={typeName} placement="right">
      <span style={{ display: 'inline-block', width: '24px', height: '24px' }}>
        {typeIcon}
      </span>
    </FAWTooltip>
  );
  
  // If status icon exists, wrap both in an <i> tag to match original structure
  if (statusIcon) {
    return (
      <i style={{ display: 'flex', alignItems: 'center', gap: '4px', width: 'auto', flexShrink: 0, marginRight: '8px' }}>
        {statusIcon}
        {typeIconWithTooltip}
      </i>
    );
  }
  
  // Wrap single icon in <i> tag for consistency
  return <i style={{ width: 'auto', flexShrink: 0, marginRight: '8px' }}>{typeIconWithTooltip}</i>;
};


const ThreeDotsVerticalIcon = ({ size = "lg", title }) => (
  <MoreIcon size={size} title={title} />
);

const DropdownMenu = React.memo(({
  id,
  isComplete,
  statusCode,
  canTakeOwnership,
  canReleaseOwnership,
  isOwnedByCurrentUser,
  canBeRemoved,
  isSoftRemoved,
  allowTypeList = [],
  workItem,
  children,
  type,
  IsRoot = false, // Use IsRoot directly from backend (PascalCase)
  index = 0,
  siblingsCount = 0,
  sectionMenu = [],
  canAppendChild = true,
  isSnippet = false,
  isDefinitionMode = false,
  addTaskAsync,
  removeTaskAsync,
  restoreTaskAsync,
  moveTaskAsync,
  moveTaskToSectionAsync,
  saveInsertSnippetAsync,
  setPredecessorModalOpen,
  setSnippetModalOpen,
  setMenuOpenNodeId,
  handleAction,
  handleError
}) => {
  const isRootNode = IsRoot;
  
  // Memoize parentTaskId calculation to avoid recomputation on every render
  const parentTaskId = useMemo(() => {
    if (isRootNode) return 0;
    if (!id || id === '' || id === null || id === undefined) return 0;
    if (typeof id === 'string') {
      const parsed = parseInt(id, 10);
      return isNaN(parsed) ? 0 : parsed;
    }
    return typeof id === 'number' ? id : 0;
  }, [isRootNode, id]);
  
  // Derive isComplete from statusCode if not provided (backend doesn't provide isComplete directly)
  const computedIsComplete = isComplete ?? (statusCode === WORK_ITEM_TASK_STATUS.COMPLETE);
  const allowAdhocEdit = !computedIsComplete && workItem?.allowAdhocFlowEdit;

  const config = [
    {
      label: "Take ownership",
      icon: <FiUserPlus size="lg" />,
      tooltip: "Take ownership of this task to work on it",
      onClick: [
        () =>
          handleAction({
            actionType: WORK_ITEM_TASK_ACTIONS.TAKE_OWNERSHIP,
            workItemId: workItem?.id || 0,
            id,
            payload: { mode: ACTION_MODES.TREE },
          }),
      ],
      condition:
        !computedIsComplete &&
        !isOwnedByCurrentUser &&
        canTakeOwnership &&
        canActionOnTreeMode({
          actionType: WORK_ITEM_TASK_ACTIONS.TAKE_OWNERSHIP,
          children,
        }),
    },
    {
      label: "Release ownership",
      icon: <FiUserMinus size="lg" />,
      tooltip: "Release ownership of this task so others can work on it",
      onClick: [
        () =>
          handleAction({
            actionType: WORK_ITEM_TASK_ACTIONS.RELEASE_OWNERSHIP,
            workItemId: workItem?.id || 0,
            id,
            payload: { mode: ACTION_MODES.TREE },
          }),
      ],
      condition:
        !computedIsComplete &&
          canReleaseOwnership &&
          canActionOnTreeMode({
              actionType: WORK_ITEM_TASK_ACTIONS.RELEASE_OWNERSHIP,
              children,
          }),
    },
    {
      label: "Mark Complete",
      icon: <FiCheck size="lg" />,
      tooltip: "Mark this task as completed",
      onClick: [
        () =>
          handleAction({
            actionType: WORK_ITEM_TASK_ACTIONS.MARK_COMPLETE,
            workItemId: workItem?.id || 0,
            id,
            payload: { mode: ACTION_MODES.TREE },
          }),
      ],
      condition:
        !computedIsComplete &&
        isOwnedByCurrentUser &&
        type !== WORK_ITEM_TASK_TYPES.APPROVE &&
        canActionOnTreeMode({
          actionType: WORK_ITEM_TASK_ACTIONS.MARK_COMPLETE,
          children,
        }),
    },
    {
      label: "Add Section",
      icon: getTypeIconLocal('SECTION'),
      tooltip: "Add a new section to organize workflow tasks",
      condition: isDefinitionMode 
        ? (canAppendChild && !isRootNode)
        : allowAdhocEdit && (allowTypeList.length === 0 || allowTypeList.includes('SECTION')),
      onClick: [() => addTaskAsync(workItem?.id || 0, parentTaskId, 'SECTION', handleError)],
    },
    {
      label: "Add Step",
      icon: getTypeIconLocal('STEP'),
      tooltip: "Add a new step to the workflow",
      condition: isDefinitionMode 
        ? (canAppendChild && !isRootNode)
        : allowAdhocEdit && (allowTypeList.length === 0 || allowTypeList.includes('STEP')),
      onClick: [() => addTaskAsync(workItem?.id || 0, parentTaskId, 'STEP', handleError)],
    },
    {
      label: "Add Route",
      icon: getTypeIconLocal('ROUTE_TO'),
      tooltip: "Add a new route to redirect workflow flow",
      condition: isDefinitionMode && canAppendChild && !isRootNode,
      definitionOnly: true, // Hide completely in execution mode
      onClick: [() => addTaskAsync(workItem?.id || 0, parentTaskId, 'ROUTE_TO', handleError)],
    },
    {
      label: "Add Edit",
      icon: getTypeIconLocal('EDIT'),
      tooltip: "Add a new edit task to the workflow",
      condition: !isDefinitionMode && allowAdhocEdit && (allowTypeList.length === 0 || allowTypeList.includes('EDIT')),
      onClick: [() => addTaskAsync(workItem?.id || 0, parentTaskId, 'EDIT', handleError)],
    },
    {
      label: "Add Approve",
      icon: getTypeIconLocal('APPROVE'),
      tooltip: "Add a new approve task to the workflow",
      condition: !isDefinitionMode && allowAdhocEdit && (allowTypeList.length === 0 || allowTypeList.includes('APPROVE')),
      onClick: [() => addTaskAsync(workItem?.id || 0, parentTaskId, 'APPROVE', handleError)],
    },
    {
      label: "Add Review",
      icon: getTypeIconLocal('REVIEW'),
      tooltip: "Add a new review task to the workflow",
      condition: isDefinitionMode 
        ? (canAppendChild && !isRootNode)
        : allowAdhocEdit && (allowTypeList.length === 0 || allowTypeList.includes('REVIEW')),
      onClick: [() => addTaskAsync(workItem?.id || 0, parentTaskId, 'REVIEW', handleError)],
    },
    {
      label: "Add Action",
      icon: getTypeIconLocal('ACTION'),
      tooltip: "Add a new action task to the workflow",
      condition: isDefinitionMode && canAppendChild && !isRootNode,
      definitionOnly: true, // Hide completely in execution mode
      onClick: [() => addTaskAsync(workItem?.id || 0, parentTaskId, 'ACTION', handleError)],
    },
    {
      label: "Add Notification",
      icon: getTypeIconLocal('NOTIFICATION'),
      tooltip: "Add a new notification task to the workflow",
      condition: isDefinitionMode && canAppendChild && !isRootNode,
      definitionOnly: true, // Hide completely in execution mode
      onClick: [() => addTaskAsync(workItem?.id || 0, parentTaskId, 'NOTIFICATION', handleError)],
    },
    {
      label: "Add Conditional Snippet",
      icon: getTypeIconLocal('IF'),
      tooltip: "Add a new conditional snippet to the workflow",
      condition: isDefinitionMode && canAppendChild && !isRootNode,
      definitionOnly: true, // Hide completely in execution mode
      onClick: [() => addTaskAsync(workItem?.id || 0, parentTaskId, 'IF', handleError)],
    },
    {
      label: "Add Close",
      icon: getTypeIconLocal('CLOSE'),
      tooltip: "Add a new close task to end the workflow",
      condition: isDefinitionMode 
        ? (canAppendChild && !isRootNode)
        : allowAdhocEdit && (allowTypeList.length === 0 || allowTypeList.includes('CLOSE')),
      onClick: [() => addTaskAsync(workItem?.id || 0, parentTaskId, 'CLOSE', handleError)],
    },
    {
      label: "Insert Snippet",
      icon: <NewTabIcon size="lg" />,
      tooltip: "Insert an existing snippet into the workflow",
      condition: isDefinitionMode ? !isSnippet : allowAdhocEdit,
      onClick: [() => setSnippetModalOpen(true)],
    },
    {
      label: "Remove",
      icon: <TrashIcon size="lg" />,
      tooltip: "Remove this task from the workflow",
      condition: isDefinitionMode ? !isRootNode : workItem?.allowAdhocFlowEdit && canBeRemoved,
      onClick: [() => removeTaskAsync(workItem?.id || 0, id, handleError)],
    },
    {
      label: "Restore",
      icon: <FiRotateCcw size="lg" />,
      tooltip: "Restore this previously removed task",
      condition: workItem?.allowAdhocFlowEdit && isSoftRemoved,
      onClick: [() => restoreTaskAsync(workItem?.id || 0, id, handleError)],
    },
    {
      label: "Move Up",
      icon: <ArrowUpIcon size="lg" />,
      tooltip: "Move this task up in the workflow order",
      condition: isDefinitionMode && !isRootNode && index > 0,
      definitionOnly: true, // Hide completely in execution mode (not just disable)
      onClick: [() => moveTaskAsync(workItem?.id || 0, id, true, handleError)],
    },
    {
      label: "Move Down", 
      icon: <ArrowDownIcon size="lg" />,
      tooltip: "Move this task down in the workflow order",
      condition: isDefinitionMode && !isRootNode && index < siblingsCount,
      definitionOnly: true, // Hide completely in execution mode (not just disable)
      onClick: [() => moveTaskAsync(workItem?.id || 0, id, false, handleError)],
    },
    {
      label: "Move to Section",
      icon: <ForkIcon size="lg" />,
      tooltip: "Move this task to a different section in the workflow",
      condition: isDefinitionMode && !isRootNode && sectionMenu && sectionMenu.length > 0,
      definitionOnly: true, // Hide completely in execution mode (not just disable)
      keepOpenAfterAction: true,
      children: [
        {
          label: "Top Level",
          tooltip: "Move this task to the top level of the workflow",
          condition: true,
          onClick: [() => moveTaskToSectionAsync(workItem?.id || 0, id, 0, handleError)],
        },
        ...(sectionMenu || []).map((section) => ({
          label: section.Label || section.label,
          tooltip: `Move this task to section: ${section.Label || section.label}`,
          condition: true,
          onClick: [() => moveTaskToSectionAsync(workItem?.id || 0, id, section.Id || section.id, handleError)],
        }))
      ],
    },
    {
      label: "Manage Predecessor",
      icon: <ConnectionIcon size="lg" />,
      tooltip: "Manage predecessor relationships for this task",
      condition: isDefinitionMode ? !isRootNode : allowAdhocEdit,
      onClick: [() => setPredecessorModalOpen(true)],
    },
  ];

  const [expandState, setExpandState] = useState({});

  const renderMenuItems = () => {
    const items = [];
    
    // In execution mode (!isDefinitionMode), show all items but disable those that don't meet condition
    // In definition mode, only show items that meet condition
    const shouldShowAll = !isDefinitionMode;
    
    config
      // First, filter out definition-only items in execution mode (hide completely, not just disable)
      .filter((c) => {
        if (c.definitionOnly && !isDefinitionMode) {
          return false; // Hide definition-only items in execution mode
        }
        return true;
      })
      // Then apply the existing logic: show all in execution mode, or only items that meet condition in definition mode
      .filter((c) => shouldShowAll || c.condition)
      .forEach((c, i) => {
        items.push(
          <DropdownMenuItem
            {...c}
            key={i}
            index={i}
            setExpandState={setExpandState}
            expandState={expandState}
            setMenuOpenNodeId={setMenuOpenNodeId}
            setSnippetModalOpen={setSnippetModalOpen}
            isDisabled={shouldShowAll ? !c.condition : false}
          />
        );
        
        if (c.children && c.children.length > 0 && expandState[i]) {
          c.children
            .filter((child) => shouldShowAll || child.condition)
            .forEach((child, childIndex) => {
              items.push(
                <DropdownMenuItem
                  {...child}
                  key={`${i}-${childIndex}`}
                  index={`${i}-${childIndex}`}
                  setExpandState={setExpandState}
                  expandState={expandState}
                  setMenuOpenNodeId={setMenuOpenNodeId}
                  setSnippetModalOpen={setSnippetModalOpen}
                  isDisabled={shouldShowAll ? !child.condition : false}
                  isChild={true}
                />
              );
            });
        }
      });
    
    return items;
  };

  const menuItems = renderMenuItems();
  
  // If no menu items, close the menu and return null
  if (menuItems.length === 0) {
    if (setMenuOpenNodeId) {
      setMenuOpenNodeId(null);
    }
    return null;
  }

  return (
    <div className="os__treeNodeDropdownMenu" style={{ position: 'relative', zIndex: 1000 }}>
      <ul style={{ position: 'relative' }}>
        {menuItems}
      </ul>
    </div>
  );
});

const DropdownMenuItem = React.memo(({
  expandState = {},
  setExpandState,
  isDisabled = false,
  tooltip = "",
  index,
  onClick = [() => {}],
  keepOpenAfterAction,
  icon,
  label,
  children,
  setMenuOpenNodeId,
  isChild = false,
}) => {
  const isExpanded = expandState[index];

  return (
    <FAWTooltip 
      title={tooltip} 
      placement="right"
      arrow={true}
    >
      <li
        onClick={() => {
          if (!isDisabled) {
            if (children && children.length > 0) {
              setExpandState({
                ...expandState,
                [index]: !expandState[index],
              });
            } else {
              onClick.forEach((fn) => fn());
              if (!keepOpenAfterAction) {
                setMenuOpenNodeId && setMenuOpenNodeId(null);
              }
            }
          }
        }}
        style={{
          position: 'relative',
          opacity: isDisabled ? 0.5 : 1,
          cursor: 'pointer',
          padding: '8px 12px',
          paddingLeft: isChild ? '32px' : '12px',
          backgroundColor: isChild ? colors.background.secondary : 'transparent',
          borderLeft: isChild ? `3px solid ${colors.action.link.default}` : 'none',
          minHeight: '36px',
          display: 'flex',
          alignItems: 'center',
          transition: 'background-color 0.2s ease',
        }}
        onMouseEnter={(e) => {
          if (!isDisabled) {
            e.currentTarget.style.backgroundColor = isChild ? colors.background.tertiary : colors.background.secondary;
          }
        }}
        onMouseLeave={(e) => {
          if (!isDisabled) {
            e.currentTarget.style.backgroundColor = isChild ? colors.background.secondary : 'transparent';
          }
        }}
        className="os__treeNodeDropdownMenuItem"
      >
        <FlexI style={{ 
          width: "100%", 
          alignItems: "center",
          gap: "8px"
        }}>
          <div style={{ 
            width: "24px", 
            height: "20px", 
            display: "flex", 
            alignItems: "center", 
            justifyContent: "flex-start",
            flexShrink: 0
          }}>
            {icon}
          </div>
          <span style={{ 
            flex: 1,
            lineHeight: "20px"
          }}>
            {label}
          </span>
          {children && children.length > 0 && (
            <div style={{
              width: "16px",
              height: "16px",
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
              flexShrink: 0,
              color: colors.type.secondary,
              transition: "color 0.2s ease"
            }}>
              {isExpanded ? (
                <FiChevronsUp size="14" />
              ) : (
                <FiChevronsDown size="14" />
              )}
            </div>
          )}
        </FlexI>
      </li>
    </FAWTooltip>
  );
});

const WorkflowTree = ({
  currentTask,
  readOnly = false,
  isPreview = false,
  treeDataJson,
  handleNodeSelect,
  handleAction,
  workItem = { id: 0, isEditable: false, allowAdhocFlowEdit: false },
  updateTreeAsync,
  saveInsertSnippetAsync,
  loadSnippetsAsync,
  removeTaskAsync,
  restoreTaskAsync,
  addTaskAsync,
  saveTaskPredecessorAsync,
  moveTaskAsync,
  moveTaskToSectionAsync,
  handleError,
  loading = false,
  height = "100%",
  isSnippet = false,
  showSearchBar = true,
  isDefinitionMode = false
}) => {
  
  const [searchString, setSearchString] = useState("");
  const [searchFocusIndex, setSearchFocusIndex] = useState(0);
  const [searchFoundCount, setSearchFoundCount] = useState(null);
  const [treeData, setTreeData] = useState([]);
  const [currentNode, setCurrentNode] = useState(null);
  const [menuOpenNodeId, setMenuOpenNodeId] = useState(null);
  const [expandAll, setExpandAll] = useState(true);
  const [predecessorModalOpen, setPredecessorModalOpen] = useState(false);
  const [snippetModalOpen, setSnippetModalOpen] = useState(false);
  const [currentSnippetId, setCurrentSnippetId] = useState(0);
  const [predecessorState, setPredecessorState] = useState(null);

  const treeContainerRef = useRef(null);

  // Function to filter tree data to show only matching nodes and their ancestors
  const filterTreeData = (data, searchQuery) => {
    if (!searchQuery || !searchQuery.trim()) {
      return data;
    }

    const query = searchQuery.toLowerCase().trim();
    
    // Helper function to check if a node matches
    // Only searches in title/Name field
    const nodeMatches = (node) => {
      const matches = (value) => {
        if (!value) return false;
        return String(value).toLowerCase().includes(query);
      };

      // Search only in title or Name (primary display field)
      return matches(node.title) || matches(node.Name);
    };

    // Recursively filter the tree
    const filterNode = (node) => {
      const nodeMatch = nodeMatches(node);
      let filteredChildren = [];

      if (node.children && node.children.length > 0) {
        filteredChildren = node.children
          .map(filterNode)
          .filter(child => child !== null);
      }

      // Keep node if it matches or has matching children
      if (nodeMatch || filteredChildren.length > 0) {
        return {
          ...node,
          children: filteredChildren.length > 0 ? filteredChildren : node.children,
          expanded: filteredChildren.length > 0 ? true : node.expanded
        };
      }

      return null;
    };

    return data
      .map(filterNode)
      .filter(node => node !== null);
  };

  // Filter tree data based on search string
  // Always use treeDataJson as source for filtering to ensure we filter from original data
  // When no search, use treeData (which may have user modifications)
  const filteredTreeData = useMemo(() => {
    const sourceData = (searchString && searchString.trim()) ? (treeDataJson || []) : treeData;
    return filterTreeData(sourceData, searchString);
  }, [treeData, treeDataJson, searchString]);

  useEffect(() => {
    setTreeData(treeDataJson || []);
  }, [treeDataJson]);

  // Reset treeData from treeDataJson when search is cleared
  useEffect(() => {
    if (!searchString || !searchString.trim()) {
      setTreeData(treeDataJson || []);
    }
  }, [searchString, treeDataJson]);

  useEffect(() => {
    toggleNodeExpansion(expandAll);
  }, [expandAll]);

  useEffect(() => {
    const handleClickOutside = (event) => {
      if (treeContainerRef.current && !treeContainerRef.current.contains(event.target)) {
        setMenuOpenNodeId(null);
      }
    };

    if (menuOpenNodeId !== null) {
      document.addEventListener('mousedown', handleClickOutside);
    }

    return () => {
      document.removeEventListener('mousedown', handleClickOutside);
    };
  }, [menuOpenNodeId]);


  const handleTreeOnChange = (treeData) => {
    setTreeData(treeData);
  };

  const handleToggleExpanded = ({ node, path, treeIndex }) => {
    setTreeData(prevTreeData => {
      const newTreeData = [...prevTreeData];
      const nodeAtPath = path.reduce((node, index) => node.children[index], { children: newTreeData });
      nodeAtPath.expanded = !nodeAtPath.expanded;
      return newTreeData;
    });
  };

  const handleNodeMenuClick = (node) => {
    
    if (workItem && workItem.isEditable) {
      const newMenuOpenNodeId = menuOpenNodeId === node.id ? null : node.id;
      setMenuOpenNodeId(newMenuOpenNodeId);
      setCurrentNode(node);
    } else {
    }
  };

  const handleNodeClick = (props) => {
    // In preview mode, don't allow node selection/clicks
    if (isPreview) {
      return;
    }
    setCurrentNode(props.node);
    handleNodeSelect(props.node);
    if (props.node.id !== menuOpenNodeId) {
      setMenuOpenNodeId(null);
    }
  };

  const handleNodeMove = (props) => {
    const { node, nextParentNode, treeData } = props;
    if (nextParentNode) {
      updateTreeAsync(
        node.id,
        nextParentNode.id,
        nextParentNode.children.map((c) => c.id).indexOf(node.id),
        treeData,
        handleError
      );
    } else {
      updateTreeAsync(
        node.id,
        0,
        treeData.map((c) => c.id).indexOf(node.id),
        treeData,
        handleError
      );
    }
  };

  const getNodeButtons = (rowInfo) => {
    // Calculate hasMenuOptions first (root nodes in snippet definition mode have no options)
    const isRootNode = rowInfo.node.IsRoot || rowInfo.node.isRoot || false;
    const hasMenuOptions = !(isDefinitionMode && isSnippet && isRootNode);
    
    // Hide menu button if noButton is set, in preview mode, or no menu options
    if (rowInfo.node.noButton || isPreview || !hasMenuOptions) {
      return "";
    }
    const buttons = [
      <FAWTooltip key="more-options" title="More options" placement="top">
        <span><ThreeDotsVerticalIcon title="" className="tree-dot-menu" /></span>
      </FAWTooltip>
    ];

    // Execution mode only: show ownership status
    if (!isDefinitionMode && rowInfo.node.checkedOutUsername) {
      buttons.push(
        <FlexI title={`Owner: ${rowInfo.node.checkedOutUsername}`}>
          <FiUser />
        </FlexI>
      );
    }

    // Show predecessor indicator in both modes
    if (isPredecessor(rowInfo.node, currentNode)) {
      buttons.push(
        <FlexI title="This task is a predecessor of the selected task">
          <FiAlertCircle style={{ color: colors.status.warning }} />
        </FlexI>
      );
    }

    // Execution mode only: show task completion/in-progress status
    // Derive isComplete and isInProgress from statusCode (since backend doesn't provide these directly)
    if (!isDefinitionMode) {
      // Normalize statusCode to uppercase for comparison (backend may send in different cases)
      const normalizedStatusCode = rowInfo.node.statusCode ? String(rowInfo.node.statusCode).toUpperCase() : null;
      const isComplete = normalizedStatusCode === WORK_ITEM_TASK_STATUS.COMPLETE;
      const isInProgress = normalizedStatusCode === WORK_ITEM_TASK_STATUS.ACTIVE || normalizedStatusCode === WORK_ITEM_TASK_STATUS.PENDING;
      
      if (isComplete) {
        buttons.push(
          <FlexI title="Task completed">
            <FiCheckCircle style={{ color: colors.status.success }} />
          </FlexI>
        );
      } else if (isInProgress) {
        buttons.push(
          <FlexI title="Task in progress">
            <FiAlertCircle style={{ color: colors.action.link.default }} />
          </FlexI>
        );
      }
    }

    return { buttons, hasMenuOptions };
  };

  const isPredecessor = (node, currentNode) => {
    return (
      currentNode &&
      currentNode.predecessors &&
      currentNode.predecessors.includes(node.id)
    );
  };

  const handleSearchOnChange = (e) => {
    setSearchString(e.target.value);
  };

  const selectPrevMatch = () => {
    const index =
      searchFocusIndex !== null
        ? (searchFoundCount + searchFocusIndex - 1) % searchFoundCount
        : searchFoundCount - 1;

    setSearchFocusIndex(index);
  };

  const selectNextMatch = () => {
    const index =
      searchFocusIndex !== null ? (searchFocusIndex + 1) % searchFoundCount : 0;
    setSearchFocusIndex(index);
  };

  // Custom search method for workflow tree nodes
  // Searches only in title/Name field
  const workflowSearchMethod = ({ node, path, treeIndex, searchQuery }) => {
    if (!searchQuery) {
      return false;
    }

    const query = searchQuery.toLowerCase().trim();
    if (!query) {
      return false;
    }

    // Helper function to check if a value matches the search query
    const matches = (value) => {
      if (!value) return false;
      return String(value).toLowerCase().includes(query);
    };

    // Search only in title or Name (primary display field)
    return matches(node.title) || matches(node.Name);
  };

  const toggleNodeExpansion = (expanded) => {
    setTreeData((prev) =>
      toggleExpandedForAll({
        treeData: prev,
        expanded,
      })
      );
    };
  
    return (
    <div className="os__wrapper" style={{ display: 'flex', flexDirection: 'column', height: '100%', minHeight: 0, width: '100%' }}>
      {showSearchBar && !readOnly && (
        <div className="os__bar-wrapper" style={{ width: '100%' }}>
          <FAWInput
            value={searchString}
            onChange={handleSearchOnChange}
            placeholder="Search"
            fullWidth
            sx={{ 
              width: "100%",
              display: 'flex !important',
              '& .MuiOutlinedInput-root': {
                height: '40px',
                borderRadius: '4px',
                '& .MuiOutlinedInput-notchedOutline': {
                  borderColor: colors.type.secondary
                },
                '&:hover .MuiOutlinedInput-notchedOutline': {
                  borderColor: colors.type.secondary
                },
                '&.Mui-focused .MuiOutlinedInput-notchedOutline': {
                  borderColor: colors.type.secondary
                },
                '& .MuiInputBase-input': {
                  padding: '8px 12px',
                  fontSize: '16px',
                  lineHeight: '24px',
                  '&::placeholder': {
                    color: colors.type.secondary,
                    opacity: 1
                  }
                }
              }
            }}
            InputProps={{
              startAdornment: (
                <InputAdornment position="start">
                  <SearchIcon size="lg" style={{ color: colors.type.default, width: '24px', height: '24px' }} />
                </InputAdornment>
              )
            }}
          />
        </div>
      )}
      <div className="os__tree-wrapper" ref={treeContainerRef} style={{ flex: 1, minHeight: 0 }}>
        {loading ? (
          <div style={{ padding: '20px' }}>
            <FAWSkeleton variant="workflowTree" />
          </div>
        ) : filteredTreeData.length === 0 ? (
          <div style={{ padding: '20px', textAlign: 'center', color: colors.type.secondary }}>
            {searchString ? 'No matching tasks found' : 'No workflow tasks found'}
          </div>
        ) : readOnly ? (
          <div className={isPreview ? 'workflow-tree-preview' : ''}>
            <SortableTree
              treeData={filteredTreeData}
              onNodeClick={handleNodeClick}
              onChange={handleTreeOnChange}
              onMoveNode={() => {}}
              onToggleExpanded={handleToggleExpanded}
              maxDepth={5}
              searchQuery={searchString}
              searchMethod={workflowSearchMethod}
              searchFocusOffset={searchFocusIndex}
              canDrag={() => false}
              canDrop={() => false}
              searchFinishCallback={(matches) => {
                setSearchFoundCount(matches.length);
                setSearchFocusIndex(
                  matches.length > 0 ? searchFocusIndex % matches.length : 0
                );
              }}
              isVirtualized={false}
              rowHeight={28}
              currentNodeId={
                currentTask && currentTask.id
                  ? currentTask.id
                  : currentNode
                  ? currentNode.id
                  : 0
              }
              menuOpenNodeId={menuOpenNodeId}
              generateNodeProps={(rowInfo) => {
                const isCurrentNode = currentNode && rowInfo.node.id === currentNode.id;
                const isMenuHidden = String(menuOpenNodeId) !== String(rowInfo.node.id);
                
                const depth = rowInfo.path ? rowInfo.path.length : 0;
                
                let className = isCurrentNode ? 'os__currentRow atlas_tree_current_node' : '';
                className += ` atlas-depth-${depth}`;
                
                // Add status class from getNodeClass (os_pending, os_active, os_removed, os_default, etc.)
                const statusClass = getNodeClass(rowInfo.node);
                if (statusClass) {
                  className += ` ${statusClass}`;
                }
                
                const nodeTitle = rowInfo.node.title || rowInfo.node.Name || 'Task';
                
                return {
                  ...getNodeButtons(rowInfo),
                  title: nodeTitle,
                  className: className.trim(),
                  isMenuHidden,
                  style: isPreview ? { cursor: 'default' } : {}
                };
              }}
            dropdownMenu={(props) => {
              // Always show menu (even for completed tasks) - menu items will be disabled based on conditions
              const index = props.node?.Index ?? (props.treeIndex || 0);
              const siblingsCount = props.node?.SiblingsCount ?? 
                (() => {
                  const totalSiblings = props.parentNode ? props.parentNode.children.length : treeData.length;
                  return totalSiblings - 1;
                })();
              
              const dropdownComponent = (
                <DropdownMenu
                  {...props.node}
                  {...currentTask}
                  IsRoot={props.node?.IsRoot || props.node?.isRoot || false}
                  workItem={workItem}
                  isDefinitionMode={isDefinitionMode}
                  updateTreeAsync={updateTreeAsync}
                  setPredecessorModalOpen={setPredecessorModalOpen}
                  setMenuOpenNodeId={setMenuOpenNodeId}
                  setSnippetModalOpen={setSnippetModalOpen}
                  handleAction={handleAction}
                  removeTaskAsync={removeTaskAsync}
                  restoreTaskAsync={restoreTaskAsync}
                  addTaskAsync={addTaskAsync}
                  moveTaskAsync={moveTaskAsync}
                  moveTaskToSectionAsync={moveTaskToSectionAsync}
                  saveInsertSnippetAsync={saveInsertSnippetAsync}
                  handleError={handleError}
                  index={index}
                  siblingsCount={siblingsCount}
                  isSnippet={isSnippet}
                />
              );
              return dropdownComponent;
            }}
            openDropdownMenu={(node) => handleNodeMenuClick(node)}
            getNodeIcon={(node) => {
              const result = getTypeIconLocal(node.Type || node.type, node, isDefinitionMode);
              return result;
            }}
            getCustomNodeClass={(node) => getNodeClass(node)}
            onVisibilityToggle={(data) => {
            }}
            style={{ height: height }}
          />
          </div>
        ) : (
          <div className={isPreview ? 'workflow-tree-preview' : ''}>
            <SortableTree
            treeData={filteredTreeData}
            onNodeClick={handleNodeClick}
            onChange={handleTreeOnChange}
            onMoveNode={(prop) => handleNodeMove({ ...prop })}
            onToggleExpanded={handleToggleExpanded}
            maxDepth={5}
            searchQuery={searchString}
            searchMethod={workflowSearchMethod}
            searchFocusOffset={searchFocusIndex}
            canDrag={({ node }) => !node.noDragging}
            canDrop={({ nextParent }) => !nextParent || !nextParent.noChildren}
            searchFinishCallback={(matches) => {
              setSearchFoundCount(matches.length);
              setSearchFocusIndex(
                matches.length > 0 ? searchFocusIndex % matches.length : 0
              );
            }}
            isVirtualized={false}
            rowHeight={28}
            currentNodeId={
              currentTask && currentTask.id
                ? currentTask.id
                : currentNode
                ? currentNode.id
                : 0
            }
            menuOpenNodeId={menuOpenNodeId}
            generateNodeProps={(rowInfo) => {
              const isCurrentNode = currentNode && rowInfo.node.id === currentNode.id;
              const isMenuHidden = String(menuOpenNodeId) !== String(rowInfo.node.id);
              
              const depth = rowInfo.path ? rowInfo.path.length : 0;
              
              let className = isCurrentNode ? 'os__currentRow atlas_tree_current_node' : '';
              className += ` atlas-depth-${depth}`;
              
              // Add status class from getNodeClass (os_pending, os_active, os_removed, os_default, etc.)
              const statusClass = getNodeClass(rowInfo.node);
              if (statusClass) {
                className += ` ${statusClass}`;
              }
              
              const nodeTitle = rowInfo.node.title || rowInfo.node.Name || 'Task';
              
              return {
                ...getNodeButtons(rowInfo),
                title: nodeTitle,
                className: className.trim(),
                isMenuHidden,
                style: isPreview ? { cursor: 'default' } : {}
              };
            }}
            dropdownMenu={(props) => {
              // Always show menu (even for completed tasks) - menu items will be disabled based on conditions
              const index = props.node?.Index ?? (props.treeIndex || 0);
              const siblingsCount = props.node?.SiblingsCount ?? 
                (() => {
                  const totalSiblings = props.parentNode ? props.parentNode.children.length : treeData.length;
                  return totalSiblings - 1;
                })();
              
              const dropdownComponent = (
                <DropdownMenu
                  {...props.node}
                  {...currentTask}
                  IsRoot={props.node?.IsRoot || props.node?.isRoot || false}
                  workItem={workItem}
                  isDefinitionMode={isDefinitionMode}
                  updateTreeAsync={updateTreeAsync}
                  setPredecessorModalOpen={setPredecessorModalOpen}
                  setMenuOpenNodeId={setMenuOpenNodeId}
                  setSnippetModalOpen={setSnippetModalOpen}
                  handleAction={handleAction}
                  removeTaskAsync={removeTaskAsync}
                  restoreTaskAsync={restoreTaskAsync}
                  addTaskAsync={addTaskAsync}
                  moveTaskAsync={moveTaskAsync}
                  moveTaskToSectionAsync={moveTaskToSectionAsync}
                  saveInsertSnippetAsync={saveInsertSnippetAsync}
                  handleError={handleError}
                  index={index}
                  siblingsCount={siblingsCount}
                  isSnippet={isSnippet}
                />
              );
              return dropdownComponent;
            }}
            openDropdownMenu={(node) => handleNodeMenuClick(node)}
            getNodeIcon={(node) => {
              const result = getTypeIconLocal(node.Type || node.type, node, isDefinitionMode);
              return result;
            }}
            getCustomNodeClass={(node) => getNodeClass(node)}
            onVisibilityToggle={(data) => {
            }}
            style={{ height: height }}
          />
          </div>
        )}
      </div>
      <Render condition={predecessorModalOpen}>
        <FAWModal
          open={predecessorModalOpen}
          onClose={() => setPredecessorModalOpen(false)}
          title="Manage Predecessors"
          maxWidth="lg"
          content={
            <Predecessors
              saveTaskPredecessorAsync={saveTaskPredecessorAsync}  
              data={treeData}
              task={currentNode}
              workflowId={workItem?.id || 0}
              handleClose={() => setPredecessorModalOpen(false)}
              handleError={handleError}
              onStateChange={setPredecessorState}
            />
          }
          actions={[
            {
              label: "Cancel",
              onClick: () => setPredecessorModalOpen(false),
              variant: "outlined",
              color: "inherit"
            },
            {
              label: "Save",
              onClick: () => {
                if (predecessorState?.saveFunction) {
                  predecessorState.saveFunction();
                }
                setPredecessorModalOpen(false);
              },
              variant: "contained",
              color: "primary",
              disabled: !predecessorState?.hasChanges
            }
          ]}
        />
      </Render>
      <Render condition={snippetModalOpen}>
        <FAWModal
          open={snippetModalOpen}
          onClose={() => setSnippetModalOpen(false)}
          title="Insert Snippet"
          maxWidth="xl"
          fullWidth={true}
          sx={{
            '& .MuiDialog-paper': {
              width: { xs: '95vw', sm: '90vw', md: '85vw', lg: '80vw', xl: '75vw' },
              maxWidth: { xs: '95vw', sm: '90vw', md: '85vw', lg: '80vw', xl: '75vw' },
              minWidth: { xs: '600px', sm: '700px', md: '800px', lg: '900px', xl: '1000px' }
            }
          }}
          content={
            <InsertSnippet
              workItemId={workItem?.id || 0}
              task={currentNode}
              currentId={currentSnippetId}
              setCurrentId={setCurrentSnippetId}
              loadSnippetsAsync={loadSnippetsAsync}
              handleError={handleError}
              setSnippetModalOpen={setSnippetModalOpen}
            />
          }
          actions={[
            {
              label: "Cancel",
              onClick: () => setSnippetModalOpen(false),
              variant: "outlined",
              color: "inherit"
            },
            {
              label: "Confirm and Insert",
              onClick: () => {
                saveInsertSnippetAsync({
                  snippetId: currentSnippetId,
                  containerId: workItem?.id || 0,
                  taskId: currentNode.id
                }, handleError);
                setSnippetModalOpen(false);
              },
              variant: "contained",
              color: "primary"
            }
          ]}
        />
      </Render>
    </div>
  );
};

export default WorkflowTree;