/**
 * Validates email address format
 * @param {string} email - Email address to validate
 * @returns {boolean} - True if valid email format
 */
export const validateEmail = (email) => {
  if (!email || email.trim() === '') {
    return true; // Empty email is valid (not required)
  }
  const emailReg = /^([\w-\.]+@([\w-]+\.)+[\w-]{2,4})?$/;
  return emailReg.test(email);
};

/**
 * Validates notification distribution list (semicolon-separated emails)
 * @param {string} distributionList - Semicolon-separated email addresses
 * @returns {object} - { isValid: boolean, errors: string[] }
 */
export const validateNotificationDistributionList = (distributionList) => {
  const errors = [];
  
  if (!distributionList || distributionList.trim() === '') {
    return { isValid: true, errors: [] }; // Empty is valid (not required)
  }
  
  // Split by semicolon and validate each email
  const emails = distributionList.split(';').map(email => email.trim()).filter(email => email !== '');
  
  emails.forEach((email, index) => {
    if (!validateEmail(email)) {
      errors.push(`Invalid email address at position ${index + 1}: ${email}`);
    }
  });
  
  return {
    isValid: errors.length === 0,
    errors
  };
};

/**
 * Validates notification task form data
 * @param {object} formData - Form data to validate
 * @returns {object} - { isValid: boolean, errors: object }
 */
export const validateNotificationTask = (formData) => {
  const errors = {};
  let isValid = true;
  
  // Validate Send Alerts To email
  if (formData.SendAlertsTo && !validateEmail(formData.SendAlertsTo)) {
    errors.SendAlertsTo = 'Invalid email address';
    isValid = false;
  }
  
  // Validate Notification Distribution List
  const distributionValidation = validateNotificationDistributionList(formData.NotificationDistributionList);
  if (!distributionValidation.isValid) {
    errors.NotificationDistributionList = distributionValidation.errors.join('; ');
    isValid = false;
  }
  
  // Validate that at least one recipient is selected
  const hasWorkQueue = formData.NotificationWorkQueueId && formData.NotificationWorkQueueId !== '';
  const hasThirdPartyFields = formData.ThirdPartyNotificationFieldCodes && formData.ThirdPartyNotificationFieldCodes.length > 0;
  const hasDistributionList = formData.NotificationDistributionList && formData.NotificationDistributionList.trim() !== '';
  
  if (!hasWorkQueue && !hasThirdPartyFields && !hasDistributionList) {
    errors.recipients = 'At least one recipient must be specified (work queue, third-party fields, or email addresses)';
    isValid = false;
  }
  
  // Validate Notification Type is selected
  if (!formData.NotificationDefinitionId || formData.NotificationDefinitionId === '' || formData.NotificationDefinitionId === 0) {
    errors.NotificationDefinitionId = 'Notification type is required';
    isValid = false;
  }
  
  // Validate Notification Language is selected
  if (!formData.NotificationLanguageCode || formData.NotificationLanguageCode === '') {
    errors.NotificationLanguageCode = 'Notification language is required';
    isValid = false;
  }
  
  return {
    isValid,
    errors
  };
};

/**
 * Validates task name (required, max 30 characters)
 * @param {string} name - Task name to validate
 * @returns {object} - { isValid: boolean, error: string }
 */
export const validateTaskName = (name) => {
  const maxLength = 30; // Matches legacy [Length(30)]
  
  // Name is required
  if (!name || name.trim() === '') {
    return { isValid: false, error: 'Name is required' };
  }
  
  if (name.length > maxLength) {
    return { isValid: false, error: `Task name cannot be longer than ${maxLength} characters` };
  }
  
  return { isValid: true, error: null };
};

/**
 * Validates task description length (from legacy: max 80 characters, optional)
 * @param {string} description - Task description to validate
 * @returns {object} - { isValid: boolean, error: string }
 */
export const validateTaskDescription = (description) => {
  const maxLength = 80; // Matches legacy [Length(80)]
  // Description is optional in legacy (no Required attribute)
  if (description && description.length > maxLength) {
    return { isValid: false, error: `Description cannot be longer than ${maxLength} characters` };
  }
  return { isValid: true, error: null };
};

/**
 * Validates that auto-complete tasks don't have required UDFs
 * @param {boolean} isAutoComplete - Whether task is auto-complete
 * @param {array} userDefinedFields - Array of UDF objects
 * @returns {object} - { isValid: boolean, error: string }
 */
export const validateAutoCompleteWithRequiredUDFs = (isAutoComplete, userDefinedFields) => {
  if (isAutoComplete && userDefinedFields) {
    const hasRequiredUDFs = userDefinedFields.some(udf => udf.IsRequired === true);
    if (hasRequiredUDFs) {
      return {
        isValid: false,
        error: 'You cannot have fields marked as required if the workflow is to be completed automatically by the system.'
      };
    }
  }
  return { isValid: true, error: null };
};

