/**
 * Validates Conditional Snippet Task specific fields
 * @param {object} formData - Form data to validate
 * @returns {object} - { isValid: boolean, errors: object }
 */
export const validateConditionalSnippetTask = (formData) => {
  const errors = {};
  let isValid = true;
  
  // Validate that at least one condition exists
  if (!formData.ConditionalSnippetRulesJson || formData.ConditionalSnippetRulesJson.length === 0) {
    errors.ConditionalSnippetRulesJson = 'At least one condition must be defined';
    isValid = false;
  }
  
  // Validate each condition has required fields
  if (formData.ConditionalSnippetRulesJson && formData.ConditionalSnippetRulesJson.length > 0) {
    formData.ConditionalSnippetRulesJson.forEach((rule, index) => {
      if (!rule.snippetId || rule.snippetId === '') {
        errors[`ConditionalSnippetRulesJson[${index}].snippetId`] = `Condition ${index + 1}: Snippet must be selected`;
        isValid = false;
      }
    });
  }
  
  return {
    isValid,
    errors
  };
};

