/**
 * Comprehensive validation for workflow task definition
 * @param {object} formData - Complete form data
 * @returns {object} - { isValid: boolean, errors: object }
 */
export const validateWorkflowTaskDefinition = (formData) => {
  const errors = {};
  let isValid = true;
  
  // Validate basic task properties
  const nameValidation = validateTaskName(formData.Name);
  if (!nameValidation.isValid) {
    errors.Name = nameValidation.error;
    isValid = false;
  }
  
  const descriptionValidation = validateTaskDescription(formData.Description);
  if (!descriptionValidation.isValid) {
    errors.Description = descriptionValidation.error;
    isValid = false;
  }
  
  // Validate auto-complete with required UDFs
  const autoCompleteValidation = validateAutoCompleteWithRequiredUDFs(
    formData.IsAutoComplete,
    formData.UserDefinedFields
  );
  if (!autoCompleteValidation.isValid) {
    errors.IsAutoComplete = autoCompleteValidation.error;
    isValid = false;
  }
  
  // Validate task type specific fields
  switch (formData.Type) {
    case 'NOTIFICATION':
      const notificationValidation = validateNotificationTask(formData);
      if (!notificationValidation.isValid) {
        Object.assign(errors, notificationValidation.errors);
        isValid = false;
      }
      break;
      
    case 'ACTION':
      const actionValidation = validateActionTask(formData);
      if (!actionValidation.isValid) {
        Object.assign(errors, actionValidation.errors);
        isValid = false;
      }
      break;
      
    case 'CONDITIONAL_SNIPPET':
      const conditionalSnippetValidation = validateConditionalSnippetTask(formData);
      if (!conditionalSnippetValidation.isValid) {
        Object.assign(errors, conditionalSnippetValidation.errors);
        isValid = false;
      }
      break;
      
    case 'REVIEW':
      const reviewValidation = validateReviewTask(formData);
      if (!reviewValidation.isValid) {
        Object.assign(errors, reviewValidation.errors);
        isValid = false;
      }
      break;
      
    case 'CLOSE':
      const closeValidation = validateCloseTask(formData);
      if (!closeValidation.isValid) {
        Object.assign(errors, closeValidation.errors);
        isValid = false;
      }
      break;
      
    case 'SECTION':
      const sectionValidation = validateSectionTask(formData);
      if (!sectionValidation.isValid) {
        Object.assign(errors, sectionValidation.errors);
        isValid = false;
      }
      break;
      
    case 'STEP':
      const stepValidation = validateStepTask(formData);
      if (!stepValidation.isValid) {
        Object.assign(errors, stepValidation.errors);
        isValid = false;
      }
      break;
      
    case 'EDIT':
      const editValidation = validateEditTask(formData);
      if (!editValidation.isValid) {
        Object.assign(errors, editValidation.errors);
        isValid = false;
      }
      break;
      
    case 'APPROVE':
      const approveValidation = validateApproveTask(formData);
      if (!approveValidation.isValid) {
        Object.assign(errors, approveValidation.errors);
        isValid = false;
      }
      break;
      
    case 'ROUTE_TO':
      const routeToValidation = validateRouteToTask(formData);
      if (!routeToValidation.isValid) {
        Object.assign(errors, routeToValidation.errors);
        isValid = false;
      }
      break;
      
    case 'GO_TO':
      const goToValidation = validateGoToTask(formData);
      if (!goToValidation.isValid) {
        Object.assign(errors, goToValidation.errors);
        isValid = false;
      }
      break;
      
    case 'IF':
      const ifValidation = validateIfTask(formData);
      if (!ifValidation.isValid) {
        Object.assign(errors, ifValidation.errors);
        isValid = false;
      }
      break;
      
    default:
      // Unknown task type - no specific validation
      break;
  }
  
  return {
    isValid,
    errors
  };
};
