import React, { useState, useMemo } from 'react';
import {
  Box,
  Paper,
  Grid,
  TextField,
  InputAdornment,
  List,
  ListItem,
  ListItemButton,
  ListItemIcon,
  ListItemText,
  Divider
} from '@mui/material';
import { Search as SearchIcon } from '@mui/icons-material';
import FAWButtonGroupTabs from '../FAWButtonGroupTabs';
import FAWTypography from '../FAWTypography';
import FAWCheckbox from '../FAWCheckbox';
import FAWDropdown from '../FAWDropdown';
import FAWSkeleton from '../FAWSkeleton';
import NoResultsFound from './NoResultsFound';
import './FieldManagementSection.css';

/**
 * Reusable Field Management Section Component
 * 
 * @param {Object} props
 * @param {string} props.title - Section title (e.g., "Available Fields", "Available Third Party Fields")
 * @param {Array} props.fields - Array of field objects with FieldDescription, FieldName, etc.
 * @param {Array} props.selectedFields - Array of selected field IDs
 * @param {Function} props.onFieldSelect - Callback when field is selected/deselected
 * @param {Array} props.categoryOptions - Options for category dropdown
 * @param {string} props.selectedCategory - Currently selected category
 * @param {Function} props.onCategoryChange - Callback when category changes
 * @param {string} props.searchPlaceholder - Placeholder text for search input
 * @param {boolean} props.readOnly - Whether the component is read-only
 * @param {boolean} props.loading - Whether the field list is loading
 */
const FieldManagementSection = ({
  title,
  fields = [],
  selectedFields = [],
  onFieldSelect,
  categoryOptions = [],
  selectedCategory = '',
  onCategoryChange,
  categoryLabel = 'Category',  // Customizable label for category dropdown
  searchPlaceholder = 'Search',
  readOnly = false,
  loading = false
}) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [activeTab, setActiveTab] = useState('available');

  // Filter fields based on search term
  const filteredFields = useMemo(() => {
    if (!searchTerm.trim()) return fields;
    
    return fields.filter(field => {
      const fieldName = field.FieldName || field.Name || field.FieldDescription || field.Description || '';
      const fieldDesc = field.FieldDescription || field.Description || field.FieldName || field.Name || '';
      const searchLower = searchTerm.toLowerCase();
      
      return fieldName.toLowerCase().includes(searchLower) || 
             fieldDesc.toLowerCase().includes(searchLower);
    });
  }, [fields, searchTerm]);

  // Separate available and included fields
  const availableFields = useMemo(() => {
    // Available tab shows ALL fields (both checked and unchecked)
    return filteredFields;
  }, [filteredFields, selectedFields]);

  const includedFields = useMemo(() => {
    // Included tab shows ONLY the checked/selected fields
    return filteredFields.filter(field => {
      const fieldName = field.FieldName || field.Name || '';
      return selectedFields.includes(fieldName);
    });
  }, [filteredFields, selectedFields]);

  const handleFieldToggle = (fieldName) => {
    if (readOnly) return;
    
    if (onFieldSelect) {
      onFieldSelect(fieldName);
    }
  };

  const handleTabChange = (tab) => {
    setActiveTab(tab);
  };

  const renderFieldList = (fieldList, isIncluded = false) => {
    return (
    <List 
      className={`field-management-section-field-list ${isIncluded ? 'field-management-section-field-list-included' : 'field-management-section-field-list-available'}`}
      sx={{ 
        maxHeight: 300, 
        overflow: 'auto',
        border: '1px solid #e0e0e0',
        borderRadius: 1,
        backgroundColor: 'white',
        mb: 0 // No bottom margin to respect the 24-unit container padding
      }}
    >
      {fieldList.length === 0 ? (
        <NoResultsFound 
          title="No results found"
          subtitle={searchTerm ? `'${searchTerm}' did not match any items.` : 'No fields available.'}
        />
      ) : (
        fieldList.map((field, index) => {
          // Use FieldName for matching - this is what selectedFields contains
          // FieldName is the unique identifier used for save/load operations
          const fieldName = field.FieldName || field.Name || '';
          
          // Use FieldDescription for display - this is the user-friendly label
          const fieldDisplayName = field.FieldDescription || field.Description || field.FieldName || field.Name || '';
          
          // Check if this field is selected using FieldName (matches RelatedFieldsManagement logic)
          const isSelected = selectedFields.includes(fieldName);
          
          // Create a unique key using FieldName and index to avoid duplicate key warnings
          // FieldName ensures semantic identity, index ensures uniqueness even when FieldName is duplicated
          const uniqueKey = `${fieldName}_${index}`;
          
          return (
            <React.Fragment key={uniqueKey}>
              <ListItem 
                className={`field-management-section-field-item ${isSelected ? 'field-management-section-field-item-selected' : 'field-management-section-field-item-unselected'}`}
                disablePadding
              >
                <ListItemButton
                  className="field-management-section-field-item-button"
                  onClick={() => handleFieldToggle(fieldName)}
                  disabled={readOnly}
                  sx={{
                    py: 0.5,
                    px: 1,
                    '&:hover': {
                      backgroundColor: readOnly ? 'transparent' : 'action.hover'
                    }
                  }}
                >
                  <ListItemIcon className="field-management-section-field-item-checkbox-container" sx={{ minWidth: 36 }}>
                    <FAWCheckbox
                      className="field-management-section-field-item-checkbox"
                      checked={isSelected}
                      disabled={readOnly}
                      size="small"
                      sx={{ p: 0.5 }}
                    />
                  </ListItemIcon>
                  <Box className="field-management-section-field-item-text-container" sx={{ flexGrow: 1, minWidth: 0 }}>
                    <FAWTypography
                      className="field-management-section-field-item-text"
                      variant="body2"
                      sx={{
                        fontSize: '14px !important',
                        lineHeight: '20px !important',
                        letterSpacing: '0.2px !important',
                        fontWeight: '400 !important',
                        overflow: 'hidden',
                        textOverflow: 'ellipsis',
                        whiteSpace: 'nowrap',
                        minWidth: 0,
                        width: '100%',
                        '@media (max-width: 1000px)': {
                          maxWidth: '685px'
                        },
                        '@media (min-width: 1001px) and (max-width: 1999px)': {
                          maxWidth: '1000px'
                        },
                        '@media (min-width: 2000px)': {
                          maxWidth: '1350px !important'
                        }
                      }}
                      title={fieldDisplayName}
                    >
                      {fieldDisplayName}
                    </FAWTypography>
                  </Box>
                </ListItemButton>
              </ListItem>
              {index < fieldList.length - 1 && <Divider className="field-management-section-field-item-divider" />}
            </React.Fragment>
          );
        })
      )}
    </List>
    );
  };

  return (
    <Paper 
      className="field-management-section"
      elevation={0} 
      sx={{ 
        p: 3, // 24 units padding (3 * 8px = 24px)
        mb: 2,
        backgroundColor: '#f3f3f3',
        borderRadius: 1,
        border: 'none',
        boxShadow: 'none'
      }}
    >
      {/* Header */}
      <FAWTypography 
        className="field-management-section-title"
        variant="h6" 
        sx={{ 
          mb: 3, // 24px spacing
          fontWeight: 600,
          fontSize: '18px',
          lineHeight: '28px',
          color: '#282e37',
          letterSpacing: '0.2px'
        }}
      >
        {title}
      </FAWTypography>

      {/* Category Dropdown and Search */}
      <Grid container spacing={2} className="field-management-section-controls" sx={{ mb: 1, alignItems: 'flex-end' }}>
        {/* Only show category dropdown if there are category options */}
        {categoryOptions && categoryOptions.length > 0 && (
          <Grid item xs={12} sm={6}>
            <Box className="field-management-section-category-container">
              <FAWDropdown
                className="field-management-section-category-dropdown"
                label={categoryLabel}
                options={categoryOptions}
                value={selectedCategory}
                onChange={(selectedOption) => onCategoryChange && onCategoryChange(selectedOption?.value || '')}
                disabled={readOnly}
                placeholder="Select category"
                fullWidth
                size="small"
              />
            </Box>
          </Grid>
        )}
        <Grid item xs={12} sm={categoryOptions && categoryOptions.length > 0 ? 6 : 12}>
          <Box className="field-management-section-search-container">
            <FAWTypography 
              className="field-management-section-search-label"
              variant="body2" 
              sx={{ 
                mb: 1, 
                fontWeight: 600,
                fontSize: '12px',
                lineHeight: '16px',
                color: '#282e37',
                letterSpacing: '0.3px'
              }}
            >
              Search
            </FAWTypography>
            <TextField
              className="field-management-section-search-input"
              fullWidth
              size="small"
              placeholder={searchPlaceholder}
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              disabled={readOnly}
              sx={{ 
                height: '40px',
                '& .MuiOutlinedInput-root': {
                  height: '40px',
                  backgroundColor: 'white',
                  borderRadius: 1,
                  '& .MuiOutlinedInput-notchedOutline': {
                    borderColor: '#6f7377'
                  },
                  '&:hover .MuiOutlinedInput-notchedOutline': {
                    borderColor: '#6f7377'
                  },
                  '&.Mui-focused .MuiOutlinedInput-notchedOutline': {
                    borderColor: '#6f7377'
                  }
                }
              }}
              InputProps={{
                startAdornment: (
                  <InputAdornment position="start" className="field-management-section-search-icon">
                    <SearchIcon fontSize="small" />
                  </InputAdornment>
                )
              }}
            />
          </Box>
        </Grid>
      </Grid>

      {/* Tabs */}
      <Box className="field-management-section-tabs-container" sx={{ mt: 2, mb: 2 }}>
        <Box 
          className="field-management-section-toggle-group"
          sx={{
            display: 'flex',
            borderRadius: 1,
            overflow: 'hidden',
            border: '1px solid #282e37'
          }}
        >
          <Box
            className="field-management-section-toggle-available"
            onClick={() => !readOnly && handleTabChange('available')}
            sx={{
              flex: 1,
              backgroundColor: activeTab === 'available' ? '#282e37' : 'white',
              color: activeTab === 'available' ? 'white' : '#282e37',
              cursor: readOnly ? 'default' : 'pointer',
              py: 1,
              px: 1.5,
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              borderRight: '1px solid #282e37',
              '&:hover': {
                backgroundColor: readOnly ? 'inherit' : (activeTab === 'available' ? '#282e37' : '#f5f5f5')
              }
            }}
          >
            <FAWTypography
              variant="body2"
              sx={{
                fontWeight: 600,
                fontSize: '16px',
                lineHeight: '25.5px',
                letterSpacing: '0.16px'
              }}
            >
              Available
            </FAWTypography>
          </Box>
          <Box
            className="field-management-section-toggle-included"
            onClick={() => !readOnly && handleTabChange('included')}
            sx={{
              flex: 1,
              backgroundColor: activeTab === 'included' ? '#282e37' : 'white',
              color: activeTab === 'included' ? 'white' : '#282e37',
              cursor: readOnly ? 'default' : 'pointer',
              py: 1,
              px: 1.5,
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              '&:hover': {
                backgroundColor: readOnly ? 'inherit' : (activeTab === 'included' ? '#282e37' : '#f5f5f5')
              }
            }}
          >
            <FAWTypography
              variant="body2"
              sx={{
                fontWeight: 600,
                fontSize: '16px',
                lineHeight: '25.5px',
                letterSpacing: '0.16px'
              }}
            >
              Included
            </FAWTypography>
          </Box>
        </Box>
      </Box>

      {/* Field List Header */}
      <FAWTypography 
        className="field-management-section-field-list-header"
        variant="subtitle2" 
        sx={{ 
          mb: 1, // Spacing/3 (1 unit)
          fontWeight: 'bold',
          color: 'text.secondary'
        }}
      >
        Field name
      </FAWTypography>

      {/* Field List */}
      {loading ? (
        <FAWSkeleton variant="fieldList" />
      ) : (
        activeTab === 'available' ? renderFieldList(availableFields) : renderFieldList(includedFields, true)
      )}
    </Paper>
  );
};

export default FieldManagementSection;
