import * as yup from 'yup';

/**
 * Yup validation schemas for workflow forms
 */

// Base validation rules - Aligned with legacy requirements
const nameValidation = yup
  .string()
  .required('Name is required') // Name should be required
  .max(30, 'Name cannot be longer than 30 characters') // Matches legacy [Length(30)]
  .trim();

const descriptionValidation = yup
  .string()
  .nullable()
  .optional() // Optional in legacy (no Required attribute in WorkflowTaskDefinition)
  .max(80, 'Description cannot be longer than 80 characters') // Matches legacy [Length(80)]
  .trim();

const emailValidation = yup
  .string()
  .email('Invalid email address format')
  .nullable()
  .optional();


const workflowTypeValidation = yup
  .string()
  .required('Workflow type is required');

const stateTransitionDomainValidation = yup
  .string()
  .required('State transition domain is required');

const durationValidation = yup
  .number()
  .min(0, 'Duration must be 0 or greater')
  .max(9999, 'Duration cannot exceed 9999')
  .integer('Duration must be a whole number')
  .nullable()
  .optional();

const slaDaysValidation = yup
  .number()
  .min(0, 'SLA days must be 0 or greater')
  .max(9999, 'SLA days cannot exceed 9999')
  .integer('SLA days must be a whole number')
  .nullable()
  .optional();

// Workflow Definition Schema - Aligned with legacy requirements
export const workflowDefinitionSchema = yup.object().shape({
  Name: nameValidation,
  Description: descriptionValidation, // Optional in legacy
  WorkflowTypeCode: workflowTypeValidation, // Required by backend
  StateTransitionDomain: stateTransitionDomainValidation, // Required by backend
  CategoryCode: yup.string().nullable().optional(), // Not required by backend
  SubcategoryCode: yup.string().nullable().optional(), // Not required by backend
  InitializerTypeCd: yup.string().nullable().optional(),
  Active: yup.boolean().required('Active status is required'),
  UseStarterSnippet: yup.boolean().default(false),
  ExpectedDuration: durationValidation,
  AllowAdHoc: yup.boolean().default(false),
  ManualEvaluation: yup.boolean().default(false),
  QueueAssignmentDomain: yup.string().nullable().optional(),
  SAS70Control: yup.boolean().default(false),
  ExpectedDurationType: yup.string().default('days')
});

// Snippet Schema - Aligned with legacy requirements
export const snippetSchema = yup.object().shape({
  Name: nameValidation,
  Description: descriptionValidation, // Optional in legacy
  CategoryCode: yup.string().nullable().optional(),
  SubcategoryCode: yup.string().nullable().optional(),
  Active: yup.boolean().default(true),
  selectedWorkflows: yup.array().default([])
});

// Task Detail Schema - Aligned with legacy requirements
export const taskDetailSchema = yup.object().shape({
  Name: nameValidation,
  Description: descriptionValidation, // Optional in legacy
  Type: yup.string().required('Task type is required'),
  Status: yup.string().nullable().optional(), // Optional in legacy (matches WorkitemStatusCode)
  Duration: durationValidation,
  SLADays: slaDaysValidation,
  WorkQueueId: yup.string().nullable().optional(),
  ContainerId: yup.string().nullable().optional(),
  ParentWorkflowTaskDefinitionId: yup.string().nullable().optional(),
  IsRequired: yup.boolean().default(false),
  IsPhase: yup.boolean().default(false),
  IsSnippetTask: yup.boolean().default(false),
  ShowCaseStatusDropdown: yup.boolean().default(true),
  AllowEditTaskName: yup.boolean().default(false),
  NewlyCreated: yup.boolean().default(false),
  isPrecondition: yup.boolean().default(false),
  showCheckBox: yup.boolean().default(true),
  highlighted: yup.boolean().default(false),
  evaluateAllConditions: yup.boolean().default(false),
  isAutoComplete: yup.boolean().default(false),
  hasRouteTo: yup.boolean().default(false),
  ControllerName: yup.string().default('WorkflowDef'),
  SendAlertsTo: emailValidation,
  workflowDefinitionTypeCode: yup.string().nullable().optional(),
  workflowDefinitionType: yup.string().nullable().optional(),
  actionType: yup.string().nullable().optional(),
  thirdPartyApprovalStatus: yup.string().nullable().optional(),
  internalOwnerQueueId: yup.string().nullable().optional(),
  formToSendId: yup.string().nullable().optional(),
  formToSendRecipientCode: yup.string().nullable().optional(),
  formToSendEmail: emailValidation,
  formToSendLanguageCode: yup.string().nullable().optional(),
  notificationWorkQueueId: yup.string().nullable().optional(),
  notificationDistributionList: yup.string().nullable().optional(),
  notificationDefinitionId: yup.string().nullable().optional(),
  notificationLanguageCode: yup.string().nullable().optional(),
  icon: yup.string().nullable().optional(),
  thirdPartyNotificationFieldCodes: yup.array().default([]),
  userDefinedFields: yup.array().default([]),
  thirdPartyFields: yup.array().default([]),
  relatedFields: yup.array().default([]),
  statuses: yup.array().default([]),
  workQueues: yup.array().default([]),
  actions: yup.array().default([]),
  thirdPartyApprovalStatuses: yup.array().default([]),
  securimateFormSubmissionSelection: yup.array().default([]),
  recipientSelection: yup.array().default([]),
  formLanguageSelection: yup.array().default([]),
  notificationWorkQueueSelection: yup.array().default([]),
  thirdPartyNotificationSelection: yup.array().default([]),
  notificationTypeSelection: yup.array().default([]),
  notificationLanguageSelection: yup.array().default([]),
  NotificationControls: yup.array().default([]),
  conditionalSnippetRulesJson: yup.array().default([]),
  categories: yup.array().default([]),
  formNames: yup.array().default([])
});

// Validation helper functions
export const validateWithYup = async (schema, data) => {
  try {
    await schema.validate(data, { abortEarly: false });
    return {
      isValid: true,
      fieldErrors: {}
    };
  } catch (error) {
    const fieldErrors = {};
    if (error.inner) {
      error.inner.forEach(err => {
        fieldErrors[err.path] = err.message;
      });
    }
    return {
      isValid: false,
      fieldErrors
    };
  }
};

// Validate single field
export const validateField = async (schema, fieldName, value) => {
  try {
    await schema.validateAt(fieldName, { [fieldName]: value });
    return {
      isValid: true,
      error: ''
    };
  } catch (error) {
    return {
      isValid: false,
      error: error.message
    };
  }
};

export default {
  workflowDefinitionSchema,
  snippetSchema,
  taskDetailSchema,
  validateWithYup,
  validateField
};
