import styled from "styled-components";
import { COLORS } from "../../Helpers/Const";
import { colors } from "../../utils/designTokens";

export const Blinking = styled.div`
  display: ${(props) => (props.block ? "block" : "inline-block")};
  width: 100%;
  animation: blinking 1s infinite;
  @keyframes blinking {
    0% {
      opacity: 0.5;
    }
    50% {
      opacity: 0.9;
    }
    100% {
      opacity: 0.5;
    }
  }
`;

export const IconGroup = styled.div`
  font-size: 18px;
  display: flex;
  cursor: pointer;

  svg {
    margin-left: 5px;
  }
`;

export const IconWrapper = styled.i`
  font-size: ${({ fontSize = "18px" }) => fontSize};
  margin-right: 5px;
  display: inline-flex;
  align-items: center;
  cursor: ${({ isOn = true }) => (isOn ? `pointer` : `not-allowed`)};
  color: ${({ isOn = true, colorOn = "white", colorOff = COLORS.LIGHT }) =>
    isOn ? colorOn : colorOff};
`;

export const TitleBar = styled.div`
  height: 36px;
  line-height: 36px;
  width: 100%;
  padding-left: 15px;
  padding-right: 10px;
  font-size: 16px;
  color: ${colors.type.inverse || '#fff'};
  display: flex;
  justify-content: space-between;
  align-items: center;
  background-color: ${COLORS.MAIN};

  i {
    cursor: pointer;
  }
`;

export const Wrapper = styled.div`
  background-color: ${colors.background.default || '#fff'};
  padding: 10px;
  border: 1px solid ${colors.ui.border.static || '#dcddf0'};
`;

export const Flex = styled.div`
  display: flex;
  justify-content: ${({ justifyContent }) =>
    justifyContent ? justifyContent : "center"};
  align-items: center;
  width: 100%;
`;

export const FlexI = styled.span`
  display: flex;
  justify-content: ${({ justifyContent }) =>
    justifyContent ? justifyContent : "center"};
  align-items: center;
`;

export const FlexSpaceBetween = styled.div`
  display: flex;
  justify-content: space-between;
  margin-bottom: 7.5px;
  align-items: center;
  button {
    margin-left: 5px;
  }
`;

export const Legend = styled.div`
  display: inline-block;
  padding: 6px 12px;
  height: 25px;
  margin: 2.5px;
  background: ${({ backgroundColor }) =>
    backgroundColor ? backgroundColor : COLORS.LIGHT};
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 13px;
`;

export const Label = styled.div`
  display: flex;
  justify-content: flex-end;
  align-items: center;
  height: 34px;
  text-align: right;
`;
