import React from "react";
import styled from "styled-components";
import {
  WORK_ITEM_TASK_TYPES,
  WORK_ITEM_TASK_STATUS,
} from "../../Helpers/Const";
import { colors } from "../../utils/designTokens";
// No React icons needed - using legacy glyphicons only

const FilledSquareIcon = styled.span`
  display: inline-block;
  background-color: ${colors.type.default};
  border-radius: 2px;
  width: 11px;
  height: 11px;
`;

// getTypeIcon function removed - using legacy glyphicons only

export const getNodeIcon = (node) => {
  const { noIcons, statusCode, isOwnedByCurrentUser, Icon, IsRoot, isRoot, Type, type } = node;
  
  if (noIcons) {
    return <div style={{ width: "5px" }}></div>;
  }
  
  // Legacy behavior: Root nodes show NO icon (just like legacy TreeItemAdmin.cshtml)
  if (IsRoot || isRoot) {
    return <div style={{ width: "5px" }}></div>;
  }
  
  // Use Type property to return exact glyphicons classes
  const nodeType = Type || type;
  if (nodeType) {
    let glyphiconsClass = "glyphicons-unchecked"; // default
    
    switch (nodeType) {
      case WORK_ITEM_TASK_TYPES.SECTION:
        glyphiconsClass = "glyphicons-more-windows";
        break;
      case WORK_ITEM_TASK_TYPES.STEP:
        glyphiconsClass = "glyphicons-unchecked";
        break;
      case WORK_ITEM_TASK_TYPES.EDIT:
        glyphiconsClass = "glyphicons-edit";
        break;
      case WORK_ITEM_TASK_TYPES.REVIEW:
        glyphiconsClass = "glyphicons-columns";
        break;
      case WORK_ITEM_TASK_TYPES.APPROVE:
        glyphiconsClass = "glyphicons-check";
        break;
      case WORK_ITEM_TASK_TYPES.CLOSE:
        glyphiconsClass = "glyphicons-stop";
        break;
      case WORK_ITEM_TASK_TYPES.ROUTE_TO:
        glyphiconsClass = "glyphicons-new-window";
        break;
      case WORK_ITEM_TASK_TYPES.IF:
        glyphiconsClass = "glyphicons-flowchart";
        break;
      case WORK_ITEM_TASK_TYPES.GOTO:
        glyphiconsClass = "glyphicons-arrow-left";
        break;
      case WORK_ITEM_TASK_TYPES.ACTION:
        glyphiconsClass = "glyphicons-log-out";
        break;
      case WORK_ITEM_TASK_TYPES.NOTIFICATION:
        glyphiconsClass = "glyphicons-envelope";
        break;
      default:
        glyphiconsClass = "glyphicons-unchecked";
        break;
    }
    
    const legacyIconClass = `glyphicons ${glyphiconsClass} pull-left tree-item-default`;
    return <i className={legacyIconClass}></i>;
  }
  
  // Fallback: Use backend Icon property if Type is not available
  if (Icon) {
    const iconMatch = Icon.match(/glyphicons\s+glyphicons-[a-z-]+/);
    if (iconMatch) {
      const glyphiconsClass = iconMatch[0];
      const legacyIconClass = `${glyphiconsClass} pull-left tree-item-default`;
      return <i className={legacyIconClass}></i>;
    }
  }
  
  // Final fallback: Default glyphicons icon
  return <i className="glyphicons glyphicons-unchecked pull-left tree-item-default"></i>;
};

export const getNodeClass = (node) => {
  let ret = "os_default";
  switch (node.statusCode) {
    case WORK_ITEM_TASK_STATUS.ACTIVE:
      ret = "os_active";
      break;
    case WORK_ITEM_TASK_STATUS.PENDING:
      ret = "os_pending";
      break;
    case WORK_ITEM_TASK_STATUS.COMPLETE:
      ret = "os_complete";
      break;
    case WORK_ITEM_TASK_STATUS.REMOVED:
      ret = "os_removed";
      break;
    default:
      ret = "os_default";
      break;
  }

  // Add your custom classes here with atlas prefix
  const customClasses = [];
  
  // Add class based on node type
  if (node.Type || node.type) {
    const nodeType = node.Type || node.type;
    customClasses.push(`atlas-type-${String(nodeType).toLowerCase()}`);
  }
  
  // Add class based on node properties
  if (node.IsRoot || node.isRoot) {
    customClasses.push('atlas-root-node');
  }
  
  if (node.IsOwned) {
    customClasses.push('atlas-owned-node');
  }
  
  // Add class based on task type
  if (node.TaskTypeCode) {
    customClasses.push(`atlas-task-${String(node.TaskTypeCode).toLowerCase()}`);
  }
  
  // Add class based on node status
  if (node.statusCode) {
    customClasses.push(`atlas-status-${String(node.statusCode).toLowerCase()}`);
  }
  
  // Add class based on node ID for unique targeting
  if (node.id) {
    customClasses.push(`atlas-node-${node.id}`);
  }
  
  // Combine status class with custom classes
  return customClasses.length > 0 ? `${ret} ${customClasses.join(' ')}` : ret;
};

const NodeIconWrapper = ({ color, children }) => {
  return <i style={{ color }}>{children}</i>;
};

export const createTreeDataFromWorkItem = (workItem) => {
  return [
    {
      title: workItem.name || "Workflow Outline",
      expanded: true,
      noIcons: true,
      canDrag: false,
      noButton: true,
      children: workItem.workItemTasks.map((task) =>
        workItemTaskToTreeBranch(task)
      ),
    },
  ];
};

export const workItemTaskToTreeBranch = (task) => {
  return {
    ...task,
    title: task.name,
    expanded: true,
    predecessors: task.taskPredecessors.map((t) => t.id),
    children: task.workItemTasks
      ? task.workItemTasks.map((t) => workItemTaskToTreeBranch(t))
      : undefined,
  };
};
