import React, { useState, useEffect, useRef, useImperativeHandle, forwardRef } from 'react';
import { 
  Box, 
  Chip,
  Alert,
  IconButton,
  Paper,
  TextField,
  FormControl,
  InputLabel,
  Select,
  MenuItem,
  RadioGroup,
  FormControlLabel,
  Radio,
  Button,
  Link
} from '@mui/material';
import { Delete as DeleteIcon, Add as AddIcon, Settings as SettingsIcon } from '@mui/icons-material';
import FAWTypography from '../../../../FAWTypography';
import FAWButton from '../../../../FAWButton';
import FAWDropdown from '../../../../FAWDropdown';
import { 
  UDFManagement, 
  ThirdPartyFieldsManagement, 
  RelatedFieldsManagement 
} from '../fieldManagement';
import initializeCaseFlowAssignmentEditor from '../../../../../CaseFlowAssignment/CaseFlowAssignmentRoot';
import { showToast } from '../../../../shared/ToastManager';
import axios from '../../../../../../Helpers/FetchCsrfToken';

/**
 * If Task Component
 * If tasks use conditional logic, UDF, ThirdParty, and Related fields
 * Matches legacy behavior for If task type with full conditional functionality
 * Exposes saveIfTask function via ref for parent components to call
 */
const IfTask = forwardRef(({ 
  formData, 
  onFieldChange, 
  readOnly = false,
  fieldErrors = {},
  isCloseTask = false,
  workflowDefId,
  taskId,
  isSnippet = false
}, ref) => {
  const [conditions, setConditions] = useState([]);
  const getInitialEvaluateAll = () => {
    const val = formData.EvaluateAllConditions;
    if (val === true || val === 'true') return 'true';
    if (val === false || val === 'false') return 'false';
    return 'true';
  };
  const [evaluateAllConditions, setEvaluateAllConditions] = useState(getInitialEvaluateAll);
  const [errors, setErrors] = useState([]);
  const conditionCounterRef = useRef(0);

  useEffect(() => {
    const val = formData.EvaluateAllConditions;
    if (val === true || val === 'true') {
      setEvaluateAllConditions('true');
    } else if (val === false || val === 'false') {
      setEvaluateAllConditions('false');
    }
  }, [formData.EvaluateAllConditions]);

  // Initialize conditions from formData
  useEffect(() => {
    if (formData.ConditionalSnippetRulesJson && Array.isArray(formData.ConditionalSnippetRulesJson) && formData.ConditionalSnippetRulesJson.length > 0) {
      const initialConditions = formData.ConditionalSnippetRulesJson.map((rule, index) => {
        // Parse JSON string to object if it's a string, otherwise use as-is
        let parsedRule = rule;
        if (typeof rule === 'string') {
          try {
            parsedRule = JSON.parse(rule);
          } catch (error) {
            console.error(`Error parsing rule JSON for condition ${index}:`, error);
            parsedRule = null;
          }
        }
        
        return {
          id: `condition-${index}`,
          editorId: `conditioneditor${Math.floor(Math.random() * 9999999)}`,
          ruleData: parsedRule,
          index: index
        };
      }).filter(condition => condition.ruleData !== null); // Filter out any failed parses
      
      setConditions(initialConditions);
      conditionCounterRef.current = initialConditions.length;
    } else {
      // Don't create default conditions - let the UI handle empty state
      setConditions([]);
      conditionCounterRef.current = 0;
    }
  }, [formData.ConditionalSnippetRulesJson]);

  // Initialize CaseFlowAssignmentEditor for each condition
  useEffect(() => {
    
    conditions.forEach((condition) => {
      const element = document.getElementById(condition.editorId);
      
      if (element && !element.hasAttribute('data-initialized')) {
        
        // Set data attributes for the component (override any existing ones)
        element.setAttribute('data-workflow-definition-type', formData.WorkflowDefinitionType || 'WorkflowDefinition');
        element.setAttribute('data-workflow-type-meaning', 'none');
        element.setAttribute('data-workflow-type-description', 'none');
        element.setAttribute('data-workflow-definition-id', workflowDefId || '');
        element.setAttribute('data-workflow-task-definition-id', taskId || '');
        
        
        
        // Initialize the component with Redux store
        initializeCaseFlowAssignmentEditor(
          condition.index,
          condition.editorId,
          true, // isConditionalSnippet
          condition.ruleData
        );
        
        // Mark as initialized to prevent re-initialization
        element.setAttribute('data-initialized', 'true');
      }
    });
  }, [conditions, formData.WorkflowDefinitionType, workflowDefId, taskId]);

  const handleEvaluateAllChange = (event) => {
    const value = event.target.value;
    setEvaluateAllConditions(value);
    onFieldChange('EvaluateAllConditions', value === 'true');
  };

  const addCondition = () => {
    const newEditorId = `conditioneditor${Math.floor(Math.random() * 9999999)}`;
    const newCondition = {
      id: `condition-${conditionCounterRef.current}`,
      editorId: newEditorId,
      ruleData: null,
      index: conditionCounterRef.current
    };

    setConditions(prev => [...prev, newCondition]);
    conditionCounterRef.current += 1;
  };

  const removeCondition = (conditionId) => {
    const conditionToRemove = conditions.find(c => c.id === conditionId);
    if (conditionToRemove) {
      // Clean up the rule editor function
      if (window.conditionalSnippetSaveFunctions && window.conditionalSnippetSaveFunctions[conditionToRemove.editorId]) {
        delete window.conditionalSnippetSaveFunctions[conditionToRemove.editorId];
      }
    }

    setConditions(prev => {
      const updated = prev.filter(c => c.id !== conditionId);
      // Update indices
      return updated.map((condition, index) => ({
        ...condition,
        index: index
      }));
    });
  };

  const validateConditions = () => {
    const newErrors = [];
    
    if (!window.conditionalSnippetSaveFunctions) {
      window.conditionalSnippetSaveFunctions = {};
    }

    conditions.forEach((condition, index) => {
      const saveFunction = window.conditionalSnippetSaveFunctions[condition.editorId];
      if (saveFunction) {
        try {
          const filterInfo = saveFunction();
          // Check if filterInfo exists and has errorMessage property
          if (filterInfo && filterInfo.errorMessage) {
            newErrors.push({
              condition: index + 1,
              message: filterInfo.errorMessage
            });
          } else if (!filterInfo) {
            // If filterInfo is undefined/null, validation failed in saveCaseFlowRule
            // Check if the editor element exists to provide better error message
            const editorElement = document.getElementById(condition.editorId);
            if (editorElement && editorElement.hasAttribute('data-initialized')) {
              // Editor is initialized but validation failed - likely missing required fields
              newErrors.push({
                condition: index + 1,
                message: 'Condition validation failed. Please ensure all required fields are filled (filters, snippet selection, etc.).'
              });
            } else {
              // Editor not initialized yet
              newErrors.push({
                condition: index + 1,
                message: 'Condition editor not initialized. Please wait for the editor to load and configure the condition.'
              });
            }
          }
        } catch (error) {
          newErrors.push({
            condition: index + 1,
            message: 'Error validating condition: ' + error.message
          });
        }
      } else {
        // Save function doesn't exist for this condition - editor might not be initialized
        const editorElement = document.getElementById(condition.editorId);
        if (editorElement) {
          newErrors.push({
            condition: index + 1,
            message: 'Condition editor is not ready. Please wait for the editor to fully load.'
          });
        } else {
          newErrors.push({
            condition: index + 1,
            message: 'Condition editor not found. Please refresh the page and try again.'
          });
        }
      }
    });

    setErrors(newErrors);
    return newErrors.length === 0;
  };

  const saveIfTask = async () => {
    if (!validateConditions()) {
      return { success: false, message: 'Please correct condition errors before saving' };
    }

    try {
      // Get CSRF token
      const csrfResponse = await fetch('/Tour/GetAntiForgeryToken');
      const csrfData = await csrfResponse.json();
      const csrfToken = csrfData.token;
      const cookieToken = csrfData.cookieToken;
      document.cookie = `CookieToken=${cookieToken}; path=/`;

      // Build filter groups
      const filterGroups = [];
      conditions.forEach(condition => {
        const saveFunction = window.conditionalSnippetSaveFunctions[condition.editorId];
        if (saveFunction) {
          try {
            const filterInfo = saveFunction();
            // Check if filterInfo exists and has no error
            if (filterInfo && !filterInfo.errorMessage && filterInfo.filters && filterInfo.filters.length > 0) {
              filterGroups.push({
                filter: filterInfo.filters[0],
                snippetId: filterInfo.snippetId || 0,
                formId: filterInfo.formId || 0
              });
            }
          } catch (error) {
            console.error(`Error building filter group for condition ${condition.id}:`, error);
            // Skip this condition if there's an error
          }
        }
      });

      const taskDefinition = {
        filterGroups,
        evaluateAllConditions: evaluateAllConditions === 'true' || evaluateAllConditions === true,
        name: formData.Name || '',
        description: formData.Description || '',
        status: formData.Status || '',
        workQueueId: formData.WorkQueueId || '',
        workflowTaskDefinitionId: taskId,
        newlyCreated: formData.NewlyCreated === 'True' || formData.NewlyCreated === true,
        isSnippetTask: formData.IsSnippetTask === 'True' || formData.IsSnippetTask === true,
        containerId: workflowDefId,
        order: formData.Order || 0,
        parentWorkflowTaskDefinitionId: formData.ParentWorkflowTaskDefinitionId || '',
        lockId: formData.LockId || 0
      };

      // Use WorkflowDef endpoint - it handles both snippets and workflow definitions based on IsSnippetTask flag
      const endpoint = '/WorkflowDef/SaveConditionalSnippetTaskDef';
      
      const response = await axios.post(endpoint, taskDefinition, {
        headers: {
          'Accept': 'application/json',
          'Content-Type': 'application/json',
          '__RequestVerificationToken': csrfToken
        }
      });

      const result = response.data;

      if (!result.success) {
        const errorMessage = result.message || 'Failed to save conditional snippet task';
        setErrors([{ condition: 0, message: errorMessage }]);
        showToast.error(errorMessage);
        return { success: false, message: errorMessage };
      } else {
        // Clear save functions
        window.conditionalSnippetSaveFunctions = {};
        setErrors([]);
        showToast.success('Conditional snippet task saved successfully');
        return { success: true, data: result };
      }
    } catch (error) {
      console.error('Error saving if task:', error);
      const errorMessage = error.message || 'Failed to save task definition.';
      setErrors([{ condition: 0, message: errorMessage }]);
      showToast.error(errorMessage);
      return { success: false, message: errorMessage };
    }
  };

  // Expose saveIfTask to parent component via ref
  useImperativeHandle(ref, () => ({
    save: saveIfTask,
    validate: validateConditions
  }));

  return (
    <Box className="if-task-container" sx={{ display: 'flex', flexDirection: 'column', gap: 3 }}>

      {/* Condition Evaluation Section */}
      <Paper 
        className="if-task-condition-evaluation-section" 
        sx={{ 
          backgroundColor: '#f3f3f3',
          borderRadius: 1,
          p: 3,
          border: 'none',
          boxShadow: 'none !important'
        }}
      >
        <FAWTypography 
          className="if-task-condition-evaluation-title"
          variant="h6"
          sx={{ fontWeight: 600, marginBottom: '20px' }}
        >
          Condition Evaluation
        </FAWTypography>

        <Box className="if-task-condition-evaluation-radio-group" sx={{ display: 'flex', flexDirection: 'column', gap: 2, mb: 3 }}>
          <Box sx={{ display: 'flex', alignItems: 'center', gap: 1.5 }}>
            <input
              type="radio"
              id="evaluate-all-if"
              name="condition-evaluation-if"
              value="true"
              checked={evaluateAllConditions === 'true'}
              onChange={handleEvaluateAllChange}
              className="if-task-condition-evaluation-radio"
              style={{
                width: '24px',
                height: '24px',
                accentColor: '#282e37'
              }}
            />
            <FAWTypography 
              className="if-task-condition-evaluation-label"
              variant="body1"
            >
              Evaluate all conditions
            </FAWTypography>
          </Box>

          <Box sx={{ display: 'flex', alignItems: 'center', gap: 1.5 }}>
            <input
              type="radio"
              id="evaluate-first-if"
              name="condition-evaluation-if"
              value="false"
              checked={evaluateAllConditions === 'false'}
              onChange={handleEvaluateAllChange}
              className="if-task-condition-evaluation-radio"
              style={{
                width: '24px',
                height: '24px',
                accentColor: '#282e37'
              }}
            />
            <FAWTypography 
              className="if-task-condition-evaluation-label"
              variant="body1"
            >
              Evaluate until first true condition is found
            </FAWTypography>
          </Box>
        </Box>

        <FAWButton
          className="if-task-add-condition-btn"
          variant="outlined"
          icon="add"
          onClick={addCondition}
          disabled={readOnly}
        >
          Add Condition
        </FAWButton>
      </Paper>

      {/* Dynamic Condition Blocks */}
      {conditions.map((condition, index) => (
        <Paper 
          key={condition.id}
          className="if-task-condition-block"
          sx={{ 
            backgroundColor: '#f3f3f3',
            borderRadius: 1,
            p: 1,
            display: 'flex',
            flexDirection: 'column',
            gap: 2
          }}
        >
          {/* Condition Header */}
          <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
            <FAWTypography 
              className="if-task-condition-title"
              variant="h6" 
              sx={{ 
                fontWeight: 600,
                fontSize: '18px',
                lineHeight: '28px',
                color: '#282e37',
                letterSpacing: '0.2px'
              }}
            >
              Condition {index + 1}
            </FAWTypography>
            <IconButton
              className="if-task-delete-btn"
              onClick={() => removeCondition(condition.id)}
              disabled={readOnly}
              size="small"
              sx={{ 
                color: '#282e37',
                '&:hover': {
                  backgroundColor: 'rgba(40, 46, 55, 0.04)'
                }
              }}
            >
              <DeleteIcon fontSize="small" />
            </IconButton>
          </Box>

          {/* Rule Editor Container */}
          <Box 
            id={condition.editorId}
            className="editor-container"
            data-workflow-definition-type={formData.WorkflowDefinitionType}
            data-workflow-type-meaning="none"
            data-workflow-type-description="none"
            data-workflow-definition-id={workflowDefId}
            data-workflow-task-definition-id={taskId}
            sx={{ 
              minHeight: '400px',
              maxHeight: '600px',
              border: '1px solid #e0e0e0',
              borderRadius: 1,
              p: 1,
              backgroundColor: 'white',
              overflowY: 'auto'
            }}
          >
            {/* Create a mock modal-body for the component */}
            <div className="modal-body" style={{ 
              height: '500px', 
              overflowY: 'auto',
              padding: '0',
              margin: '0'
            }}>
              {/* CaseFlowAssignmentEditor will be initialized here via useEffect */}
            </div>
          </Box>
        </Paper>
      ))}

      {/* Error Display */}
      {errors.length > 0 && (
        <Alert severity="error" sx={{ mb: 2 }}>
          <FAWTypography variant="body2" sx={{ fontWeight: 600, mb: 1 }}>
            Please correct the following errors before saving:
          </FAWTypography>
          {errors.map((error, index) => (
            <FAWTypography key={index} variant="body2">
              <strong>Condition {error.condition}</strong>: {error.message}
            </FAWTypography>
          ))}
        </Alert>
      )}

      {/* User Defined Fields - Show for all task types EXCEPT Action, Notification, ConditionalSnippet, Section, IF */}
      {formData.Type !== 'Action' && 
       formData.Type !== 'ACTION' &&
       formData.Type !== 'Notification' && 
       formData.Type !== 'NOTIFICATION' &&
       formData.Type !== 'ConditionalSnippet' && 
       formData.Type !== 'CONDITIONAL_SNIPPET' &&
       formData.Type !== 'Section' && 
       formData.Type !== 'SECTION' &&
       formData.Type !== 'IF' && (
        <Box className="if-task-udf-section">
          <UDFManagement
            formData={formData}
            onFieldChange={onFieldChange}
            readOnly={readOnly}
          />
        </Box>
      )}

      {/* Third Party Fields - Show for all task types EXCEPT Action, Notification, ConditionalSnippet, Section, IF */}
      {formData.Type !== 'Action' && 
       formData.Type !== 'ACTION' &&
       formData.Type !== 'Notification' && 
       formData.Type !== 'NOTIFICATION' &&
       formData.Type !== 'ConditionalSnippet' && 
       formData.Type !== 'CONDITIONAL_SNIPPET' &&
       formData.Type !== 'Section' && 
       formData.Type !== 'SECTION' &&
       formData.Type !== 'IF' && (
        <Box className="if-task-third-party-section" sx={{ mb: 3 }}>
          <ThirdPartyFieldsManagement
            formData={formData}
            onFieldChange={onFieldChange}
            readOnly={readOnly}
          />
        </Box>
      )}

      {/* Related Fields - Only show for snippet tasks or FormSubmission workflows, but NOT for Action, Notification, ConditionalSnippet, Section, IF */}
      {formData.Type !== 'Notification' && 
       formData.Type !== 'NOTIFICATION' &&
       formData.Type !== 'Action' &&
       formData.Type !== 'ACTION' &&
       formData.Type !== 'ConditionalSnippet' &&
       formData.Type !== 'CONDITIONAL_SNIPPET' &&
       formData.Type !== 'Section' &&
       formData.Type !== 'SECTION' &&
       formData.Type !== 'IF' &&
       (formData.IsSnippetTask === true || formData.WorkflowDefinitionTypeCode === 'FormSubmission') && (
        <>
          {/* Divider above Related Fields */}
          <Box 
            className="if-task-divider-above-related-fields" 
            sx={{ 
              height: '1px', 
              backgroundColor: '#e0e0e0', 
              margin: '16px 0',
              width: '100%'
            }} 
          />
          <Box className="if-task-related-fields-section" sx={{ mb: 3 }}>
            <RelatedFieldsManagement
              formData={formData}
              onFieldChange={onFieldChange}
              readOnly={readOnly}
            />
          </Box>
        </>
      )}
    </Box>
  );
});

IfTask.displayName = 'IfTask';

export default IfTask;

