import React from 'react';
import { Box } from '@mui/material';
import FAWTypography from '../../../FAWTypography';
import FAWInput from '../../../FAWInput';
import FAWTextarea from '../../../FAWTextarea';
import FAWDropdown from '../../../FAWDropdown';
import { getRouteToLabel } from '../utils';

/**
 * Basic Task Fields Component
 * Contains the fundamental fields (Name, Description, Status, Route To) that all task types should have
 * Used across all task types to ensure consistent basic field handling
 * Field management sections (UDF, ThirdParty, Related) are handled by individual task type components
 */
const BasicTaskFields = ({ 
  formData, 
  onFieldChange, 
  readOnly = false,
  fieldErrors = {},
  isCloseTask = false
}) => {
  // Calculate if status dropdown should be shown
  const showStatusDropdown = formData.ShowCaseStatusDropdown || formData.HasStatus || formData.hasStatus;
  
  // Calculate if route to dropdown should be shown
  const showRouteToDropdown = formData.HasRouteTo || formData.hasRouteTo;
  const routeToLabel = getRouteToLabel(formData.Type);
  
  // Calculate if name field should be editable
  const isNameEditable = !readOnly;
  
  return (
    <Box className="basic-task-fields-container">
      {/* Name Section */}
      <Box className="basic-task-name-section" sx={{ display: 'flex', flexDirection: 'column', gap: '8px', mb: 2 }}>
        <FAWTypography 
          className="basic-task-name-label"
          sx={{ fontSize: '14px', fontWeight: 500 }}
        >
          Name
        </FAWTypography>
        <FAWInput
          className="basic-task-name-input"
          placeholder="Enter task name"
          value={formData.Name || ''}
          onChange={(e) => onFieldChange('Name', e.target.value)}
          disabled={!isNameEditable}
          fullWidth
          required
          error={!!fieldErrors.Name}
          helperText={fieldErrors.Name || ''}
          sx={{
            '& .MuiOutlinedInput-root': {
              height: '40px',
              backgroundColor: 'white',
              borderRadius: '8px',
              '& .MuiOutlinedInput-notchedOutline': {
                borderColor: '#6f7377'
              }
            }
          }}
        />
      </Box>
      
      {/* Description Section */}
      <Box className="basic-task-description-section" sx={{ display: 'flex', flexDirection: 'column', gap: '8px', mb: 2 }}>
        <FAWTypography 
          className="basic-task-description-label"
          sx={{ fontSize: '14px', fontWeight: 500 }}
        >
          Description
        </FAWTypography>
        <FAWTextarea
          className="basic-task-description-input"
          placeholder="Enter task description"
          value={formData.Description || ''}
          onChange={(e) => onFieldChange('Description', e.target.value)}
          disabled={readOnly}
          fullWidth
          rows={3}
          error={!!fieldErrors.Description}
          helperText={fieldErrors.Description || ''}
          sx={{
            '& .MuiOutlinedInput-root': {
              minHeight: '84px',
              backgroundColor: 'white',
              borderRadius: '8px',
              overflow: 'visible !important',
              '& .MuiOutlinedInput-notchedOutline': {
                borderColor: '#6f7377'
              }
            }
          }}
        />
      </Box>
      
      {/* Divider above Status and Route To */}
      {(showStatusDropdown || showRouteToDropdown) && (
        <Box 
          className="basic-task-divider-above-status-route" 
          sx={{ 
            height: '1px', 
            backgroundColor: '#e0e0e0', 
            margin: '16px 0',
            width: '100%'
          }} 
        />
      )}

      {/* Status and Route To Section - Side by Side */}
      {(showStatusDropdown || showRouteToDropdown) && (
        <Box className="basic-task-status-route-section" sx={{ display: 'flex', gap: '16px', mb: 2 }}>
          {/* Status Field - Left Half */}
          {showStatusDropdown && (
            <Box className="basic-task-status-section" sx={{ flex: 1, display: 'flex', flexDirection: 'column', gap: '8px' }}>
              <FAWDropdown
                className="basic-task-status-dropdown"
                label={isCloseTask ? 'Disposition' : 'Status'}
                placeholder={formData.Statuses && formData.Statuses.length > 0 ? "Choose an option" : "No options available"}
                value={formData.Status || ''}
                onChange={(selectedOption) => onFieldChange('Status', selectedOption?.value || '')}
                disabled={readOnly || !formData.Statuses || formData.Statuses.length === 0}
                options={formData.Statuses && formData.Statuses.length > 0 ? formData.Statuses.map((status) => ({
                  value: status.Value || status.value,
                  label: status.Text || status.text
                })) : []}
                error={!!fieldErrors.Status}
                helperText={fieldErrors.Status || ''}
                sx={{
                  '& .MuiOutlinedInput-root': {
                    height: '40px',
                    backgroundColor: formData.Statuses && formData.Statuses.length > 0 ? 'white' : '#f5f5f5',
                    borderRadius: '8px',
                    '& .MuiOutlinedInput-notchedOutline': {
                      borderColor: formData.Statuses && formData.Statuses.length > 0 ? '#6f7377' : '#d0d0d0'
                    }
                  },
                  '& .MuiInputBase-input': {
                    color: formData.Statuses && formData.Statuses.length > 0 ? 'inherit' : '#999',
                    cursor: formData.Statuses && formData.Statuses.length > 0 ? 'text' : 'not-allowed'
                  }
                }}
              />
            </Box>
          )}

          {/* Route To Field - Right Half */}
          {showRouteToDropdown && (
            <Box className="basic-task-route-to-section" sx={{ flex: 1, display: 'flex', flexDirection: 'column', gap: '8px' }}>
              <FAWDropdown
                className="basic-task-route-to-dropdown"
                label={routeToLabel}
                placeholder={formData.WorkQueues && formData.WorkQueues.length > 0 ? "Choose an option" : "N/A"}
                value={formData.WorkQueues && formData.WorkQueues.length > 0 ? String(formData.WorkQueueId || '') : 'N/A'}
                onChange={(selectedOption) => onFieldChange('WorkQueueId', selectedOption?.value || '')}
                disabled={readOnly || !(formData.WorkQueues && formData.WorkQueues.length > 0)}
                options={formData.WorkQueues && formData.WorkQueues.length > 0 ? formData.WorkQueues.map((queue) => ({
                  value: queue.Value || queue.value,
                  label: queue.Text || queue.text
                })) : []}
                error={!!fieldErrors.WorkQueueId}
                helperText={fieldErrors.WorkQueueId || ''}
                sx={{
                  '& .MuiOutlinedInput-root': {
                    height: '40px',
                    backgroundColor: formData.WorkQueues && formData.WorkQueues.length > 0 ? 'white' : '#f5f5f5',
                    borderRadius: '8px',
                    '& .MuiOutlinedInput-notchedOutline': {
                      borderColor: formData.WorkQueues && formData.WorkQueues.length > 0 ? '#6f7377' : '#d0d0d0'
                    }
                  },
                  '& .MuiInputBase-input': {
                    color: formData.WorkQueues && formData.WorkQueues.length > 0 ? 'inherit' : '#999',
                    cursor: formData.WorkQueues && formData.WorkQueues.length > 0 ? 'text' : 'not-allowed'
                  }
                }}
              />
            </Box>
          )}
        </Box>
      )}

    </Box>
  );
};

export default BasicTaskFields;
