import React from 'react';
import PropTypes from 'prop-types';
import {
    Dialog,
    DialogTitle,
    DialogContent,
    DialogActions,
    Box,
    IconButton
} from '@mui/material';
import CloseIcon from '@mui/icons-material/Close';
import FAWTypography from './FAWTypography';
import FAWTooltip from './FAWTooltip';
import FAWButton from './FAWButton';
import FAWLoader from './FAWLoader';
import { colors } from "../../utils/designTokens";

/**
 * FAWConfirmDialogue - Unified dialog component for both custom content and confirmations
 * 
 * CUSTOM CONTENT MODE:
 * @param {React.Node} props.children - Custom dialog content
 * @param {Array} props.actions - Array of action button configurations
 * 
 * CONFIRMATION MODE:
 * @param {string} props.variant - Confirmation type (delete, warning, info)
 * @param {string} props.message - Main confirmation message
 * @param {string} props.description - Additional description text
 * @param {string} props.itemName - Name of item being acted upon
 * @param {function} props.onConfirm - Function called when user confirms
 * @param {string} props.confirmLabel - Label for confirm button
 * @param {string} props.cancelLabel - Label for cancel button
 * @param {boolean} props.loading - Whether confirm action is loading
 * 
 * COMMON PROPS:
 * @param {boolean} props.open - Whether dialog is open
 * @param {function} props.onClose - Function called when dialog should close
 * @param {string} props.title - Dialog title text
 * @param {string} props.maxWidth - Dialog max width (xs, sm, md, lg, xl)
 * @param {boolean} props.fullWidth - Whether dialog should take full width
 * @param {boolean} props.showCloseButton - Whether to show close button in title
 * @param {Object} props.sx - Additional styling
 */
const FAWConfirmDialogue = ({
    // Common props
    open = false,
    onClose,
    title,
    titleColor: propTitleColor,
    maxWidth = 'sm',
    fullWidth = true,
    showCloseButton = false,
    sx = {},
    /** When true, positions the dialog at the top of the viewport instead of centered */
    positionAtTop = false,
    
    // Custom content mode
    children,
    actions = [],
    
    // Confirmation mode
    variant,
    message,
    description,
    itemName,
    onConfirm,
    confirmLabel,
    cancelLabel = 'Cancel',
    loading = false,
    
    ...rest
}) => {
    // Determine if this is confirmation mode
    const isConfirmationMode = Boolean(variant || message || onConfirm);
    
    // Get variant configuration for confirmation mode
    const getVariantConfig = () => {
        switch (variant) {
            case 'delete':
                return {
                    titleColor: 'error',
                    confirmColor: 'error',
                    defaultTitle: 'Confirm Delete',
                    defaultMessage: 'Are you sure you want to delete this item?',
                    defaultDescription: 'This action cannot be undone.',
                    defaultConfirmLabel: 'Delete'
                };
            case 'warning':
                return {
                    titleColor: 'warning.main',
                    confirmColor: 'warning',
                    defaultTitle: 'Warning',
                    defaultMessage: 'This action requires confirmation.',
                    defaultConfirmLabel: 'Proceed'
                };
            default: // info
                return {
                    titleColor: 'primary.main',
                    confirmColor: 'primary',
                    defaultTitle: 'Confirm Action',
                    defaultMessage: 'Are you sure you want to proceed?',
                    defaultConfirmLabel: 'Confirm'
                };
        }
    };
    
    // Build confirmation actions if in confirmation mode
    let finalActions = actions;
    let finalTitle = title;
    let finalTitleColor = 'inherit';
    let dialogContent = children;
    
    if (isConfirmationMode) {
        const config = getVariantConfig();
        finalTitle = title || config.defaultTitle;
        finalTitleColor = propTitleColor || config.titleColor;
        
        finalActions = [
            {
                label: cancelLabel,
                onClick: onClose,
                variant: 'outlined',
                color: 'inherit',
                disabled: loading
            },
            {
                label: confirmLabel || config.defaultConfirmLabel,
                onClick: onConfirm,
                variant: 'contained',
                color: config.confirmColor,
                disabled: loading,
                loading: loading,
                sx: variant === 'delete' ? {
                    backgroundColor: colors.status.error,
                    color: colors.type.inverse,
                    '&:hover': {
                        backgroundColor: colors.status.error + 'dd'
                    },
                    '&:disabled': {
                        backgroundColor: colors.status.error + '80',
                        color: colors.type.inverse
                    }
                } : {}
            }
        ];
        
        // Parse message to highlight item names in red for delete variant
        const renderMessage = () => {
            const messageText = message || config.defaultMessage;
            
            if (variant === 'delete' && itemName) {
                // Split message by the item name to apply red color
                const parts = messageText.split(itemName);
                if (parts.length > 1) {
                    return (
                        <FAWTypography variant="body1">
                            {parts[0]}
                            <span style={{ color: colors.status.error, fontWeight: 'bold' }}>
                                {itemName}
                            </span>
                            {parts[1]}
                        </FAWTypography>
                    );
                }
            }
            
            return (
                <FAWTypography variant="body1">
                    {messageText}
                </FAWTypography>
            );
        };
        
        dialogContent = (
            <>
                {renderMessage()}
                
                {(description || config.defaultDescription) && (
                    <FAWTypography variant="body2" sx={{ color: 'text.secondary' }}>
                        {description || config.defaultDescription}
                    </FAWTypography>
                )}
            </>
        );
    }
    const positionAtTopSx = positionAtTop
        ? {
            '& .MuiDialog-container': {
                alignItems: 'flex-start',
                paddingTop: '24px'
            }
        }
        : {};
    return (
        <Dialog
            open={open}
            onClose={onClose}
            maxWidth={maxWidth}
            fullWidth={fullWidth}
            sx={{
                ...sx,
                ...positionAtTopSx,
                '& .MuiDialog-paper': {
                    borderRadius: 1,
                    ...sx
                }
            }}
            {...rest}
        >
            {finalTitle && (
                <DialogTitle sx={{ 
                    display: 'flex', 
                    justifyContent: 'space-between', 
                    alignItems: 'center',
                    pb: 1
                }}>
                    <FAWTypography 
                        variant="subtitle1" 
                        component="span"
                        color={finalTitleColor}
                        sx={{ 
                            fontWeight: 'bold', 
                            fontSize: '1.5rem' 
                        }}
                    >
                        {finalTitle}
                    </FAWTypography>
                    {showCloseButton && (
                        <FAWTooltip title="Close">
                            <IconButton
                                onClick={onClose}
                                size="small"
                                sx={{ color: 'text.secondary' }}
                            >
                                <CloseIcon />
                            </IconButton>
                        </FAWTooltip>
                    )}
                </DialogTitle>
            )}
            
            <DialogContent>
                <Box sx={{ display: 'flex', flexDirection: 'column', gap: 2, py: 1 }}>
                    {dialogContent}
                </Box>
            </DialogContent>
            
            {finalActions.length > 0 && (
                <DialogActions sx={{ justifyContent: 'space-between', px: 3, py: 2 }}>
                    {finalActions.map((action, index) => (
                        <FAWButton
                            key={index}
                            variant={action.variant || 'outlined'}
                            color={action.color || 'inherit'}
                            onClick={action.onClick}
                            disabled={action.disabled || false}
                            startIcon={action.startIcon}
                            endIcon={action.endIcon}
                            sx={action.sx}
                        >
                            {action.loading ? (
                                <FAWLoader size={20} />
                            ) : (
                                action.label
                            )}
                        </FAWButton>
                    ))}
                </DialogActions>
            )}
        </Dialog>
    );
};

FAWConfirmDialogue.propTypes = {
    open: PropTypes.bool,
    onClose: PropTypes.func,
    title: PropTypes.string,
    titleColor: PropTypes.string,
    children: PropTypes.node,
    actions: PropTypes.arrayOf(PropTypes.shape({
        label: PropTypes.string.isRequired,
        onClick: PropTypes.func.isRequired,
        variant: PropTypes.string,
        color: PropTypes.string,
        disabled: PropTypes.bool,
        loading: PropTypes.bool,
        startIcon: PropTypes.node,
        endIcon: PropTypes.node,
        sx: PropTypes.object
    })),
    maxWidth: PropTypes.oneOf(['xs', 'sm', 'md', 'lg', 'xl']),
    fullWidth: PropTypes.bool,
    showCloseButton: PropTypes.bool,
    sx: PropTypes.object,
    positionAtTop: PropTypes.bool
};

export default FAWConfirmDialogue;
