import React, { useState, useEffect, useMemo } from 'react';
import { Box, Typography, Alert } from '@mui/material';
import FAWModal from '../FAWModal';
import FAWButton from '../FAWButton';
import FAWSkeleton from '../FAWSkeleton';
import FAWTooltip from '../FAWTooltip';
import FAWTable from '../FAWTable/FAWTable';

/**
 * Shared Insert Snippet Modal Component
 * Used by both workflow definitions and snippets
 */
const InsertSnippetModal = ({ 
  open, 
  onClose, 
  onSave, 
  entityId, // Can be workflowId or snippetId
  entityType = 'workflow', // 'workflow' or 'snippet'
  taskId,
  getSnippetsApi // Function to get snippets - should be passed from parent
}) => {
  const [loading, setLoading] = useState(false);
  const [saving, setSaving] = useState(false);
  const [snippets, setSnippets] = useState([]);
  const [selectedSnippetId, setSelectedSnippetId] = useState(null);
  const [error, setError] = useState(null);

  // Load snippets when modal opens
  useEffect(() => {
    if (open && entityId && getSnippetsApi) {
      loadSnippets();
    }
  }, [open, entityId, getSnippetsApi]);

  const loadSnippets = async () => {
    setLoading(true);
    setError(null);

    try {
      const snippetsData = await getSnippetsApi(entityId);
      setSnippets(Array.isArray(snippetsData) ? snippetsData : []);
    } catch (err) {
      setError(err.message || 'Failed to load snippets');
      setSnippets([]);
    } finally {
      setLoading(false);
    }
  };

  const handleSnippetSelect = (snippetId) => {
    setSelectedSnippetId(snippetId);
    setError(null);
  };

  const handleSave = async () => {
    if (!selectedSnippetId) {
      setError('Please select a snippet to insert');
      return;
    }

    setSaving(true);
    setError(null);

    try {
      // Call the save handler with the selected snippet
      if (onSave) {
        await onSave({
          snippetId: selectedSnippetId,
          entityId,
          entityType,
          taskId
        });
      }
      onClose();
    } catch (err) {
      setError(err.message || 'Failed to insert snippet');
    } finally {
      setSaving(false);
    }
  };

  // Convert snippets to FAWTable rows format
  const rows = useMemo(() => {
    return snippets.map((snippet) => ({
      id: snippet.id || `snippet_${snippet.name}`,
      name: snippet.name || '',
      description: snippet.description || '',
      lastUpdate: snippet.lastUpdate || null,
    }));
  }, [snippets]);

  // FAWTable column definitions
  const columns = useMemo(() => [
    {
      field: 'name',
      headerName: 'Name',
      width: 300,
      minWidth: 200,
      renderCell: (params) => {
        const isSelected = selectedSnippetId === params.row.id;
        return (
          <Typography 
            variant="body2" 
            sx={{ 
              fontWeight: isSelected ? 600 : 400,
              color: isSelected ? '#1976d2' : 'inherit'
            }}
          >
            {params.value}
          </Typography>
        );
      }
    },
    {
      field: 'description',
      headerName: 'Description',
      flex: 1,
      minWidth: 300,
      renderCell: (params) => (
        <FAWTooltip title={params.value || 'No description available'}>
          <Typography 
            variant="body2" 
            sx={{ 
              overflow: 'hidden',
              textOverflow: 'ellipsis',
              whiteSpace: 'nowrap'
            }}
          >
            {params.value || 'No description available'}
          </Typography>
        </FAWTooltip>
      )
    },
    {
      field: 'lastUpdate',
      headerName: 'Last Updated',
      width: 200,
      renderCell: (params) => (
        <Typography variant="body2" color="text.secondary">
          {params.value ? new Date(params.value).toLocaleDateString() : 'N/A'}
        </Typography>
      )
    }
  ], [selectedSnippetId]);

  // FAWTable row click handler
  const handleRowClick = (params) => {
    const snippetId = params.row.id;
    handleSnippetSelect(snippetId);
  };

  // FAWTable row style for selection
  const getRowClassName = (params) => {
    if (selectedSnippetId === params.row.id) {
      return 'snippet-row-selected';
    }
    return '';
  };

  const modalContent = (
    <Box sx={{ p: 2, height: '100%', display: 'flex', flexDirection: 'column' }}>
      {loading ? (
        <Box sx={{ flex: 1 }}>
          <FAWSkeleton variant="modal" />
        </Box>
      ) : error ? (
        <Alert severity="error" sx={{ mb: 2 }}>
          {error}
        </Alert>
      ) : (
        <>
          {/* Instructions */}
          <Typography variant="body2" sx={{ mb: 2, color: 'text.secondary' }}>
            Select a snippet to insert into the workflow. Click on a row to select it.
          </Typography>

          {/* Snippets FAWTable */}
          <Box sx={{ flex: 1, mb: 2 }}>
            {snippets.length > 0 ? (
              <>
                <style>{`
                  .snippet-row-selected {
                    background-color: #e3f2fd !important;
                  }
                  .snippet-row-selected:hover {
                    background-color: #bbdefb !important;
                  }
                `}</style>
                <FAWTable
                  rows={rows}
                  columns={columns}
                  onRowClick={handleRowClick}
                  maxHeight={500}
                  minHeight={500}
                  showToolbar={false}
                  showPagination={false}
                  showFilter={true}
                  showSearch={true}
                  checkboxSelection={false}
                  enableMultiSelect={false}
                  hasDisableRowSelectionClick={false}
                  getRowClassName={getRowClassName}
                  emptyStateTitle="No snippets available for this workflow"
                  gridSx={{ height: '500px', width: '100%' }}
                />
              </>
            ) : (
              <Box sx={{ 
                height: 500, 
                display: 'flex', 
                alignItems: 'center', 
                justifyContent: 'center',
                border: '1px solid #e0e0e0',
                borderRadius: 1,
                backgroundColor: '#f5f5f5'
              }}>
                <Typography variant="body2" color="text.secondary">
                  No snippets available for this workflow
                </Typography>
              </Box>
            )}
          </Box>

          {/* Action Buttons */}
          <Box sx={{ display: 'flex', gap: 2, justifyContent: 'flex-end', borderTop: '1px solid #e0e0e0', pt: 2 }}>
            <FAWButton
              variant="outlined"
              color="inherit"
              onClick={onClose}
              disabled={saving}
            >
              Cancel
            </FAWButton>
            <FAWButton
              variant="contained"
              onClick={handleSave}
              disabled={saving || !selectedSnippetId}
            >
              {saving ? 'Saving...' : 'Confirm and Insert'}
            </FAWButton>
          </Box>
        </>
      )}
    </Box>
  );

  return (
    <FAWModal
      open={open}
      onClose={onClose}
      title="Insert Snippet"
      content={modalContent}
      fullWidth={true}
      sx={{
        '& .MuiDialog-paper': {
          width: { xs: '95vw', sm: '90vw', md: '80vw', lg: '70vw', xl: '60vw' },
          maxWidth: { xs: '95vw', sm: '90vw', md: '80vw', lg: '70vw', xl: '60vw' },
          minWidth: { xs: '400px', sm: '500px', md: '600px', lg: '700px', xl: '800px' }
        }
      }}
    />
  );
};

export default InsertSnippetModal;
