  // Add task to workflow
  async addTask(workflowId, parentTaskId, taskType) {
    const taskTypeName = getTaskTypeName(taskType);
    
    try {
      showToast.info(`Creating ${taskTypeName} task...`);
      const response = await this.request(`/WorkflowDef/CreateWorkflowTaskDef?workflowDefId=${workflowId}&parentTaskId=${parentTaskId}&taskType=${taskType}`, {
        method: 'POST'
      });

      if (response.success) {
        showToast.success(response.message || `${taskTypeName} task created successfully`);
      }
      return {
        ...response,
        redirectToTask: true,
        taskId: response.taskId || response.data?.taskId
      };
    } catch (error) {
      console.error('Error adding task:', error);
      showToast.error(error.message || `Failed to create ${taskTypeName} task`);
      throw error;
    }
  }

