import React from 'react';
import { Box, Chip } from '@mui/material';
import FAWTypography from '../../../../FAWTypography';
import { 
  UDFManagement, 
  ThirdPartyFieldsManagement, 
  RelatedFieldsManagement 
} from '../fieldManagement';

/**
 * Approve Task Component
 * Approve tasks use UDF, ThirdParty, and Related fields
 * Matches legacy behavior for Approve task type
 */
const ApproveTask = ({ 
  formData, 
  onFieldChange, 
  readOnly = false,
  fieldErrors = {},
  isCloseTask = false
}) => {
  return (
    <Box className="approve-task-container">
      
      {/* Approve Task Specific Configuration */}
      <FAWTypography variant="body2" color="text.secondary">
        This task will require approval from designated users. Configure the approval workflow settings below.
      </FAWTypography>

      {/* User Defined Fields - Show for all task types EXCEPT Action, Notification, ConditionalSnippet, Section */}
      {formData.Type !== 'Action' && 
       formData.Type !== 'Notification' && 
       formData.Type !== 'ConditionalSnippet' && 
       formData.Type !== 'Section' && (
        <Box className="approve-task-udf-section" sx={{ mb: 3 }}>
          <UDFManagement
            formData={formData}
            onFieldChange={onFieldChange}
            readOnly={readOnly}
          />
        </Box>
      )}

      {/* Third Party Fields - Show for all task types EXCEPT Action, Notification, ConditionalSnippet, Section */}
      {formData.Type !== 'Action' && 
       formData.Type !== 'Notification' && 
       formData.Type !== 'ConditionalSnippet' && 
       formData.Type !== 'Section' && (
        <Box className="approve-task-third-party-section" sx={{ mb: 3 }}>
          <ThirdPartyFieldsManagement
            formData={formData}
            onFieldChange={onFieldChange}
            readOnly={readOnly}
          />
        </Box>
      )}

      {/* Related Fields - Only show for snippet tasks or FormSubmission workflows, but NOT for Action, Notification, ConditionalSnippet, Section */}
      {formData.Type !== 'Notification' && 
       formData.Type !== 'Action' &&
       formData.Type !== 'ConditionalSnippet' &&
       formData.Type !== 'Section' &&
       (formData.IsSnippetTask === true || formData.WorkflowDefinitionTypeCode === 'FormSubmission') && (
        <Box className="approve-task-related-fields-section" sx={{ mb: 3 }}>
          <FAWTypography className="approve-task-related-fields-title" variant="h6" sx={{ mb: 2, fontSize: '1.1rem', fontWeight: 'bold' }}>
            Form Answers
            {formData.RelatedFields && formData.RelatedFields.length > 0 && (
              <Chip 
                className="approve-task-related-fields-count-chip"
                label={formData.RelatedFields.length} 
                size="small" 
                sx={{ ml: 1 }} 
              />
            )}
          </FAWTypography>
          <RelatedFieldsManagement
            formData={formData}
            onFieldChange={onFieldChange}
            readOnly={readOnly}
          />
        </Box>
      )}
    </Box>
  );
};

export default ApproveTask;
