import React from 'react';
import { Box, Grid, Chip } from '@mui/material';
import FAWTypography from '../../../../FAWTypography';
import FAWRadioGroup from '../../../../FAWRadioGroup';
import { 
  UDFManagement, 
  ThirdPartyFieldsManagement, 
  RelatedFieldsManagement 
} from '../fieldManagement';

/**
 * Close Task Component
 * Close tasks have IsAutoComplete radio buttons and use UDF, ThirdParty, Related fields
 * Matches legacy behavior for Close task type
 */
const CloseTask = ({ 
  formData, 
  onFieldChange, 
  readOnly = false,
  fieldErrors = {},
  isCloseTask = false
}) => {
  return (
    <Box className="close-task-container">  
      
      {/* Auto Complete Section */}
      <Box className="close-task-auto-complete-section" sx={{ mb: 3 }}>
        <FAWTypography 
          className="close-task-auto-complete-label" 
          variant="subtitle2" 
          sx={{ mb: 1, fontWeight: 'bold' }}
        >
          Auto Complete
        </FAWTypography>
        <FAWRadioGroup
          className="close-task-auto-complete-radio-group"
          value={formData.IsAutoComplete ? 'true' : 'false'}
          onChange={(event) => {
            const value = event.target.value;
            onFieldChange('IsAutoComplete', value === 'true');
          }}
          disabled={readOnly}
          options={[
            { value: 'false', label: 'Workflow will be completed manually' },
            { value: 'true', label: 'Workflow will be completed automatically by the system' }
          ]}
          row={false}
          spacing={1}
        />
      </Box>

      {/* User Defined Fields - Show for all task types EXCEPT Action, Notification, ConditionalSnippet, Section */}
      {formData.Type !== 'Action' && 
       formData.Type !== 'Notification' && 
       formData.Type !== 'ConditionalSnippet' && 
       formData.Type !== 'Section' && (
        <Box className="close-task-udf-section" sx={{ mb: 3 }}>
          <UDFManagement
            formData={formData}
            onFieldChange={onFieldChange}
            readOnly={readOnly}
          />
        </Box>
      )}

      {/* Third Party Fields - Show for all task types EXCEPT Action, Notification, ConditionalSnippet, Section */}
      {formData.Type !== 'Action' && 
       formData.Type !== 'Notification' && 
       formData.Type !== 'ConditionalSnippet' && 
       formData.Type !== 'Section' && (
        <Box className="close-task-third-party-section" sx={{ mb: 3 }}>
          <ThirdPartyFieldsManagement
            formData={formData}
            onFieldChange={onFieldChange}
            readOnly={readOnly}
          />
        </Box>
      )}

      {/* Related Fields - Only show for snippet tasks or FormSubmission workflows, but NOT for Action, Notification, ConditionalSnippet, Section */}
      {formData.Type !== 'Notification' && 
       formData.Type !== 'Action' &&
       formData.Type !== 'ConditionalSnippet' &&
       formData.Type !== 'Section' &&
       (formData.IsSnippetTask === true || formData.WorkflowDefinitionTypeCode === 'FormSubmission') && (
        <Box className="close-task-related-fields-section" sx={{ mb: 3 }}>
          <FAWTypography className="close-task-related-fields-title" variant="h6" sx={{ mb: 2, fontSize: '1.1rem', fontWeight: 'bold' }}>
            Form Answers
            {formData.RelatedFields && formData.RelatedFields.length > 0 && (
              <Chip 
                className="close-task-related-fields-count-chip"
                label={formData.RelatedFields.length} 
                size="small" 
                sx={{ ml: 1 }} 
              />
            )}
          </FAWTypography>
          <RelatedFieldsManagement
            formData={formData}
            onFieldChange={onFieldChange}
            readOnly={readOnly}
          />
        </Box>
      )}
      
    </Box>
  );
};

export default CloseTask;
