import React, { Children, cloneElement, useRef } from 'react';
import PropTypes from 'prop-types';
import classnames from './utils/classnames';
import './tree-node.css';
import { useDrop } from 'react-dnd';

function TreeNode(props) {
  const {
    children,
    listIndex,
    swapFrom = null,
    swapLength = null,
    swapDepth = null,
    scaffoldBlockPxWidth,
    lowerSiblingCounts,
    isOver,
    draggedNode = null,
    canDrop = false,
    treeIndex,
    treeId,
    getPrevRow,
    node,
    path,
    rowDirection = 'ltr',
    onDrop = undefined,
    currentNodeId,
    ...otherProps
  } = props;

  const rowDirectionClass = rowDirection === 'rtl' ? 'rst__rtl' : null;

  // Construct the scaffold representing the structure of the tree
  const scaffoldBlockCount = lowerSiblingCounts.length;
  const scaffold = [];
  lowerSiblingCounts.forEach((lowerSiblingCount, i) => {
    let lineClass = '';
    if (lowerSiblingCount > 0) {
      if (listIndex === 0) {
        lineClass = 'rst__lineHalfHorizontalRight rst__lineHalfVerticalBottom';
      } else if (i === scaffoldBlockCount - 1) {
        lineClass = 'rst__lineHalfHorizontalRight rst__lineFullVertical';
      } else {
        lineClass = 'rst__lineFullVertical';
      }
    } else if (listIndex === 0) {
      lineClass = 'rst__lineHalfHorizontalRight';
    } else if (i === scaffoldBlockCount - 1) {
      lineClass = 'rst__lineHalfVerticalTop rst__lineHalfHorizontalRight';
    }

    scaffold.push(
      <div
        key={`pre_${1 + i}`}
        style={{ width: scaffoldBlockPxWidth }}
        className={classnames('rst__lineBlock', lineClass, rowDirectionClass)}
      />
    );

    if (treeIndex !== listIndex && i === swapDepth) {
      let highlightLineClass = '';
      if (listIndex === swapFrom + swapLength - 1) {
        highlightLineClass = 'rst__highlightBottomLeftCorner';
      } else if (treeIndex === swapFrom) {
        highlightLineClass = 'rst__highlightTopLeftCorner';
      } else {
        highlightLineClass = 'rst__highlightLineVertical';
      }
      let style;
      if (rowDirection === 'rtl') {
        style = {
          width: scaffoldBlockPxWidth,
          right: scaffoldBlockPxWidth * i,
        };
      } else {
        style = {
          width: scaffoldBlockPxWidth,
          left: scaffoldBlockPxWidth * i,
        };
      }
      scaffold.push(
        <div
          key={i}
          style={style}
          className={classnames(
            'rst__absoluteLineBlock',
            highlightLineClass,
            rowDirectionClass
          )}
        />
      );
    }
  });

  let style;
  if (rowDirection === 'rtl') {
    style = { right: scaffoldBlockPxWidth * scaffoldBlockCount };
  } else {
    style = { left: scaffoldBlockPxWidth * scaffoldBlockCount };
  }

  // DnD drop logic
  const ref = useRef(null);
  const [, drop] = useDrop({
    accept: 'TREE_NODE', // You may want to make this dynamic
    drop: (item, monitor) => {
      if (onDrop) {
        onDrop(item, monitor, props);
      }
    },
    collect: (monitor) => ({
      isOver: monitor.isOver(),
      canDrop: monitor.canDrop(),
    }),
  });
  drop(ref);

  return (
    <div
      ref={ref}
      {...otherProps}
      className={classnames(
        'rst__node', 
        rowDirectionClass,
        node.id === currentNodeId && 'current_selected_node'
      )}
    >
      {scaffold}
      <div className="rst__nodeContent atlas_nodeContent" style={style}>
        {Children.map(children, child =>
          cloneElement(child, {
            isOver,
            canDrop,
            draggedNode,
          })
        )}
      </div>
    </div>
  );
}

TreeNode.propTypes = {
  treeIndex: PropTypes.number.isRequired,
  treeId: PropTypes.string.isRequired,
  swapFrom: PropTypes.number,
  swapDepth: PropTypes.number,
  swapLength: PropTypes.number,
  scaffoldBlockPxWidth: PropTypes.number.isRequired,
  lowerSiblingCounts: PropTypes.arrayOf(PropTypes.number).isRequired,
  listIndex: PropTypes.number.isRequired,
  children: PropTypes.node.isRequired,
  isOver: PropTypes.bool,
  canDrop: PropTypes.bool,
  draggedNode: PropTypes.shape({}),
  getPrevRow: PropTypes.func.isRequired,
  node: PropTypes.shape({}).isRequired,
  path: PropTypes.arrayOf(
    PropTypes.oneOfType([PropTypes.string, PropTypes.number])
  ).isRequired,
  rowDirection: PropTypes.string,
  onDrop: PropTypes.func,
};

export default TreeNode;
