import React from 'react';
import {
  Box,
  Grid
} from '@mui/material';
import FAWInput from '../../../../FAWInput';
import FAWDropdown from '../../../../FAWDropdown';
import FAWTypography from '../../../../FAWTypography';

/**
 * Action Task Component
 * Action tasks have ActionType dropdown, SendForm sub-fields (Form, Recipient, Email, Language), UpdateApprovalStatus, AssignInternalOwner
 * Matches legacy behavior for Action task type
 */
const ActionTask = ({ 
  formData, 
  onFieldChange, 
  readOnly = false,
  fieldErrors = {},
  isCloseTask = false
}) => {
  return (
    <Box className="action-task-container">
      
      {/* Action Type Selection */}
      {formData.Actions && formData.Actions.length > 0 && (
        <Box className="action-task-action-type-section" sx={{ mb: 3 }}>
          <Grid container spacing={2}>
            <Grid item xs={12} md={6}>
              <FAWDropdown
                className="action-task-action-type-dropdown"
                label="Action Type"
                value={formData.ActionType || ''}
                onChange={(selectedOption) => onFieldChange('ActionType', selectedOption?.value || '')}
                disabled={readOnly}
                options={formData.Actions.map((action) => ({
                  value: action.Value || action.value,
                  label: action.Text || action.text
                }))}
                fullWidth
              />
            </Grid>
          </Grid>
        </Box>
      )}

      {/* Update Approval Status */}
      {(formData.ActionType === 'UpdateApprovStatus' || formData.ActionType === 'UpdateApprovalStatus') && formData.ThirdPartyApprovalStatuses && (
        <Box className="action-task-approval-status-section" sx={{ mb: 3 }}>
          <Grid container spacing={2}>
            <Grid item xs={12} md={6}>
              <FAWDropdown
                className="action-task-approval-status-dropdown"
                label="Approval Status"
                value={formData.ThirdPartyApprovalStatus || ''}
                onChange={(selectedOption) => onFieldChange('ThirdPartyApprovalStatus', selectedOption?.value || '')}
                disabled={readOnly}
                options={formData.ThirdPartyApprovalStatuses.map((status) => ({
                  value: status.Value || status.value,
                  label: status.Text || status.text
                }))}
                fullWidth
              />
            </Grid>
          </Grid>
        </Box>
      )}

      {/* Assign Internal Owner */}
      {formData.ActionType === 'AssignInternalOwner' && formData.WorkQueues && (
        <Box className="action-task-internal-owner-section" sx={{ mb: 3 }}>
          <Grid container spacing={2}>
            <Grid item xs={12} md={6}>
              <FAWDropdown
                className="action-task-internal-owner-dropdown"
                label="Internal Owner Queue"
                value={formData.InternalOwnerQueueId || ''}
                onChange={(selectedOption) => onFieldChange('InternalOwnerQueueId', selectedOption?.value || '')}
                disabled={readOnly}
                options={formData.WorkQueues.map((queue) => ({
                  value: queue.Value || queue.value,
                  label: queue.Text || queue.text
                }))}
                fullWidth
              />
            </Grid>
          </Grid>
        </Box>
      )}

      {/* Send Form */}
      {formData.ActionType === 'SendForm' && formData.SecurimateFormSubmissionSelection && (
        <Box className="action-task-send-form-section" sx={{ mb: 3 }}>
          <Grid container spacing={2}>
            <Grid item xs={12} md={6}>
              <FAWDropdown
                className="action-task-form-to-send-dropdown"
                label="Form to Send"
                value={formData.FormToSendId || ''}
                onChange={(selectedOption) => onFieldChange('FormToSendId', selectedOption?.value || '')}
                disabled={readOnly}
                options={formData.SecurimateFormSubmissionSelection.map((form) => ({
                  value: form.Value || form.value,
                  label: form.Text || form.text
                }))}
                fullWidth
              />
            </Grid>
            <Grid item xs={12} md={6}>
              <FAWDropdown
                className="action-task-recipient-dropdown"
                label="Recipient"
                value={formData.FormToSendRecipientCode || ''}
                onChange={(selectedOption) => onFieldChange('FormToSendRecipientCode', selectedOption?.value || '')}
                disabled={readOnly}
                options={formData.RecipientSelection.map((recipient) => ({
                  value: recipient.Value || recipient.value,
                  label: recipient.Text || recipient.text
                }))}
                fullWidth
              />
            </Grid>
            {formData.FormToSendRecipientCode === 'AddEmailAddress' && (
              <Grid item xs={12} md={6}>
                <FAWInput
                  className="action-task-email-input"
                  label="Email Address"
                  value={formData.FormToSendEmail || ''}
                  onChange={(e) => onFieldChange('FormToSendEmail', e.target.value)}
                  disabled={readOnly}
                  fullWidth
                />
              </Grid>
            )}
            <Grid item xs={12} md={6}>
              <FAWDropdown
                className="action-task-form-language-dropdown"
                label="Form Language"
                value={formData.FormToSendLanguageCode || ''}
                onChange={(selectedOption) => onFieldChange('FormToSendLanguageCode', selectedOption?.value || '')}
                disabled={readOnly}
                options={formData.FormLanguageSelection.map((language) => ({
                  value: language.Value || language.value,
                  label: language.Text || language.text
                }))}
                fullWidth
              />
            </Grid>
          </Grid>
        </Box>
      )}
    </Box>
  );
};

export default ActionTask;
