import React, { useState, useEffect } from 'react';
import { Box } from '@mui/material';
import FieldManagementSection from '../../../../shared/FieldManagementSection';

/**
 * User Defined Fields Management Component
 * Uses the reusable FieldManagementSection component
 */
const UDFManagement = ({ 
  formData, 
  onFieldChange, 
  readOnly = false 
}) => {
  const [selectedFields, setSelectedFields] = useState([]);
  const [selectedCategory, setSelectedCategory] = useState('all');
  

  // Update selected fields when formData changes
  useEffect(() => {
    if (formData && formData.UserDefinedFields) {
      const fieldNames = formData.UserDefinedFields.map(field => field.Name || field.FieldName);
      setSelectedFields(fieldNames);
    }
  }, [formData]);

  // Handle field selection
  const handleFieldSelect = (fieldName) => {
    
    if (readOnly) return;
    
    const newSelectedFields = selectedFields.includes(fieldName)
      ? selectedFields.filter(name => name !== fieldName)
      : [...selectedFields, fieldName];
    
    
    setSelectedFields(newSelectedFields);
    
    // Convert back to the format expected by parent component
    if (onFieldChange) {
      const selectedFieldObjects = newSelectedFields.map(name => 
        formData.UserDefinedFieldsAll?.find(field => (field.Name || field.FieldName) === name)
      ).filter(Boolean);
      
      onFieldChange('UserDefinedFields', selectedFieldObjects);
    }
  };

  // Handle category change
  const handleCategoryChange = (category) => {
    setSelectedCategory(category);
  };

  // Category options for the dropdown - use actual Categories from formData
  const categoryOptions = React.useMemo(() => {
    if (!formData.Categories || !Array.isArray(formData.Categories)) {
      return [{ value: 'all', label: 'All Categories' }];
    }
    
    // Add "All Categories" option first, then add actual categories from formData
    const mappedCategories = formData.Categories.map(category => {
      // Handle the specific structure: { Text: "...", Value: "...", Disabled: false, Selected: false, Group: null }
      const value = category.Value || '';
      const label = category.Text || '';
      
      return {
        value: String(value),
        label: String(label)
      };
    }).filter(option => option.value && option.label); // Filter out invalid options
    
    return [
      { value: 'all', label: 'All Categories' },
      ...mappedCategories
    ];
  }, [formData.Categories]);

  // Filter fields based on category
  // Use UserDefinedFieldsAll as the pool, but if empty, merge in UserDefinedFields 
  // to at least show the already-selected fields
  const allAvailableFields = React.useMemo(() => {
    const allFields = formData.UserDefinedFieldsAll || [];
    const selectedFieldsData = formData.UserDefinedFields || [];
    
    // If UserDefinedFieldsAll is empty but we have selected fields, 
    // use the selected fields as the pool (so "Included" tab shows them)
    if (allFields.length === 0 && selectedFieldsData.length > 0) {
      return selectedFieldsData;
    }
    
    // Merge: include any selected fields not already in allFields
    const allFieldNames = new Set(allFields.map(f => f.Name || f.FieldName));
    const missingSelectedFields = selectedFieldsData.filter(f => {
      const name = f.Name || f.FieldName;
      return !allFieldNames.has(name);
    });
    
    return [...allFields, ...missingSelectedFields];
  }, [formData.UserDefinedFieldsAll, formData.UserDefinedFields]);
  
  const filteredFields = React.useMemo(() => {
    if (!allAvailableFields || allAvailableFields.length === 0) return [];
    
    if (selectedCategory === 'all') {
      return allAvailableFields;
    }
    
    // Filter by actual category value from formData.Categories (matches legacy behavior)
    const filtered = allAvailableFields.filter(field => {
      // Legacy uses field.Category for comparison (not CategoryText)
      const fieldCategory = field.Category || '';
      return fieldCategory === selectedCategory;
    });
    
    return filtered;
  }, [allAvailableFields, selectedCategory]);

  return (
    <>
      {/* Divider above User Defined Fields */}
      <Box 
        className="udf-divider" 
        sx={{ 
          height: '1px', 
          backgroundColor: '#e0e0e0', 
          margin: '16px 0',
          width: '100%'
        }} 
      />
      
      <FieldManagementSection
        title="Available Fields"
        fields={filteredFields}
        selectedFields={selectedFields}
        onFieldSelect={handleFieldSelect}
        categoryOptions={categoryOptions}
        selectedCategory={selectedCategory}
        onCategoryChange={handleCategoryChange}
        searchPlaceholder="Type in field name"
        readOnly={readOnly}
      />
    </>
  );
};

export default UDFManagement;