import React from 'react';
import { Box, Chip } from '@mui/material';
import FAWTypography from '../../../../FAWTypography';
import { 
  UDFManagement, 
  ThirdPartyFieldsManagement, 
  RelatedFieldsManagement 
} from '../fieldManagement';

/**
 * Review Task Component
 * Review tasks use UDF, ThirdParty, Related fields
 * Matches legacy behavior for Review task type
 */
const ReviewTask = ({ 
  formData, 
  onFieldChange, 
  readOnly = false,
  fieldErrors = {},
  isCloseTask = false
}) => {
  return (
    <Box className="review-task-container">
      
      {/* User Defined Fields - Show for all task types EXCEPT Action, Notification, ConditionalSnippet, Section */}
      {formData.Type !== 'Action' && 
       formData.Type !== 'Notification' && 
       formData.Type !== 'ConditionalSnippet' && 
       formData.Type !== 'Section' && (
        <Box className="review-task-udf-section" sx={{ mb: 3 }}>
          <UDFManagement
            formData={formData}
            onFieldChange={onFieldChange}
            readOnly={readOnly}
          />
        </Box>
      )}

      {/* Third Party Fields - Show for all task types EXCEPT Action, Notification, ConditionalSnippet, Section */}
      {formData.Type !== 'Action' && 
       formData.Type !== 'Notification' && 
       formData.Type !== 'ConditionalSnippet' && 
       formData.Type !== 'Section' && (
        <Box className="review-task-third-party-section" sx={{ mb: 3 }}>
          <ThirdPartyFieldsManagement
            formData={formData}
            onFieldChange={onFieldChange}
            readOnly={readOnly}
          />
        </Box>
      )}

      {/* Related Fields - Only show for snippet tasks or FormSubmission workflows, but NOT for Action, Notification, ConditionalSnippet, Section */}
      {formData.Type !== 'Notification' && 
       formData.Type !== 'Action' &&
       formData.Type !== 'ConditionalSnippet' &&
       formData.Type !== 'Section' &&
       (formData.IsSnippetTask === true || formData.WorkflowDefinitionTypeCode === 'FS' || formData.WorkflowDefinitionTypeCode === 'FormSubmission') && (
        <Box className="review-task-related-fields-section" sx={{ mb: 3 }}>
          <RelatedFieldsManagement
            formData={formData}
            onFieldChange={onFieldChange}
            readOnly={readOnly}
          />
        </Box>
      )}
      
    </Box>
  );
};

export default ReviewTask;

