import React, { useState, useEffect, useMemo, useRef, useCallback } from 'react';
import { Box } from '@mui/material';
import FieldManagementSection from '../../../../shared/FieldManagementSection';

/**
 * Related Fields Management Component
 * 
 * LEGACY BEHAVIOR:
 * - Forms dropdown to select which form to load fields from
 * - Loads ONE form's fields at a time via API
 * - Available tab shows fields from selected form
 * - Included tab shows saved RelatedFields
 */
const RelatedFieldsManagement = ({ 
  formData, 
  onFieldChange, 
  readOnly = false 
}) => {
  const [selectedFields, setSelectedFields] = useState([]);
  const [selectedFormId, setSelectedFormId] = useState('');
  const [apiFields, setApiFields] = useState([]);
  const [loading, setLoading] = useState(false);
  const [fieldsCache, setFieldsCache] = useState({});
  const fieldsCacheRef = useRef({});
  const previousRelatedFieldsRef = useRef();
  
  // Keep ref in sync with state
  useEffect(() => {
    fieldsCacheRef.current = fieldsCache;
  }, [fieldsCache]);

  // Values must be strings to match DOM select behavior
  const formOptions = useMemo(() => {
    if (!formData?.FormNames?.length) return [];
    return formData.FormNames.map(form => ({
      value: String(form.Value || form.value || ''),
      label: form.Text || form.text
    }));
  }, [formData?.FormNames]);

  useEffect(() => {
    if (formData?.RelatedFields) {
      const fieldNames = formData.RelatedFields.map(f => f.FieldName || f.Name);
      setSelectedFields(fieldNames);
    }
  }, [formData?.RelatedFields]);

  useEffect(() => {
    if (!formData?.FormNames?.length) return;

    let formIdToLoad = String(formData.FormNames[0].Value || formData.FormNames[0].value || '');
    
    // If saved RelatedFields exist, prefer their form
    if (formData.RelatedFields?.length > 0) {
      const savedFormName = formData.RelatedFields[0].FormName || formData.RelatedFields[0].formName;
      if (savedFormName) {
        const matchingForm = formData.FormNames.find(f => (f.Text || f.text) === savedFormName);
        if (matchingForm) {
          formIdToLoad = String(matchingForm.Value || matchingForm.value || '');
        }
      }
    }

    if (formIdToLoad) {
      setSelectedFormId(formIdToLoad);
      loadFieldsForForm(formIdToLoad);
    }
  }, [formData?.Id]);

  // Separate effect to clear cache and reload when RelatedFields change after save
  // This ensures we get all available fields, not just the selected ones
  useEffect(() => {
    if (!selectedFormId || !formData?.RelatedFields) return;
    
    // Compare current RelatedFields with previous to detect actual changes
    const currentRelatedFields = JSON.stringify(formData.RelatedFields);
    const previousRelatedFields = previousRelatedFieldsRef.current;
    
    // Only reload if RelatedFields actually changed (not on initial mount)
    if (previousRelatedFields !== undefined && currentRelatedFields !== previousRelatedFields) {
      // Clear cache for the current form to ensure fresh data after save
      setFieldsCache(prev => {
        const newCache = { ...prev };
        delete newCache[selectedFormId];
        return newCache;
      });
      // Reload fields to get all available fields, not just selected ones
      loadFieldsForForm(selectedFormId);
    }
    
    // Update ref for next comparison
    previousRelatedFieldsRef.current = currentRelatedFields;
  }, [formData?.RelatedFields, selectedFormId, loadFieldsForForm]);

  const loadFieldsForForm = useCallback(async (formId) => {
    if (!formId || !formData) return;

    // Check cache using ref to get latest value synchronously
    if (fieldsCacheRef.current[formId]) {
      setApiFields(fieldsCacheRef.current[formId]);
      return;
    }

    // Cache miss - load from API
    setLoading(true);
    try {
      const isSnippet = formData.IsSnippetTask === true;
      const apiService = isSnippet 
        ? await import('../../../snippet/services/snippetApi')
        : await import('../../../workflowdefinition/services/workflowDefinitionApi');
      
      const api = isSnippet ? apiService.snippetApi : apiService.workflowDefinitionApi;
      
      const workflowTaskDefId = formData.Id || formData.id;
      const containerId = formData.ContainerId || formData.containerId;
      const definitionType = isSnippet ? 'Snippet' : 'WorkflowDefinition';

      const result = isSnippet 
        ? await api.getAnswersForForm(formId, workflowTaskDefId, containerId, definitionType)
        : await api.getAnswersForForm(formId, workflowTaskDefId, containerId, definitionType);

      if (result?.success && result.results) {
        const fields = result.results.map(field => ({
          FieldName: field.FieldName || field.fieldName || field.Name || field.name,
          FieldDescription: field.FieldDescription || field.fieldDescription || field.Description || field.description,
          FormName: field.FormName || field.formName,
          FieldType: field.FieldType || field.fieldType,
          RefDomain: field.RefDomain || field.refDomain,
          ...field
        }));

        const uniqueFields = fields.reduce((acc, field) => {
          const name = field.FieldName || field.Name || '';
          if (!acc.some(f => (f.FieldName || f.Name) === name)) {
            acc.push(field);
          }
          return acc;
        }, []);

        setFieldsCache(prev => ({ ...prev, [formId]: uniqueFields }));
        setApiFields(uniqueFields);
      } else {
        setApiFields([]);
      }
    } catch (error) {
      console.error('Error loading fields for form:', error);
      setApiFields([]);
    } finally {
      setLoading(false);
    }
  }, [formData]);

  const availableFields = useMemo(() => {
    const savedFields = formData?.RelatedFields || [];
    if (!apiFields.length && !savedFields.length) return [];

    const merged = [...apiFields];
    
    savedFields.forEach(saved => {
      const name = saved.FieldName || saved.Name;
      if (!merged.some(f => (f.FieldName || f.Name) === name)) {
        merged.push(saved);
      }
    });

    return merged;
  }, [apiFields, formData?.RelatedFields]);

  const handleFormChange = (formId) => {
    setSelectedFormId(formId);
    loadFieldsForForm(formId);
  };

  const handleFieldSelect = (fieldName) => {
    if (readOnly) return;

    const isSelected = selectedFields.includes(fieldName);
    const newSelectedFields = isSelected
      ? selectedFields.filter(name => name !== fieldName)
      : [...selectedFields, fieldName];

    setSelectedFields(newSelectedFields);

    if (onFieldChange) {
      const newFieldObjects = newSelectedFields
        .map(name => availableFields.find(f => (f.FieldName || f.Name) === name))
        .filter(Boolean);
      
      onFieldChange('RelatedFields', newFieldObjects);
    }
  };

  return (
    <Box>
      <Box sx={{ height: '1px', backgroundColor: '#e0e0e0', margin: '16px 0', width: '100%' }} />
      <FieldManagementSection
        title="Available Form Answers"
        fields={availableFields}
        selectedFields={selectedFields}
        onFieldSelect={handleFieldSelect}
        categoryOptions={formOptions}
        selectedCategory={selectedFormId}
        onCategoryChange={handleFormChange}
        categoryLabel="Forms"
        searchPlaceholder="Type in field name"
        readOnly={readOnly}
        loading={loading}
      />
    </Box>
  );
};

export default RelatedFieldsManagement;
