import React from 'react';
import { Box, Chip } from '@mui/material';
import FAWTypography from '../../../../FAWTypography';
import { 
  UDFManagement, 
  ThirdPartyFieldsManagement, 
  RelatedFieldsManagement 
} from '../fieldManagement';

/**
 * Route To Task Component
 * Route To tasks use UDF, ThirdParty, and Related fields
 * Matches legacy behavior for RouteTo task type
 */
const RouteToTask = ({ 
  formData, 
  onFieldChange, 
  readOnly = false,
  fieldErrors = {},
  isCloseTask = false
}) => {
  return (
    <Box className="route-to-task-container">
      <FAWTypography 
        className="route-to-task-title" 
        variant="h6" 
        sx={{ mb: 2, fontWeight: 'bold' }}
      >
        Route To Task Configuration
      </FAWTypography>
      {/* User Defined Fields - Match Legacy UI */}
      <Box className="route-to-task-udf-section" sx={{ mb: 3 }}>
        <FAWTypography className="route-to-task-udf-title" variant="h6" sx={{ mb: 2, fontSize: '1.1rem', fontWeight: 'bold' }}>
          Included Fields / Available Fields
          {formData.UserDefinedFields && formData.UserDefinedFields.length > 0 && (
            <Chip 
              className="route-to-task-udf-count-chip"
              label={formData.UserDefinedFields.length} 
              size="small" 
              sx={{ ml: 1 }} 
            />
          )}
        </FAWTypography>
        <UDFManagement
          formData={formData}
          onFieldChange={onFieldChange}
          readOnly={readOnly}
        />
      </Box>

      {/* Third Party Fields - Show for all task types EXCEPT Action, Notification, ConditionalSnippet, Section */}
      {formData.Type !== 'Action' && 
       formData.Type !== 'Notification' && 
       formData.Type !== 'ConditionalSnippet' && 
       formData.Type !== 'Section' && (
        <Box className="route-to-task-third-party-section">
          <ThirdPartyFieldsManagement
            formData={formData}
            onFieldChange={onFieldChange}
            readOnly={readOnly}
          />
        </Box>
      )}

      {/* Related Fields - Only show for snippet tasks or FormSubmission workflows, but NOT for Action, Notification, ConditionalSnippet, Section */}
      {formData.Type !== 'Notification' && 
       formData.Type !== 'Action' &&
       formData.Type !== 'ConditionalSnippet' &&
       formData.Type !== 'Section' &&
       (formData.IsSnippetTask === true || formData.WorkflowDefinitionTypeCode === 'FormSubmission') && (
        <Box className="route-to-task-related-fields-section" sx={{ mb: 3 }}>
          <FAWTypography className="route-to-task-related-fields-title" variant="h6" sx={{ mb: 2, fontSize: '1.1rem', fontWeight: 'bold' }}>
            Form Answers
            {formData.RelatedFields && formData.RelatedFields.length > 0 && (
              <Chip 
                className="route-to-task-related-fields-count-chip"
                label={formData.RelatedFields.length} 
                size="small" 
                sx={{ ml: 1 }} 
              />
            )}
          </FAWTypography>
          <RelatedFieldsManagement
            formData={formData}
            onFieldChange={onFieldChange}
            readOnly={readOnly}
          />
        </Box>
      )}
    </Box>
  );
};

export default RouteToTask;

