import React, { useState, useEffect } from 'react';
import { Box, Grid, Paper, FormControl, Select, MenuItem, FormHelperText, Chip, OutlinedInput } from '@mui/material';
import FAWInput from '../../../../FAWInput';
import FAWDropdown from '../../../../FAWDropdown';
import FAWTypography from '../../../../FAWTypography';
import FAWButton from '../../../../FAWButton';
import ExternalLinkIcon from "@diligentcorp/atlas-react-icons/dist/esm/lens/ExternalLink.js";

/**
 * Notification Task Component
 * Notification tasks have Recipients (Queue, ThirdParty, Email), NotificationType, Language, Preview (Subject/Body), Edit Notification link
 * Matches legacy behavior for Notification task type
 */
const NotificationTask = ({ 
  formData, 
  onFieldChange, 
  readOnly = false,
  fieldErrors = {},
  isCloseTask = false
}) => {
  const [subjectTemplate, setSubjectTemplate] = useState('');
  const [messageTemplate, setMessageTemplate] = useState('');
  const [editNotificationLink, setEditNotificationLink] = useState('');

  // Handle notification template changes
  const handleNotificationTemplateChange = async () => {
    const notificationLanguage = formData.NotificationLanguageCode;
    const notificationId = formData.NotificationDefinitionId;

    if (notificationId && notificationLanguage) {
      // Set edit notification link
      setEditNotificationLink(`/notification/editNotification?notificationDefinitionId=${notificationId}&selectedLanguage=${notificationLanguage}`);
      
      try {
        // Call API to get notification template
        const response = await fetch(`/WorkflowTaskDefSnippet/GetNotificationDetails?notficiationDefId=${notificationId}&languageCode=${notificationLanguage}`);
        
        if (response.ok) {
          const data = await response.json();
          setSubjectTemplate(data?.SubjectTemplate || 'none available');
          setMessageTemplate(data?.MessageTemplate || 'none available');
        } else {
          setSubjectTemplate('Error loading template');
          setMessageTemplate('Error loading template');
        }
      } catch (error) {
        console.error('Error fetching notification details:', error);
        setSubjectTemplate('Error loading template');
        setMessageTemplate('Error loading template');
      }
    } else {
      setEditNotificationLink('');
      setSubjectTemplate('none available');
      setMessageTemplate('none available');
    }
  };

  useEffect(() => {
    handleNotificationTemplateChange();
  }, [formData.NotificationDefinitionId, formData.NotificationLanguageCode]);

  return (
    <Box className="notification-task-container" sx={{ display: 'flex', flexDirection: 'column', gap: 3 }}>
      
      {/* Recipients Section - Gray Background Container */}
      <Paper 
        className="notification-task-recipients-section" 
        sx={{ 
          background: 'var(--Color-Gray-100, #F3F3F3)',
          borderRadius: 1,
          p: 3,
          border: 'none',
          boxShadow: 'none !important'
        }}
      >
        <Box className="notification-task-recipients-header" sx={{ mb: 3 }}>
          <FAWTypography 
            className="notification-task-recipients-title" 
            variant="h6" 
            sx={{ 
              fontWeight: 600,
              fontSize: '18px',
              lineHeight: '28px',
              color: '#282e37',
              letterSpacing: '0.2px'
            }}
          >
            Recipients
          </FAWTypography>
        </Box>
        
        <Box className="notification-task-recipients-fields" sx={{ display: 'flex', flexDirection: 'column', gap: 2 }}>
          <FAWDropdown
            className="notification-task-work-queue-dropdown"
            label="Send to users of this queue"
            placeholder="Choose an option"
            value={formData.NotificationWorkQueueId || ''}
            onChange={(selectedOption) => onFieldChange('NotificationWorkQueueId', selectedOption?.value || '')}
            disabled={readOnly}
            options={formData.NotificationWorkQueueSelection?.map((queue) => ({
              value: queue.Value || queue.value,
              label: queue.Text || queue.text
            })) || []}
            fullWidth
            sx={{
              '& .MuiOutlinedInput-root': {
                backgroundColor: '#FFFFFF !important',
              }
            }}
          />  
          
          <FormControl fullWidth>
            <FAWTypography 
              variant="body2" 
              component="label" 
              sx={{ 
                display: "block", 
                marginBottom: "4px",
                fontWeight: "500",
                fontSize: "14px"
              }}
            >
              Send to email from third-party field
            </FAWTypography>
            <Select
              className="notification-task-third-party-dropdown"
              multiple
              value={formData.ThirdPartyNotificationFieldCodes || []}
              onChange={(e) => onFieldChange('ThirdPartyNotificationFieldCodes', e.target.value)}
              disabled={readOnly}
              input={<OutlinedInput />}
              renderValue={(selected) => (
                <Box sx={{ display: 'flex', flexWrap: 'wrap', gap: 0.5 }}>
                  {selected.map((value) => {
                    const option = formData.ThirdPartyNotificationSelection?.find(field => 
                      (field.Value || field.value) === value
                    );
                    return (
                      <Chip 
                        key={value} 
                        label={option ? (option.Text || option.text) : value}
                        size="small"
                      />
                    );
                  })}
                </Box>
              )}
              sx={{
                '& .MuiSelect-select': { 
                  fontSize: '1.1rem', 
                  paddingTop: '12px !important' 
                },
              }}
            >
              {formData.ThirdPartyNotificationSelection?.map((field) => (
                <MenuItem 
                  key={field.Value || field.value} 
                  value={field.Value || field.value}
                  sx={{
                    backgroundColor: '#ffffff !important',
                    fontSize: '14px',
                    padding: '12px 16px',
                    '&:hover': {
                      backgroundColor: '#f5f5f5'
                    },
                    '&.Mui-selected': {
                      backgroundColor: '#e3f2fd',
                      color: '#1976d2',
                      '&:hover': {
                        backgroundColor: '#e3f2fd'
                      }
                    }
                  }}
                >
                  {field.Text || field.text}
                </MenuItem>
              )) || []}
            </Select>
          </FormControl>
          
          <FAWInput
            className="notification-task-distribution-list"
            label="Send to these email addresses"
            placeholder="Placeholder"
            value={formData.NotificationDistributionList || ''}
            onChange={(e) => onFieldChange('NotificationDistributionList', e.target.value)}
            disabled={readOnly}
            multiline
            rows={3}
            fullWidth
            sx={{
              backgroundColor: '#FFFFFF !important',
            }}
          />
        </Box>

        {/* Notification Type and Language - Side by Side */}
        <Box className="notification-task-type-section" sx={{ display: 'flex', gap: 2, mt: 2 }}>
          <Box sx={{ flex: 1 }}>
            <FAWDropdown
              className="notification-task-type-dropdown"
              label="Notification type"
              placeholder="Choose an option"
              value={formData.NotificationDefinitionId || ''}
              onChange={(selectedOption) => {
                onFieldChange('NotificationDefinitionId', selectedOption?.value || '');
                handleNotificationTemplateChange();
              }}
              disabled={readOnly}
              options={formData.NotificationTypeSelection?.map((type) => ({
                value: type.Value || type.value,
                label: type.Text || type.text
              })) || []}
              fullWidth
              sx={{
                '& .MuiOutlinedInput-root': {
                  backgroundColor: '#FFFFFF !important'
                }
              }}
            />
          </Box>
          
          <Box sx={{ flex: 1 }}>
            <FAWDropdown
              className="notification-task-language-dropdown"
              label="Language"
              placeholder="Choose an option"
              value={formData.NotificationLanguageCode || ''}
              onChange={(selectedOption) => {
                onFieldChange('NotificationLanguageCode', selectedOption?.value || '');
                handleNotificationTemplateChange();
              }}
              disabled={readOnly}
              options={formData.NotificationLanguageSelection?.map((lang) => ({
                value: lang.Value || lang.value,
                label: lang.Text || lang.text
              })) || []}
              fullWidth
              sx={{
                '& .MuiOutlinedInput-root': {
                  backgroundColor: '#FFFFFF !important'
                }
              }}
            />
          </Box>
        </Box>
      </Paper>

      {/* Notification Preview - Gray Background Container */}
      <Paper 
        className="notification-task-preview-section" 
        sx={{ 
          background: 'var(--Color-Gray-100, #F3F3F3)',
          borderRadius: 1,
          p: 3,
          border: 'none',
          boxShadow: 'none !important'
        }}
      >
        <Box className="notification-task-preview-header" sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 3 }}>
          <FAWTypography 
            className="notification-task-preview-title" 
            variant="h6" 
            sx={{ 
              fontWeight: 600,
              fontSize: '18px',
              lineHeight: '28px',
              color: '#282e37',
              letterSpacing: '0.2px'
            }}
          >
            Notification preview
          </FAWTypography>
          
          {editNotificationLink && (
            <FAWButton
              className="notification-task-edit-button"
              variant="text"
              size="medium"
              onClick={() => window.open(editNotificationLink, '_blank')}
              endIcon={<ExternalLinkIcon size="lg" />}
              sx={{ 
                fontSize: '16px',
              }}
            >
              Edit notification
            </FAWButton>
          )}
        </Box>
        
        <Box className="notification-task-preview-content" sx={{ display: 'flex', flexDirection: 'column', gap: 2 }}>
          <Box className="notification-task-subject-preview">
            <FAWTypography 
              className="notification-task-subject-label" 
              variant="body2" 
              sx={{ 
                mb: 1, 
                fontWeight: 600,
                fontSize: '14px',
                lineHeight: '20px',
                color: '#282e37',
                letterSpacing: '0.2px'
              }}
            >
              Subject
            </FAWTypography>
            <FAWTypography
              sx={{ 
                fontSize: '14px',
                lineHeight: '20px',
                color: '#282e37',
                letterSpacing: '0.2px',
                //fontStyle: subjectTemplate === 'none available' || subjectTemplate === 'Error loading template' ? 'italic' : 'normal'
              }}
              dangerouslySetInnerHTML={{ __html: subjectTemplate }}
            />
          </Box>
          
          <Box className="notification-task-body-preview">
            <FAWTypography 
              className="notification-task-body-label" 
              variant="body2" 
              sx={{ 
                mb: 1, 
                fontWeight: 600,
                fontSize: '14px',
                lineHeight: '20px',
                color: '#282e37',
                letterSpacing: '0.2px'
              }}
            >
              Body
            </FAWTypography>
            <FAWTypography
              sx={{ 
                fontSize: '14px',
                lineHeight: '20px',
                color: '#282e37',
                letterSpacing: '0.2px',
              }}
              dangerouslySetInnerHTML={{ __html: messageTemplate }}
            />
          </Box>
        </Box>
      </Paper>
    </Box>
  );
};

export default NotificationTask;
