/**
 * Validation utilities for workflow forms using Yup schemas
 */
import { 
  workflowDefinitionSchema, 
  snippetSchema, 
  taskDetailSchema, 
  validateWithYup, 
  validateField 
} from '../schemas/validationSchemas';

/**
 * Validates workflow definition form data using Yup schema
 * @param {object} formData - Form data to validate
 * @returns {Promise<object>} - Validation result with isValid and fieldErrors
 */
export const validateWorkflowDefinition = async (formData) => {
  return await validateWithYup(workflowDefinitionSchema, formData);
};

/**
 * Validates snippet form data using Yup schema
 * @param {object} formData - Form data to validate
 * @returns {Promise<object>} - Validation result with isValid and fieldErrors
 */
export const validateSnippet = async (formData) => {
  return await validateWithYup(snippetSchema, formData);
};

/**
 * Validates task detail form data using Yup schema
 * @param {object} formData - Form data to validate
 * @param {function} hasRequiredUDFs - Function to check if required UDFs are present
 * @returns {Promise<object>} - Validation result with isValid and fieldErrors
 */
export const validateTaskDetail = async (formData, hasRequiredUDFs) => {
  const result = await validateWithYup(taskDetailSchema, formData);
  
  // Additional custom validation for UDFs (matches legacy behavior)
  if (hasRequiredUDFs && !hasRequiredUDFs()) {
    result.fieldErrors.userDefinedFields = 'Missing required fields'; // Matches legacy message
    result.isValid = false;
  }
  
  return result;
};

/**
 * Validates a single field using appropriate schema
 * @param {string} formType - Type of form ('workflow', 'snippet', 'task')
 * @param {string} fieldName - Name of the field to validate
 * @param {any} value - Value to validate
 * @returns {Promise<object>} - Validation result with isValid and error
 */
export const validateFormField = async (formType, fieldName, value) => {
  let schema;
  switch (formType) {
    case 'workflow':
      schema = workflowDefinitionSchema;
      break;
    case 'snippet':
      schema = snippetSchema;
      break;
    case 'task':
      schema = taskDetailSchema;
      break;
    default:
      throw new Error(`Unknown form type: ${formType}`);
  }
  
  return await validateField(schema, fieldName, value);
};

/**
 * Legacy validateForm function for backward compatibility
 * @param {object} formData - Form data to validate
 * @param {function} hasRequiredUDFs - Function to check if required UDFs are present
 * @returns {object} - Validation result with isValid and fieldErrors
 */
export const validateForm = async (formData, hasRequiredUDFs) => {
  // Try to determine form type based on available fields
  if (formData.WorkflowTypeCode !== undefined) {
    return await validateWorkflowDefinition(formData);
  } else if (formData.CategoryCode !== undefined && !formData.Type) {
    return await validateSnippet(formData);
  } else {
    return await validateTaskDetail(formData, hasRequiredUDFs);
  }
};

/**
 * Validates description field
 * @param {string} description - Description to validate
 * @returns {object} - Validation result with isValid and error
 */
export const validateDescription = (description) => {
  if (!description || description.trim() === '') {
    return {
      isValid: false,
      error: 'Description is required'
    };
  }
  
  if (description.length < 10) {
    return {
      isValid: false,
      error: 'Description must be at least 10 characters long'
    };
  }
  
  return {
    isValid: true,
    error: ''
  };
};

/**
 * Gets error message for a specific field
 * @param {object} fieldErrors - Field errors object
 * @param {string} fieldName - Name of the field
 * @returns {string} - Error message or empty string
 */
export const getFieldError = (fieldErrors, fieldName) => {
  return fieldErrors && fieldErrors[fieldName] ? fieldErrors[fieldName] : '';
};

/**
 * Checks if a field has an error
 * @param {object} fieldErrors - Field errors object
 * @param {string} fieldName - Name of the field
 * @returns {boolean} - True if field has error
 */
export const hasFieldError = (fieldErrors, fieldName) => {
  return fieldErrors && fieldErrors[fieldName] ? true : false;
};

/**
 * Clears error for a specific field
 * @param {object} fieldErrors - Field errors object
 * @param {string} fieldName - Name of the field
 * @returns {object} - Updated field errors object
 */
export const clearFieldError = (fieldErrors, fieldName) => {
  if (!fieldErrors) return {};
  const newErrors = { ...fieldErrors };
  delete newErrors[fieldName];
  return newErrors;
};

export default validateForm;
