import { isEqual, omit, pick } from 'lodash';

/**
 * Smart Form Change Detection Utility
 * 
 * This utility provides intelligent form change detection by comparing only
 * the fields that users can actually edit, ignoring UI-only fields and
 * system-generated fields.
 */

/**
 * Defines which fields are editable by users in different contexts
 * These arrays can be customized based on the specific form type
 */
export const EDITABLE_FIELD_KEYS = {
  // Basic task fields that users can edit
  BASIC_TASK: [
    'Name',
    'Description', 
    'Status',
    'Duration',
    'Type',
    'Order',
    'WorkQueueId',
    'IsRequired',
    'SLADays',
    'IsPhase',
    'IsSnippetTask',
    'ShowCaseStatusDropdown',
    'RequireCommentActions',
    'AllowEditTaskName',
    'SendAlertsTo'
  ],

  // User Defined Fields
  UDF: [
    'UserDefinedFields'
  ],

  // Third Party Fields
  THIRD_PARTY: [
    'ThirdPartyFields'
  ],

  // Related Fields
  RELATED: [
    'RelatedFields'
  ],

  // Notification fields
  NOTIFICATION: [
    'NotificationControls',
    'NotificationWorkQueueId',
    'NotificationDefinitionId',
    'NotificationLanguageCode',
    'ThirdPartyNotificationFieldCodes'
  ],

  // Action task specific fields
  ACTION: [
    'ActionType',
    'ThirdPartyApprovalStatus',
    'InternalOwnerQueueId',
    'FormToSendId',
    'FormToSendRecipientCode',
    'FormToSendLanguageCode'
  ],

  // Review task specific fields
  REVIEW: [
    'ReviewActionType'
  ],

  // Step task specific fields
  STEP: [
    'StepActionType'
  ],

  // Section task specific fields
  SECTION: [
    'IsPhase'
  ]
};

/**
 * Fields that should be ignored during change detection
 * These are typically UI-only fields, system fields, or computed fields
 */
export const IGNORED_FIELD_KEYS = [
  // UI-only fields
  'Statuses',
  'WorkQueues', 
  'Actions',
  'ThirdPartyApprovalStatuses',
  'SecurimateFormSubmissionSelection',
  'RecipientSelection',
  'FormLanguageSelection',
  'NotificationWorkQueueSelection',
  'ThirdPartyNotificationSelection',
  'NotificationTypeSelection',
  'NotificationLanguageSelection',
  'Categories',
  'FormNames',
  'SecurimateFormLanguagesByFormIdJson',
  'FormNamesByIdJson',
  'UserDefinedFieldsAll',
  'ThirdPartyFieldsAll',
  'RelatedFieldsAll',
  
  // System fields
  'Id',
  'WorkflowDefId',
  'ContainerId',
  'ParentWorkflowTaskDefinitionId',
  'ControllerName',
  'InstanceType',
  'LockId',
  'DisplayText',
  'RelatedDataDefs',
  'RelatedDatas',
  'UIAlerts',
  'WorkflowDefinitionId',
  'WorkflowDefinitionType',
  'ConnectionName',
  'AgencyId',
  
  // Computed/temporary fields
  'SettingsXML',
  'AllowTypeList',
  'AllowTypeMultiSelectList',
  'NotificationDistributionList',
  'ConditionalSnippetRulesJson',
  'ConditonalSnippetId'
];

/**
 * Special system flags that affect form behavior but should be ignored in change detection
 * These fields are used for UI logic but don't represent user-editable content
 */
export const SYSTEM_FLAGS = [
  'NewlyCreated',
  'IsNewlyCreated',
  'IsSnippetTask',
  'ShowCaseStatusDropdown',
  'AllowEditTaskName'
];

/**
 * Get editable fields for a specific task type
 * @param {string} taskType - The type of task (e.g., 'ACTION', 'REVIEW', 'STEP', 'SECTION')
 * @param {Array} additionalFields - Additional fields to include
 * @returns {Array} Array of editable field keys
 */
export const getEditableFields = (taskType, additionalFields = []) => {
  const baseFields = EDITABLE_FIELD_KEYS.BASIC_TASK || [];
  const taskSpecificFields = EDITABLE_FIELD_KEYS[taskType] || [];
  
  return [
    ...baseFields,
    ...taskSpecificFields,
    ...additionalFields
  ];
};

/**
 * Get all editable fields for a form (includes all possible editable fields)
 * @param {Array} additionalFields - Additional fields to include
 * @returns {Array} Array of all editable field keys
 */
export const getAllEditableFields = (additionalFields = []) => {
  const allFields = Object.values(EDITABLE_FIELD_KEYS).flat();
  const uniqueFields = [...new Set(allFields)];
  
  return [
    ...uniqueFields,
    ...additionalFields
  ];
};

/**
 * Extract only editable fields from form data using lodash pick
 * @param {Object} formData - The form data object
 * @param {Array} editableFields - Array of editable field keys
 * @returns {Object} Object containing only editable fields
 */
export const extractEditableFields = (formData, editableFields) => {
  if (!formData || !Array.isArray(editableFields)) {
    return {};
  }

  // Use lodash pick for better performance and cleaner code
  return pick(formData, editableFields);
};

/**
 * Check if form has changes using smart detection
 * @param {Object} currentFormData - Current form data
 * @param {Object} originalFormData - Original form data
 * @param {string} taskType - Type of task (optional)
 * @param {Array} additionalEditableFields - Additional fields to consider editable
 * @returns {boolean} True if form has changes
 */
export const hasFormChanges = (
  currentFormData, 
  originalFormData, 
  taskType = null,
  additionalEditableFields = []
) => {
  if (!currentFormData || !originalFormData) {
    return false;
  }

  // Get editable fields based on task type
  const editableFields = taskType 
    ? getEditableFields(taskType, additionalEditableFields)
    : getAllEditableFields(additionalEditableFields);

  // Extract only editable fields from both datasets using lodash pick
  const currentEditable = pick(currentFormData, editableFields);
  const originalEditable = pick(originalFormData, editableFields);

  // Compare using lodash isEqual for deep comparison
  return !isEqual(currentEditable, originalEditable);
};

/**
 * Check if form has changes using the "omit ignored fields" approach (like existing implementation)
 * This is more efficient when you have many ignored fields and few editable fields
 * @param {Object} currentFormData - Current form data
 * @param {Object} originalFormData - Original form data
 * @param {Array} additionalIgnoredFields - Additional fields to ignore
 * @returns {boolean} True if form has changes
 */
export const hasFormChangesByOmit = (
  currentFormData,
  originalFormData,
  additionalIgnoredFields = []
) => {
  if (!currentFormData || !originalFormData) {
    return false;
  }

  // Combine default ignored fields with system flags and additional ones
  const allIgnoredFields = [...IGNORED_FIELD_KEYS, ...SYSTEM_FLAGS, ...additionalIgnoredFields];

  // Use lodash omit to remove ignored fields
  const currentData = omit(currentFormData, allIgnoredFields);
  const originalData = omit(originalFormData, allIgnoredFields);

  // Compare using lodash isEqual for deep comparison
  return !isEqual(currentData, originalData);
};

/**
 * Get a summary of what fields have changed
 * @param {Object} currentFormData - Current form data
 * @param {Object} originalFormData - Original form data
 * @param {string} taskType - Type of task (optional)
 * @param {Array} additionalEditableFields - Additional fields to consider editable
 * @returns {Object} Object with changed fields and their values
 */
export const getChangedFields = (
  currentFormData,
  originalFormData,
  taskType = null,
  additionalEditableFields = []
) => {
  if (!currentFormData || !originalFormData) {
    return { changedFields: {}, hasChanges: false };
  }

  const editableFields = taskType 
    ? getEditableFields(taskType, additionalEditableFields)
    : getAllEditableFields(additionalEditableFields);

  // Use lodash pick for better performance
  const currentEditable = pick(currentFormData, editableFields);
  const originalEditable = pick(originalFormData, editableFields);

  const changedFields = {};
  let hasChanges = false;

  editableFields.forEach(key => {
    const currentValue = currentEditable[key];
    const originalValue = originalEditable[key];

    if (!isEqual(currentValue, originalValue)) {
      changedFields[key] = {
        current: currentValue,
        original: originalValue
      };
      hasChanges = true;
    }
  });

  return { changedFields, hasChanges };
};

/**
 * Check if a task is newly created (not yet saved)
 * @param {Object} formData - The form data object
 * @returns {boolean} True if task is newly created
 */
export const isNewlyCreated = (formData) => {
  if (!formData) return false;
  
  // Check both possible field names for newly created flag
  // Handle both boolean and string values
  const newlyCreated = formData.NewlyCreated === true || formData.NewlyCreated === 'true' || formData.NewlyCreated === 'True';
  const isNewlyCreated = formData.IsNewlyCreated === true || formData.IsNewlyCreated === 'true' || formData.IsNewlyCreated === 'True';
  
  return newlyCreated || isNewlyCreated;
};

/**
 * Get the appropriate warning message based on task state
 * @param {boolean} isNewlyCreated - Whether task is newly created
 * @param {boolean} hasChanges - Whether form has changes
 * @returns {Object} Warning message configuration
 */
export const getWarningMessage = (isNewlyCreated, hasChanges) => {
  if (isNewlyCreated) {
    return {
      title: "Unsaved Task",
      message: "The new task definition has not yet been saved. Any changes will be lost and the element removed by canceling. Do you want to continue without saving?",
      severity: "warning"
    };
  } else if (hasChanges) {
    return {
      title: "Unsaved Changes", 
      message: "Changes were made, do you want to continue without saving?",
      severity: "info"
    };
  }
  
  return null;
};


/**
 * Create a form change detection hook for React components
 * @param {Object} currentFormData - Current form data
 * @param {Object} originalFormData - Original form data
 * @param {string} taskType - Type of task (optional)
 * @param {Array} additionalEditableFields - Additional fields to consider editable
 * @returns {Object} Object with change detection methods and state
 */
export const useFormChangeDetection = (
  currentFormData,
  originalFormData,
  taskType = null,
  additionalEditableFields = []
) => {
  const hasChanges = hasFormChanges(
    currentFormData,
    originalFormData,
    taskType,
    additionalEditableFields
  );

  const { changedFields } = getChangedFields(
    currentFormData,
    originalFormData,
    taskType,
    additionalEditableFields
  );

  const isNew = isNewlyCreated(currentFormData);
  const warningMessage = getWarningMessage(isNew, hasChanges);

  return {
    hasChanges,
    changedFields,
    isNewlyCreated: isNew,
    warningMessage,
    getChangedFields: () => getChangedFields(currentFormData, originalFormData, taskType, additionalEditableFields),
    hasFormChanges: () => hasFormChanges(currentFormData, originalFormData, taskType, additionalEditableFields)
  };
};

export default {
  EDITABLE_FIELD_KEYS,
  IGNORED_FIELD_KEYS,
  SYSTEM_FLAGS,
  getEditableFields,
  getAllEditableFields,
  extractEditableFields,
  hasFormChanges,
  hasFormChangesByOmit,
  getChangedFields,
  isNewlyCreated,
  getWarningMessage,
  useFormChangeDetection
};
