import React, { useState, useEffect } from "react";
import { Box, useTheme, Grid } from "@mui/material";
import { Search as SearchIcon } from "@mui/icons-material";
import { snippetTableColumns } from "../../config";
import SnippetsTable from "./SnippetsTable";
import useSearch from "../Hooks/useSearch";
import FAWCard from "../component-widget/FAWCard";
import FAWTypography from "../component-widget/FAWTypography";
import FAWInput from "../component-widget/FAWInput";
import FAWLoader from "../component-widget/FAWLoader";
import WorkflowTree from "./WorkflowTree";
import axios from "../../Helpers/FetchCsrfToken";


const InsertSnippet = ({
  loadSnippetsAsync,
  workItemId,
  task,
  currentId,
  setCurrentId,
  handleError,
  setSnippetModalOpen
}) => {
  const theme = useTheme();
  
  const [snippets, setSnippets] = useState(null);
  const [searchTerm, setSearchTerm] = useState("");
  const [loadingSnippets, setLoadingSnippets] = useState(false);
  const [currentSnippet, setCurrentSnippet] = useState(null);
  const [snippetTree, setSnippetTree] = useState([]);

  const [filteredResult] = useSearch({
    searchTerm,
    allItems: snippets,
    keys: ["title", "description", "lastUpdate"],
  });

  useEffect(() => {
    const loadSnippets = async (workItemId) => {
      if (typeof loadSnippetsAsync !== 'function') {
        console.error('loadSnippetsAsync is not a function!', loadSnippetsAsync);
        setLoadingSnippets(false);
        return;
      }
      
      setLoadingSnippets(true);
      try {
        const snippets = await loadSnippetsAsync(workItemId, (error, result) => {
          if (error) {
            handleError(error, result, workItemId, 0);
          }
        });
        setLoadingSnippets(false);
        if (snippets && snippets.length > 0) {
          setSnippets(snippets);
        }
        else if(snippets === undefined){
          setSnippetModalOpen(false);
        }
      } catch (error) {
        console.error('Error calling loadSnippetsAsync:', error);
        setLoadingSnippets(false);
        handleError(error, null, workItemId, 0);
      }
    };
    if (workItemId && workItemId > 0) {
      loadSnippets(workItemId);
    }
  }, [workItemId]);

  useEffect(() => {
    if (!currentId || currentId === 0) {
      setCurrentSnippet(null);
      setSnippetTree([]);
      return;
    }

    if (filteredResult) {
      const selectedSnippet = filteredResult.find((s) => {
        const snippetId = s.id || s.Id;
        return Number(snippetId) === Number(currentId);
      });
      
      if (selectedSnippet) {
        setCurrentSnippet(selectedSnippet);
        loadSnippetTree(selectedSnippet.id || selectedSnippet.Id);
      }
    }
  }, [currentId, filteredResult]);

  const loadSnippetTree = async (snippetId) => {
    if (!snippetId) return;
    
    try {
      const response = await axios({
        url: `/WorkflowTaskDefSnippet/GetSnippetTree?snippetId=${snippetId}`,
        method: 'GET',
        timeout: 300000
      });

      if (typeof response.data === 'string' && response.data.includes('<!DOCTYPE html>')) {
        throw new Error('Server returned HTML instead of JSON');
      }

      const result = response.data;
      if (!result?.success) {
        setSnippetTree([]);
        return;
      }

      const transformNode = (node) => ({
        ...node,
        title: node.Name || node.name || '',
        children: node.Children ? node.Children.map(transformNode) : (node.children ? node.children.map(transformNode) : []),
        expanded: true,
        // Preserve Type and Icon properties for icon rendering
        Type: node.Type || node.type,
        type: node.Type || node.type,
        Icon: node.Icon || node.icon,
        icon: node.Icon || node.icon,
      });

      const treeData = result.data;
      const transformedData = Array.isArray(treeData) 
        ? treeData.map(transformNode)
        : treeData?.Children 
          ? treeData.Children.map(transformNode)
          : [];

      setSnippetTree(transformedData || []);
    } catch (error) {
      console.error('Error loading snippet tree:', error);
      setSnippetTree([]);
    }
  };

  const getCurrentTree = (trees) => {
    if (!Array.isArray(trees) || !trees.length) return [];
    return trees.map((tree) => ({
      ...tree,
      title: tree.title || tree.name || tree.Name || '',
      Name: tree.Name || tree.name || tree.title || '',
      children: getCurrentTree(tree.children || tree.Children || []),
      // Preserve Type and Icon properties for icon rendering
      Type: tree.Type || tree.type,
      type: tree.Type || tree.type,
      Icon: tree.Icon || tree.icon,
      icon: tree.Icon || tree.icon,
    }));
  };

  const currentTree = getCurrentTree(snippetTree);
  
  // Convert to treeDataJson format expected by WorkflowTree
  const treeDataJson = currentTree.length > 0 ? currentTree : null;

  return (
    <Grid container sx={{ height: '100%' }}>
      {/* Left Column - Snippets Table */}
      <Grid item xs={12} md={8} sx={{ borderRight: '1px solid', borderColor: 'divider' }}>
        <FAWCard sx={{ height: '100%', display: 'flex', flexDirection: 'column', overflow: 'hidden', borderRadius: 0, boxShadow: 'none' }}>
          {/* Header */}
          <Box
            sx={{
              backgroundColor: theme.palette.primary.main,
              color: theme.palette.primary.contrastText,
              p: 2,
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'space-between',
              minHeight: 56
            }}
          >
            <FAWTypography variant="h6" component="h2">
              Snippets
            </FAWTypography>
            <FAWInput
              placeholder="Search Name, Description, Last updated..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              startIcon={<SearchIcon />}
              sx={{
                width: 300,
                '& .MuiOutlinedInput-root': {
                  backgroundColor: 'white',
                  '& fieldset': {
                    borderColor: 'rgba(255, 255, 255, 0.3)',
                  },
                  '&:hover fieldset': {
                    borderColor: 'rgba(255, 255, 255, 0.5)',
                  },
                  '&.Mui-focused fieldset': {
                    borderColor: 'white',
                  },
                },
                '& .MuiInputBase-input': {
                  color: theme.palette.text.primary,
                  '&::placeholder': {
                    color: theme.palette.text.secondary,
                    opacity: 1,
                  },
                },
              }}
            />
          </Box>

          {/* Content */}
          <Box sx={{ flex: 1, overflow: 'hidden', display: 'flex', flexDirection: 'column' }}>
            {!filteredResult || loadingSnippets ? (
              <Box
                sx={{
                  display: 'flex',
                  flexDirection: 'column',
                  alignItems: 'center',
                  justifyContent: 'center',
                  height: 300,
                  gap: 2
                }}
              >
                <FAWLoader 
                  size={40}
                  label="Loading snippets..."
                  inline={false}
                />
              </Box>
            ) : (
              <Box sx={{ flex: 1, overflow: 'auto', maxHeight: '70vh' }}>
                <SnippetsTable
                  columns={snippetTableColumns}
                  entries={filteredResult}
                  toggleSelection={(id) =>
                    setCurrentId((prev) => (prev === id ? 0 : id))
                  }
                  selectedId={currentId}
                />
              </Box>
            )}
          </Box>
        </FAWCard>
      </Grid>

      {/* Right Column - Preview Panel */}
      <Grid item xs={12} md={4}>
        <Box sx={{ display: 'flex', flexDirection: 'column', height: '100%', p: 2 }}>
          <FAWTypography variant="h6" sx={{ mb: 2, fontWeight: 600 }}>
            Preview{currentSnippet ? `: ${currentSnippet.name || currentSnippet.title || currentSnippet.Name || ''}` : ''}
          </FAWTypography>
          <Box sx={{ flex: 1, overflow: 'auto', border: '1px solid', borderColor: 'divider', borderRadius: 1, p: 2 }}>
            {currentSnippet && treeDataJson ? (
              <WorkflowTree
                currentTask={null}
                readOnly={true}
                isPreview={true}
                treeDataJson={treeDataJson}
                handleNodeSelect={() => {}} // No-op for preview
                handleAction={() => {}} // No-op for preview
                workItem={{ id: 0, isEditable: false, allowAdhocFlowEdit: false }}
                updateTreeAsync={async () => {}} // No-op for preview
                removeTaskAsync={async () => {}} // No-op for preview
                restoreTaskAsync={async () => {}} // No-op for preview
                addTaskAsync={async () => {}} // No-op for preview
                saveTaskPredecessorAsync={async () => {}} // No-op for preview
                moveTaskAsync={async () => {}} // No-op for preview
                moveTaskToSectionAsync={async () => {}} // No-op for preview
                handleError={() => {}} // No-op for preview
                loading={false}
                height="100%"
                isSnippet={true}
                showSearchBar={false}
                isDefinitionMode={true}
                saveInsertSnippetAsync={async () => {}} // No-op for preview
                loadSnippetsAsync={async () => {}} // No-op for preview
              />
            ) : (
              <Box sx={{ display: 'flex', alignItems: 'center', justifyContent: 'center', height: 200, color: 'text.secondary' }}>
                <FAWTypography variant="body2">
                  {currentSnippet ? 'No preview available' : 'Select a snippet to preview'}
                </FAWTypography>
              </Box>
            )}
          </Box>
        </Box>
      </Grid>
    </Grid>
  );
};

export default InsertSnippet;
