/**
 * Task Type Utilities
 * Shared utilities for converting task type codes to user-friendly names
 */

/**
 * Converts task type codes to user-friendly display names
 * @param {string} type - The task type code (e.g., 'SECTION', 'IF', 'NOTIFICATION')
 * @returns {string} - The user-friendly name (e.g., 'Section', 'Conditional', 'Notification')
 */
export const getTaskTypeName = (type) => {
  const taskTypeNames = {
    'SECTION': 'Section',
    'STEP': 'Step', 
    'REVIEW': 'Review',
    'NOTIFICATION': 'Notification',
    'ROUTE_TO': 'Route To',
    'ACTION': 'Action',
    'IF': 'Conditional',
    'CONDITIONAL_SNIPPET': 'Conditional Snippet',
    'CLOSE': 'Close',
    'EDIT': 'Edit',
    'APPROVE': 'Approve',
    'GO_TO': 'Go To'
  };
  return taskTypeNames[type] || type;
};

/**
 * Gets all available task type names for display purposes
 * @returns {Object} - Object with task type codes as keys and display names as values
 */
export const getAllTaskTypeNames = () => {
  return {
    'SECTION': 'Section',
    'STEP': 'Step', 
    'REVIEW': 'Review',
    'NOTIFICATION': 'Notification',
    'ROUTE_TO': 'Route To',
    'ACTION': 'Action',
    'IF': 'Conditional',
    'CONDITIONAL_SNIPPET': 'Conditional Snippet',
    'CLOSE': 'Close',
    'EDIT': 'Edit',
    'APPROVE': 'Approve',
    'GO_TO': 'Go To'
  };
};

/**
 * Checks if a task type is valid
 * @param {string} type - The task type code to validate
 * @returns {boolean} - True if the task type is valid, false otherwise
 */
export const isValidTaskType = (type) => {
  const validTypes = Object.keys(getAllTaskTypeNames());
  return validTypes.includes(type);
};

/**
 * Gets task type flags for conditional rendering
 * @param {string} type - The task type code
 * @returns {Object} - Object with boolean flags for each task type
 */
export const getTaskTypeFlags = (type) => {
  return {
    isActionTask: type === 'ACTION',
    isNotificationTask: type === 'NOTIFICATION',
    isCloseTask: type === 'CLOSE',
    isSectionTask: type === 'SECTION',
    isReviewTask: type === 'REVIEW',
    isStepTask: type === 'STEP',
    isRouteToTask: type === 'ROUTE_TO',
    isEditTask: type === 'EDIT',
    isApproveTask: type === 'APPROVE',
    isGoToTask: type === 'GO_TO',
    isIfTask: type === 'IF' || type === 'CONDITIONAL_SNIPPET' // Both IF and CONDITIONAL_SNIPPET use IfTask component
  };
};

/**
 * Gets the route to label based on task type
 * Matches legacy ASP.NET conditional labeling behavior
 * @param {string} type - The task type code
 * @returns {string} - The appropriate label for route to functionality
 */
export const getRouteToLabel = (type) => {
  const routeLabels = {
    'REVIEW': 'Review By:',
    'CLOSE': 'Closure By:',
    'ROUTE_TO': 'Route To:',
    'GO_TO': 'Go To:',
    'IF': 'Conditional Route:'
  };
  return routeLabels[type] || 'Route To:';
};

/**
 * Checks if a task type has required UDFs
 * @param {string} type - The task type code
 * @returns {boolean} - True if the task type requires UDFs
 */
export const hasRequiredUDFs = (type) => {
  const udfRequiredTypes = ['ACTION', 'NOTIFICATION', 'REVIEW'];
  return udfRequiredTypes.includes(type);
};

/**
 * Checks if all required UDFs are properly filled in
 * @param {object} formData - Form data containing UserDefinedFields
 * @param {boolean} validateUDFs - Whether to validate UDFs (matches legacy validateRelateData parameter)
 * @returns {boolean} - True if all required UDFs are filled in
 */
export const areRequiredUDFsFilled = (formData, validateUDFs = false) => {
  // If not validating UDFs, always return true (matches legacy behavior)
  if (!validateUDFs) {
    return true;
  }
  
  // If task type doesn't require UDFs, return true
  if (!formData || !formData.Type || !hasRequiredUDFs(formData.Type)) {
    return true;
  }
  
  // Check if UserDefinedFields exist and are properly filled
  const userDefinedFields = formData.UserDefinedFields || [];
  
  // If no UDFs are defined, that's valid (not all ACTION/NOTIFICATION/REVIEW tasks need UDFs)
  if (userDefinedFields.length === 0) {
    return true;
  }
  
  // Check if any required UDFs are missing values (matches legacy logic exactly)
  const hasUnfilledRequiredFields = userDefinedFields.some(field => {
    // Check if field is marked as required and has no value
    const isRequired = field.IsRequired === true || field.isRequired === true;
    const hasValue = field.Value !== undefined && field.Value !== null && field.Value !== '';
    
    return isRequired && !hasValue;
  });
  
  return !hasUnfilledRequiredFields;
};

/**
 * Validates form data for task completion (matches legacy ValidateModel with validateRelateData = true)
 * @param {object} formData - Form data to validate
 * @returns {object} - { isValid: boolean, error: string }
 */
export const validateTaskCompletion = (formData) => {
  // Check name validation (matches legacy ValidateModel logic exactly)
  // Legacy: bool nameValid = !string.IsNullOrEmpty(model.Name) && !model.Name.Equals("[Name]");
  const nameValid = formData && formData.Name && formData.Name.trim() !== '' && formData.Name !== '[Name]';
  
  // Check UDF validation (matches legacy validateRelateData = true)
  const udfValid = areRequiredUDFsFilled(formData, true);
  
  if (!nameValid) {
    return {
      isValid: false,
      error: 'Missing required fields' // Matches legacy message
    };
  }
  
  if (!udfValid) {
    return {
      isValid: false,
      error: 'Missing required fields' // Matches legacy message
    };
  }
  
  return {
    isValid: true,
    error: null
  };
};

export default {
  getTaskTypeName,
  getAllTaskTypeNames,
  isValidTaskType,
  getTaskTypeFlags,
  getRouteToLabel,
  hasRequiredUDFs,
  areRequiredUDFsFilled,
  validateTaskCompletion
};