import React, { useState, useEffect } from 'react';
import { Box } from '@mui/material';
import FieldManagementSection from '../../../../shared/FieldManagementSection';

/**
 * Third Party Fields Management Component
 * Uses the reusable FieldManagementSection component
 */
const ThirdPartyFieldsManagement = ({ 
  formData, 
  onFieldChange, 
  readOnly = false 
}) => {
  const [selectedFields, setSelectedFields] = useState([]);
  
  const getThirdPartyFieldsAll = () => formData?.ThirdPartyFieldsAll || formData?.thirdPartyFieldsAll || [];
  const getThirdPartyFields = () => formData?.ThirdPartyFields || formData?.thirdPartyFields || [];

  const allAvailableFields = React.useMemo(() => {
    const allFields = getThirdPartyFieldsAll();
    const savedFields = getThirdPartyFields();
    
    if (!allFields.length && !savedFields.length) return [];
    
    const merged = [...allFields];
    
    savedFields.forEach(saved => {
      const name = saved.FieldName || saved.fieldName || saved.Name || saved.name;
      if (!merged.some(f => (f.FieldName || f.fieldName || f.Name || f.name) === name)) {
        merged.push(saved);
      }
    });
    
    return merged;
  }, [formData?.ThirdPartyFieldsAll, formData?.thirdPartyFieldsAll, formData?.ThirdPartyFields, formData?.thirdPartyFields]);

  useEffect(() => {
    const fields = getThirdPartyFields();
    if (fields && fields.length > 0) {
      const fieldNames = fields.map(field => field.FieldName || field.fieldName || field.Name || field.name);
      setSelectedFields(fieldNames);
    }
  }, [formData?.ThirdPartyFields, formData?.thirdPartyFields]);

  const handleFieldSelect = (fieldName) => {
    if (readOnly) return;
    
    const newSelectedFields = selectedFields.includes(fieldName)
      ? selectedFields.filter(name => name !== fieldName)
      : [...selectedFields, fieldName];
    
    setSelectedFields(newSelectedFields);
    
    if (onFieldChange) {
      const selectedFieldObjects = newSelectedFields.map(name => 
        allAvailableFields.find(field => (field.FieldName || field.fieldName || field.Name || field.name) === name)
      ).filter(Boolean);
      
      onFieldChange('ThirdPartyFields', selectedFieldObjects);
    }
  };

  return (
    <>
      <Box 
        sx={{ 
          height: '1px', 
          backgroundColor: '#e0e0e0', 
          margin: '16px 0',
          width: '100%'
        }} 
      />
      <FieldManagementSection
        title="Available Third Party Fields"
        fields={allAvailableFields}
        selectedFields={selectedFields}
        onFieldSelect={handleFieldSelect}
        searchPlaceholder="Type in field name"
        readOnly={readOnly}
      />
    </>
  );
};

export default ThirdPartyFieldsManagement;