export function defaultGetNodeKey({ treeIndex }) {
  return treeIndex;
}

// Cheap hack to get the text of a react object
function getReactElementText(parent) {
  if (typeof parent === "string") {
    return parent;
  }

  if (
    typeof parent !== "object" ||
    !parent.props ||
    !parent.props.children ||
    (typeof parent.props.children !== "string" &&
      typeof parent.props.children !== "object")
  ) {
    return "";
  }

  if (typeof parent.props.children === "string") {
    return parent.props.children;
  }

  return parent.props.children
    .map((child) => getReactElementText(child))
    .join("");
}

// Search for a query string inside a node property
function stringSearch(key, searchQuery, node, path, treeIndex, caseSensitive) {
  if (!searchQuery) {
    return false;
  }

  if (!caseSensitive) {
    searchQuery = searchQuery.toUpperCase();
  }

  if (typeof node[key] === "function") {
    let str = String(node[key]({ node, path, treeIndex }));
    if (!str) {
      return false;
    }
    if (!caseSensitive) {
      str = str.toUpperCase();
    }
    // Search within text after calling its function to generate the text
    return str.indexOf(searchQuery) > -1;
  }

  if (typeof node[key] === "object") {
    let str = getReactElementText(node[key]);
    if (!str) {
      return false;
    }

    if (!caseSensitive) {
      str = str.toUpperCase();
    }
    // Search within text inside react elements
    return str.indexOf(searchQuery) > -1;
  }

  let str = String(node[key]);
  if (!str) {
    return false;
  }

  if (!caseSensitive) {
    str = str.toUpperCase();
  }
  // Search within string
  return str.indexOf(searchQuery) > -1;
}

export function defaultSearchMethod({
  node,
  path,
  treeIndex,
  searchQuery,
  caseSensitive = true,
}) {
  return (
    stringSearch("title", searchQuery, node, path, treeIndex, caseSensitive) ||
    stringSearch("subtitle", searchQuery, node, path, treeIndex, caseSensitive)
  );
}
