import React, { useMemo, useEffect } from "react";
import FAWTable from "../component-widget/FAWTable/FAWTable";
import FAWTypography from "../component-widget/FAWTypography";
import FAWTooltip from "../component-widget/FAWTooltip";
import { Box } from "@mui/material";
import { colors } from "../../utils/designTokens";

/**
 * Helper function to convert hex color to rgba
 */
const hexToRgba = (hex, alpha = 1) => {
  if (!hex) return null;
  const cleanHex = hex.replace('#', '');
  const r = parseInt(cleanHex.substr(0, 2), 16);
  const g = parseInt(cleanHex.substr(2, 2), 16);
  const b = parseInt(cleanHex.substr(4, 2), 16);
  return `rgba(${r}, ${g}, ${b}, ${alpha})`;
};

const SnippetTable = ({ columns, entries, toggleSelection, selectedId }) => {
  // Convert columns to FAWTable format
  const fawTableColumns = useMemo(() => {
    return columns.map((column) => {
      const colDef = {
        field: column.accessor,
        headerName: column.Header,
        sortable: true,
        filterable: true,
        align: 'left',
        headerAlign: 'left',
        flex: column.accessor === 'name' ? 0.8 : column.accessor === 'description' ? 1 : 0.5,
        minWidth: column.accessor === 'name' ? 150 : column.accessor === 'lastUpdate' ? 120 : 150,
      };

      // Custom cell renderer based on column type
      colDef.renderCell = (params) => {
        const isSelected = Number(params.row.id) === Number(selectedId);
        const value = params.value;

        if (column.accessor === 'lastUpdate') {
          return (
            <FAWTypography variant="body2" color="text.secondary">
              {value ? new Date(value).toLocaleDateString() : 'N/A'}
            </FAWTypography>
          );
        }

        if (column.accessor === 'description') {
          return (
            <FAWTooltip title={value || 'No description available'}>
              <Box
                sx={{
                  overflow: 'hidden',
                  textOverflow: 'ellipsis',
                  whiteSpace: 'nowrap',
                  width: '100%',
                  padding: '4px 0',
                }}
              >
                <FAWTypography
                  variant="body2"
                  sx={{
                    fontWeight: isSelected ? 600 : 400,
                    color: isSelected ? '#1976d2' : 'inherit',
                  }}
                >
                  {value || 'No description available'}
                </FAWTypography>
              </Box>
            </FAWTooltip>
          );
        }

        // Default cell renderer for name and other fields
        return (
          <FAWTypography
            variant="body2"
            sx={{
              fontWeight: isSelected ? 600 : 400,
              color: isSelected ? colors.action.link.default || '#1976d2' : 'inherit'
            }}
          >
            {value}
          </FAWTypography>
        );
      };

      return colDef;
    });
  }, [columns, selectedId]);

  // Convert entries to FAWTable rows format (ensure each row has a unique id)
  const fawTableRows = useMemo(() => {
    return entries.map((entry, index) => {
      // Use id field if available, otherwise create one
      let uniqueId;
      if (entry.id !== undefined && entry.id !== null) {
        uniqueId = entry.id;
      } else if (entry.Id !== undefined && entry.Id !== null) {
        uniqueId = entry.Id;
      } else {
        uniqueId = `snippet_${index}`;
      }

      return {
        ...entry,
        id: uniqueId,
      };
    });
  }, [entries]);

  // FAWTable row click handler
  const handleRowClick = (params) => {
    const snippetId = params.row.id;
    toggleSelection(snippetId);
  };

  // FAWTable row className for selection styling
  const getRowClassName = (params) => {
    if (Number(params.row.id) === Number(selectedId)) {
      return 'snippet-selected-row';
    }
    return '';
  };

  return (
    <Box 
      className="snippets-table-container"
      sx={{ 
        height: '100%', 
        width: '100%',
        overflow: 'hidden',
        '& .MuiDataGrid-root': {
          overflow: 'hidden !important',
        },
        '& .MuiDataGrid-main': {
          overflow: 'hidden !important',
        },
        '& .MuiDataGrid-virtualScroller': {
          overflowX: 'hidden !important',
          overflowY: 'auto !important',
        }
      }}
    >
        <FAWTable
          rows={fawTableRows}
          columns={fawTableColumns}
          onRowClick={handleRowClick}
          getRowClassName={getRowClassName}
          showPagination={false}
          showToolbar={false}
          showSearch={false}
          autoHeight={true}
          enableMultiSelect={false}
          checkboxSelection={false}
          hasDisableRowSelectionClick={false}
          emptyStateTitle="No snippets available"
          emptyStateMessage="No snippets available"
          rowHeight={44}
          columnHeaderHeight={56}
        />
    </Box>
  );
};

export default SnippetTable;
