import React, { useState, useEffect, useContext, Fragment, useMemo, useCallback, useRef } from "react";
import styled from "styled-components";
import { Box } from "@mui/material";
import { COLORS } from "../../Helpers/Const";
import { IconWrapper } from "../Base/static";
import { FiPlus, FiMinus } from "react-icons/fi";
import FAWButton from "../component-widget/FAWButton";
import FAWSkeleton from "../component-widget/FAWSkeleton";
import FAWCheckbox from "../component-widget/FAWCheckbox";
import { colors } from "../../utils/designTokens";


const Predecessors = ({
  saveTaskPredecessorAsync,
  data = [],
  task = {},
  workflowId,
  handleClose,
  handleError,
  onStateChange
}) => {
  // Safely extract task properties with defaults
  const { id, predecessors = [] } = task || {};
  
  // Memoize the original predecessors to prevent unnecessary re-renders
  // Use JSON.stringify for deep comparison to avoid infinite loops
  const predecessorsString = useMemo(() => JSON.stringify(Array.isArray(predecessors) ? predecessors : []), [predecessors]);
  const dataString = useMemo(() => JSON.stringify(Array.isArray(data) ? data : []), [data]);
  
  // Helper function to check if a node is a header/parent node that should be filtered out
  // Headers are nodes that have children but no valid selectable ID (can't be a predecessor)
  const isHeaderNode = (node) => {
    // Check if node has children
    const hasChildren = node?.children && Array.isArray(node.children) && node.children.length > 0;
    
    // Check if node has a valid selectable ID
    // A valid ID should be a number > 0, not null, undefined, or 0
    const nodeId = node?.id;
    const hasValidId = nodeId !== null && nodeId !== undefined && nodeId !== '' && 
                       (typeof nodeId === 'number' ? nodeId > 0 : 
                        typeof nodeId === 'string' ? !isNaN(parseInt(nodeId, 10)) && parseInt(nodeId, 10) > 0 : false);
    
    // If it has children but no valid ID, it's a header node that should be filtered
    return hasChildren && !hasValidId;
  };

  const [localData, setLocalData] = useState(() => {
    if (!Array.isArray(data)) return [];
    // Filter out header nodes (nodes with children but no valid ID) - they're not useful
    // If they have children, promote children to top level
    const filteredData = [];
    data.forEach(node => {
      if (!isHeaderNode(node)) {
        filteredData.push(node);
      } else if (node?.children && Array.isArray(node.children) && node.children.length > 0) {
        // Promote children of header nodes to top level
        filteredData.push(...node.children);
      }
    });
    return filteredData;
  });
  const [localPredecessors, setLocalPredecessors] = useState(() => Array.isArray(predecessors) ? predecessors : []);
  const [loading, setLoading] = useState(false);
  const [fetchedPredecessors, setFetchedPredecessors] = useState(null); // Track fetched data separately
  
  // Use fetched predecessors as the baseline if available, otherwise use prop predecessors
  const originalPredecessors = useMemo(() => {
    if (fetchedPredecessors !== null) {
      return Array.isArray(fetchedPredecessors) ? fetchedPredecessors.slice() : [];
    }
    return Array.isArray(predecessors) ? predecessors.slice() : [];
  }, [fetchedPredecessors, predecessorsString]);
  
  // Fetch predecessor data from API when component mounts or when workflowId/taskId changes
  useEffect(() => {
    const fetchPredecessorData = async () => {
      if (!workflowId || !id || workflowId === 0 || id === 0 || !saveTaskPredecessorAsync) {
        return;
      }
      
      setLoading(true);
      try {
        // Use simple API to get just the list of predecessor IDs
        if (saveTaskPredecessorAsync.getTaskPredecessors) {
          const predecessorIds = await saveTaskPredecessorAsync.getTaskPredecessors(workflowId, id);
          // Normalize IDs to numbers and remove duplicates
          const normalizedIds = Array.from(new Set(
            (Array.isArray(predecessorIds) ? predecessorIds : []).map(id => 
              typeof id === 'string' ? parseInt(id, 10) : Number(id)
            ).filter(id => !isNaN(id) && id > 0)
          ));
          setFetchedPredecessors(normalizedIds);
          setLocalPredecessors(normalizedIds);
        } else {
          throw new Error('getTaskPredecessors method not available');
        }
      } catch (error) {
        console.error('Error fetching predecessor data:', error);
        if (handleError) {
          handleError(error);
        }
      } finally {
        setLoading(false);
      }
    };
    
    fetchPredecessorData();
  }, [workflowId, id, handleError, saveTaskPredecessorAsync]);

  const addPredecessor = useCallback((id) =>
    setLocalPredecessors(prev => [...prev, id]), []);
  const removePredecessor = useCallback((id) =>
    setLocalPredecessors(prev => prev.filter((p) => p !== id)), []);

  // Track previous prop values to prevent infinite loops
  const prevDataStringRef = useRef(dataString);
  const prevPredecessorsStringRef = useRef(predecessorsString);

  // Update local state when props change, but only if they're actually different
  // Use string comparison to prevent infinite loops from new array references
  useEffect(() => {
    if (dataString !== prevDataStringRef.current && Array.isArray(data)) {
      prevDataStringRef.current = dataString;
      // Filter out header nodes (nodes with children but no valid ID) - they're not useful
      // If they have children, promote children to top level
      const filteredData = [];
      data.forEach(node => {
        if (!isHeaderNode(node)) {
          filteredData.push(node);
        } else if (node?.children && Array.isArray(node.children) && node.children.length > 0) {
          // Promote children of header nodes to top level
          filteredData.push(...node.children);
        }
      });
      setLocalData(filteredData);
    }
  }, [dataString, data]);

  // Only update from props if we haven't fetched data yet (fetchedPredecessors is null)
  useEffect(() => {
    if (fetchedPredecessors === null && predecessorsString !== prevPredecessorsStringRef.current && Array.isArray(predecessors)) {
      prevPredecessorsStringRef.current = predecessorsString;
      setLocalPredecessors(predecessors);
    }
  }, [predecessorsString, predecessors, fetchedPredecessors]);

  // Memoize addedIds and removeIds to prevent infinite loops
  // Ensure they are always arrays
  const addedIds = useMemo(() => {
    if (!Array.isArray(localPredecessors) || !Array.isArray(originalPredecessors)) {
      return [];
    }
    return localPredecessors.filter((p) => !originalPredecessors.includes(p));
  }, [localPredecessors, originalPredecessors]);

  const removeIds = useMemo(() => {
    if (!Array.isArray(localPredecessors) || !Array.isArray(originalPredecessors)) {
      return [];
    }
    return originalPredecessors.filter((p) => !localPredecessors.includes(p));
  }, [localPredecessors, originalPredecessors]);

  // Use ref to avoid infinite loop with onStateChange
  const onStateChangeRef = useRef(onStateChange);
  onStateChangeRef.current = onStateChange;

  // Memoize saveFunction to prevent it from changing on every render
  // Send the final list of predecessor IDs (simple approach)
  const saveFunction = useCallback(() => {
    if (!id || !workflowId || !saveTaskPredecessorAsync) return;
    return saveTaskPredecessorAsync(workflowId, id, localPredecessors, handleError);
  }, [saveTaskPredecessorAsync, workflowId, id, localPredecessors, handleError]);

  // Memoize the state object to prevent unnecessary re-renders
  const stateObject = useMemo(() => ({
    addedIds,
    removeIds,
    hasChanges: addedIds.length > 0 || removeIds.length > 0,
    saveFunction
  }), [addedIds, removeIds, saveFunction]);

  // Notify parent component about state changes
  // Use a ref to track previous state to avoid unnecessary updates
  const prevStateRef = useRef();
  useEffect(() => {
    const prevState = prevStateRef.current;
    const stateChanged = !prevState || 
      JSON.stringify(prevState.addedIds) !== JSON.stringify(addedIds) ||
      JSON.stringify(prevState.removeIds) !== JSON.stringify(removeIds);
    
    if (stateChanged && onStateChangeRef.current) {
      prevStateRef.current = stateObject;
      onStateChangeRef.current(stateObject);
    }
  }, [addedIds, removeIds, stateObject]);

  return (
    <Fragment>
      {loading ? (
        <FAWSkeleton variant="predecessor" />
      ) : (
        <div className="row">
          {localData.map((node, index) => (
            <Node
              key={index}
              {...node}
              level={1}
              original={originalPredecessors}
              current={localPredecessors}
              addPredecessor={addPredecessor}
              removePredecessor={removePredecessor}
              currentTaskId={id} // Pass current task ID to hide its checkbox
            />
          ))}
        </div>
      )}
      {/* Status Legend */}
      <Box 
        sx={{ 
          display: "flex", 
          padding: "15px 0 10px 0", 
          borderTop: `1px solid ${colors?.ui?.border?.static || '#dadada'}`,
          gap: "8px",
          alignItems: "center"
        }}
      >
        <FAWButton
          variant="outlined"
          size="small"
          disabled
          sx={{
            backgroundColor: COLORS.LIGHT || '#f5f5f5',
            borderColor: COLORS.LIGHT || '#f5f5f5',
            color: '#282e37',
            cursor: 'default',
            '&:hover': {
              backgroundColor: COLORS.LIGHT || '#f5f5f5',
              borderColor: COLORS.LIGHT || '#f5f5f5',
            },
            '&.Mui-disabled': {
              backgroundColor: COLORS.LIGHT || '#f5f5f5',
              borderColor: COLORS.LIGHT || '#f5f5f5',
              color: '#282e37',
            }
          }}
        >
          Current
        </FAWButton>
        <FAWButton
          variant="outlined"
          size="small"
          disabled
          sx={{
            backgroundColor: COLORS.SUCCESS_BACKGROUND || '#d4edda',
            borderColor: COLORS.SUCCESS_BACKGROUND || '#d4edda',
            color: '#282e37',
            cursor: 'default',
            '&:hover': {
              backgroundColor: COLORS.SUCCESS_BACKGROUND || '#d4edda',
              borderColor: COLORS.SUCCESS_BACKGROUND || '#d4edda',
            },
            '&.Mui-disabled': {
              backgroundColor: COLORS.SUCCESS_BACKGROUND || '#d4edda',
              borderColor: COLORS.SUCCESS_BACKGROUND || '#d4edda',
              color: '#282e37',
            }
          }}
        >
          Added
        </FAWButton>
        <FAWButton
          variant="outlined"
          size="small"
          disabled
          sx={{
            backgroundColor: COLORS.LIGHT_RED || '#f8d7da',
            borderColor: COLORS.LIGHT_RED || '#f8d7da',
            color: '#282e37',
            cursor: 'default',
            '&:hover': {
              backgroundColor: COLORS.LIGHT_RED || '#f8d7da',
              borderColor: COLORS.LIGHT_RED || '#f8d7da',
            },
            '&.Mui-disabled': {
              backgroundColor: COLORS.LIGHT_RED || '#f8d7da',
              borderColor: COLORS.LIGHT_RED || '#f8d7da',
              color: '#282e37',
            }
          }}
        >
          Removed
        </FAWButton>
      </Box>
    </Fragment>
  );
};

const Node = ({
  id,
  title,
  children,
  level,
  original,
  current,
  removePredecessor,
  addPredecessor,
  currentTaskId, // Add currentTaskId prop to identify the task being edited
}) => {
  const childChidrenLevel = level + 1;
  
  // Normalize IDs for comparison (handle both string and number types)
  const normalizedId = typeof id === 'string' ? parseInt(id, 10) : Number(id);
  const normalizedCurrent = Array.isArray(current) ? current.map(c => typeof c === 'string' ? parseInt(c, 10) : Number(c)) : [];
  const normalizedOriginal = Array.isArray(original) ? original.map(o => typeof o === 'string' ? parseInt(o, 10) : Number(o)) : [];
  const normalizedCurrentTaskId = currentTaskId ? (typeof currentTaskId === 'string' ? parseInt(currentTaskId, 10) : Number(currentTaskId)) : null;
  
  const isPedecessor = !isNaN(normalizedId) && normalizedCurrent.includes(normalizedId);
  const isAdded = !isNaN(normalizedId) && normalizedCurrent.includes(normalizedId) && !normalizedOriginal.includes(normalizedId);
  const isRemoved = !isNaN(normalizedId) && !normalizedCurrent.includes(normalizedId) && normalizedOriginal.includes(normalizedId);
  const isOriginal = !isNaN(normalizedId) && normalizedOriginal.includes(normalizedId) && normalizedCurrent.includes(normalizedId);
  const isCurrentTask = normalizedCurrentTaskId && !isNaN(normalizedId) && normalizedId === normalizedCurrentTaskId;

  return (
    <Fragment>
      <div
        className={`col-md-offset-${level} col-md-${12 - level}`}
        style={{ borderLeft: `1px solid ${colors?.type?.secondary || '#6f7377'}`, padding: "3px 10px" }}
      >
        <div
          className="checkbox"
          style={{
            marginTop: 0,
            marginBottom: 0,
            backgroundColor: isAdded
              ? COLORS.SUCCESS_BACKGROUND
              : isRemoved
              ? COLORS.LIGHT_RED
              : isOriginal
              ? COLORS.LIGHT
              : COLORS.TRANSPARENT,
          }}
        >
          <div
            style={{
              display: "flex",
              justifyContent: "space-between",
              alignItems: "center",
              fontSize: "12px",
              minHeight: 0,
            }}
          >
            <div style={{ display: "flex", alignItems: "center", flex: 1 }}>
              {/* Hide checkbox for current task (can't be its own precondition) - matching legacy behavior */}
              {!isCurrentTask ? (
                <FAWCheckbox
                  id={`predecessor-checkbox-${normalizedId}`}
                  checked={isPedecessor}
                  onChange={(e, checked) => {
                    if (!isNaN(normalizedId)) {
                      // Material-UI Checkbox onChange provides (event, checked) as parameters
                      const isChecked = checked !== undefined ? checked : (e?.target?.checked ?? false);
                      isChecked ? addPredecessor(normalizedId) : removePredecessor(normalizedId);
                    }
                  }}
                  label={title}
                  labelStyle={{
                    fontWeight: 'normal',
                    color: 'inherit',
                    paddingLeft: '0px',
                    fontSize: '12px'
                  }}
                />
              ) : (
                <span style={{
                  fontWeight: isCurrentTask ? 'bold' : 'normal',
                  color: isCurrentTask ? 'cornflowerblue' : 'inherit',
                  paddingLeft: '0px',
                  fontSize: '12px'
                }}>
                  {title}
                </span>
              )}
            </div>
            <span >
              <IconWrapper colorOn={COLORS.TEXT} fontSize={12}>
                {isAdded ? <FiPlus style={{ cursor: 'default' }}/> : isRemoved ? <FiMinus style={{ cursor: 'default' }}/> : ""}
              </IconWrapper>
            </span>
          </div>
        </div>
      </div>
      {children && children.length > 0
        ? children.map((child, index) => (
            <Node
              key={index}
              {...child}
              level={childChidrenLevel}
              current={current}
              original={original}
              removePredecessor={removePredecessor}
              addPredecessor={addPredecessor}
              currentTaskId={currentTaskId} // Pass currentTaskId to nested nodes
            />
          ))
        : ""}
    </Fragment>
  );
};

export default Predecessors;
