import React, { useState, useEffect } from 'react';
import {
  Box,
  List,
  ListItem,
  ListItemText,
  ListItemButton,
  CircularProgress,
  Alert
} from '@mui/material';
import FAWTypography from '../FAWTypography';
import FAWInput from '../FAWInput';
import FAWButton from '../FAWButton';
import FAWModal from '../FAWModal';

/**
 * Shared Search UDF Modal Component
 * Used by workflow definitions, snippets, and work items
 */
const SearchUDFModal = ({ 
  open, 
  onClose, 
  entityId, // Can be workflowId, snippetId, or workItemId
  entityType = 'workflow', // 'workflow', 'snippet', or 'workitem'
  onNavigateToTask
}) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [searchResults, setSearchResults] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  const handleSearch = async () => {
    setLoading(true);
    setError(null);

    try {
      // Determine the correct API endpoint based on entity type
      let endpoint;
      let bodyParams;
      
      if (entityType === 'snippet') {
        endpoint = '/WorkflowTaskDefSnippet/SearchUDFs';
        bodyParams = { snippetId: entityId, searchTerm: searchTerm || '' };
      } else if (entityType === 'workitem') {
        endpoint = '/WorkItem/SearchUDFsApi';
        bodyParams = { workItemId: entityId, term: searchTerm || '' };
      } else {
        endpoint = '/WorkflowDef/SearchUDFsApi';
        bodyParams = { workflowDefId: entityId, term: searchTerm || '' };
      }

      const response = await fetch(endpoint, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: new URLSearchParams(bodyParams)
      });

      if (!response.ok) {
        throw new Error('Search request failed');
      }

      const data = await response.json();
      
      if (!data.success) {
        throw new Error(data.message || 'Search failed');
      }

      // Transform the results to match our component's expected format
      const results = data.results.map(result => ({
        id: result.Id,
        name: result.Name,
        description: result.IsHighlighted ? 'Contains matching fields' : 'No matching fields',
        taskId: result.Id,
        isHighlighted: result.IsHighlighted,
        order: result.Order
      }));
      
      setSearchResults(results);
    } catch (err) {
      setError('Failed to search fields. Please try again.');
      console.error('Search UDF error:', err);
    } finally {
      setLoading(false);
    }
  };

  const handleResultClick = (result) => {
    // Use the provided navigation handler or dispatch a custom event
    if (onNavigateToTask) {
      onNavigateToTask(result.taskId, entityId);
    } else {
      const event = new CustomEvent('navigateToTask', {
        detail: { 
          taskId: result.taskId,
          ...(entityType === 'snippet' ? { snippetId: entityId } : 
              entityType === 'workitem' ? { workItemId: entityId } : 
              { workflowId: entityId })
        }
      });
      window.dispatchEvent(event);
    }
    
    onClose();
  };

  const handleKeyPress = (event) => {
    if (event.key === 'Enter') {
      handleSearch();
    }
  };

  // Load initial data when modal opens and clear when closes
  useEffect(() => {
    if (open && entityId) {
      handleInitialLoad();
    } else if (!open) {
      setSearchTerm('');
      setSearchResults([]);
      setError(null);
    }
  }, [open, entityId]);

  const handleInitialLoad = async () => {
    setLoading(true);
    setError(null);

    try {
      // Determine the correct API endpoint based on entity type
      let endpoint;
      let bodyParams;
      
      if (entityType === 'snippet') {
        endpoint = '/WorkflowTaskDefSnippet/SearchUDFs';
        bodyParams = { snippetId: entityId, searchTerm: '' };
      } else if (entityType === 'workitem') {
        endpoint = '/WorkItem/SearchUDFsApi';
        bodyParams = { workItemId: entityId, term: '' };
      } else {
        endpoint = '/WorkflowDef/SearchUDFsApi';
        bodyParams = { workflowId: entityId, term: '' };
      }

      const response = await fetch(endpoint, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: new URLSearchParams(bodyParams)
      });

      if (!response.ok) {
        throw new Error('Initial load failed');
      }

      const data = await response.json();
      
      if (!data.success) {
        throw new Error(data.message || 'Initial load failed');
      }

      // Transform the results to match our component's expected format
      const results = data.results.map(result => ({
        id: result.Id,
        name: result.Name,
        description: result.IsHighlighted ? 'Contains matching fields' : 'No matching fields',
        taskId: result.Id,
        isHighlighted: result.IsHighlighted,
        order: result.Order
      }));
      
      setSearchResults(results);
    } catch (err) {
      setError('Failed to load search data. Please try again.');
      console.error('Initial load error:', err);
    } finally {
      setLoading(false);
    }
  };

  const modalContent = (
    <Box sx={{ p: 2 }}>
      {/* Search Input */}
      <Box sx={{ display: 'flex', gap: 1, mb: 2 }}>
        <FAWInput
          fullWidth
          placeholder="Search for fields..."
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
          onKeyPress={handleKeyPress}
          disabled={loading}
        />
        <FAWButton
          variant="contained"
          onClick={handleSearch}
          disabled={loading || !searchTerm.trim()}
        >
          Search
        </FAWButton>
      </Box>

      {/* Instructions */}
      <FAWTypography variant="body2" color="text.secondary" sx={{ mb: 2 }}>
        Click a highlighted task to navigate to it.
      </FAWTypography>

      {/* Error Display */}
      {error && (
        <Alert severity="error" sx={{ mb: 2 }}>
          {error}
        </Alert>
      )}

      {/* Loading State */}
      {loading && (
        <Box sx={{ display: 'flex', justifyContent: 'center', p: 3 }}>
          <CircularProgress />
        </Box>
      )}

      {/* Search Results */}
      {!loading && searchResults.length > 0 && (
        <Box sx={{ 
          maxHeight: 400, 
          overflowY: 'auto',
          border: '1px solid #e0e0e0',
          borderRadius: 1
        }}>
          <List>
            {searchResults.map((result) => (
              <ListItem key={result.id} disablePadding>
                <ListItemButton 
                  onClick={() => handleResultClick(result)}
                  sx={{ 
                    '&:hover': { backgroundColor: '#f0f0f0' },
                    backgroundColor: result.isHighlighted ? '#e3f2fd' : 'transparent'
                  }}
                >
                  <ListItemText
                    primary={
                      <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
                        <FAWTypography 
                          variant="body2" 
                          sx={{ 
                            fontWeight: result.isHighlighted ? 'bold' : 'normal',
                            color: result.isHighlighted ? '#1976d2' : 'inherit'
                          }}
                        >
                          {result.name}
                        </FAWTypography>
                        {result.isHighlighted && (
                          <FAWTypography variant="caption" sx={{ 
                            backgroundColor: '#1976d2', 
                            color: 'white', 
                            px: 1, 
                            py: 0.5, 
                            borderRadius: 1,
                            fontSize: '0.7rem'
                          }}>
                            MATCH
                          </FAWTypography>
                        )}
                      </Box>
                    }
                    secondary={result.description}
                  />
                </ListItemButton>
              </ListItem>
            ))}
          </List>
        </Box>
      )}

      {/* No Results */}
      {!loading && searchTerm && searchResults.length === 0 && !error && (
        <Box sx={{ textAlign: 'center', p: 3 }}>
          <FAWTypography variant="body2" color="text.secondary">
            No fields found matching "{searchTerm}"
          </FAWTypography>
        </Box>
      )}

      {/* Initial State */}
      {!loading && !searchTerm && searchResults.length === 0 && (
        <Box sx={{ textAlign: 'center', p: 3 }}>
          <FAWTypography variant="body2" color="text.secondary">
            Enter a search term to find additional fields
          </FAWTypography>
        </Box>
      )}
    </Box>
  );

  return (
    <FAWModal
      open={open}
      onClose={onClose}
      title="Find Additional Fields"
      maxWidth="md"
      content={modalContent}
    />
  );
};

export default SearchUDFModal;
