import React, { useState } from 'react';
import {
  Box,
  Menu,
  MenuItem,
  ListItemIcon,
  ListItemText
} from '@mui/material';
import FAWTooltip from '../../../FAWTooltip';
// Import lens icons from @diligentcorp/atlas-react-icons/lens
import { 
  AddIcon,          // Plus 
  StackIcon,        // Section 
  NextStepIcon,     // Step 
  ReviewIcon,       // Review 
  AlertOnIcon,      // Notification 
  ForkIcon,         // Route 
  FlagIcon,         // Action 
  FlowsIcon,        // Conditional snippet 
  ClearIcon         // Close
} from "@diligentcorp/atlas-react-icons/lens";

/**
 * Add Task Dropdown Component
 * Provides a dropdown menu with common task types for adding new tasks
 */
const AddTaskDropdown = ({ onAddTask, disabled = false }) => {
  const [anchorEl, setAnchorEl] = useState(null);
  const open = Boolean(anchorEl);

  const handleClick = (event) => {
    setAnchorEl(event.currentTarget);
  };

  const handleClose = () => {
    setAnchorEl(null);
  };

  const handleAddTask = (taskType) => {
    // Close the menu first to remove aria-hidden
    handleClose();
    
    // Defer the callback to allow menu to close and focus to restore first
    setTimeout(() => {
      onAddTask(taskType);
    }, 100);
  };

  // Common task types with their lens icons and labels
  const taskTypes = [
    {
      type: 'SECTION',
      label: 'Add Section',
      icon: <StackIcon size="lg" style={{ display: 'block', width: '20px', height: '20px' }} />
    },
    {
      type: 'STEP',
      label: 'Add Step',
      icon: <NextStepIcon size="lg" style={{ display: 'block', width: '20px', height: '20px' }} />
    },
    {
      type: 'REVIEW',
      label: 'Add Review',
      icon: <ReviewIcon size="lg" style={{ display: 'block', width: '20px', height: '20px' }} />
    },
    {
      type: 'NOTIFICATION',
      label: 'Add Notification',
      icon: <AlertOnIcon size="lg" style={{ display: 'block', width: '20px', height: '20px' }} />
    },
    {
      type: 'ROUTE_TO',
      label: 'Add Route To',
      icon: <ForkIcon size="lg" style={{ display: 'block', width: '20px', height: '20px' }} />
    },
    {
      type: 'ACTION',
      label: 'Add Action',
      icon: <FlagIcon size="lg" style={{ display: 'block', width: '20px', height: '20px' }} />
    },
    {
      type: 'IF',
      label: 'Add Conditional Snippet',
      icon: <FlowsIcon size="lg" style={{ display: 'block', width: '20px', height: '20px' }} />
    },
    {
      type: 'CLOSE',
      label: 'Add Close',
      icon: <ClearIcon size="lg" style={{ display: 'block', width: '20px', height: '20px' }} />
    }
  ];

  return (
    <>
      <FAWTooltip title="Add new task">
        <Box
          id="add-task-button"
          component="button"
          aria-haspopup="true"
          aria-expanded={open}
          disabled={disabled}
          sx={{
            backgroundColor: '#282e37',
            borderRadius: '4px',
            p: '4px',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            width: '32px',
            height: '32px',
            cursor: disabled ? 'not-allowed' : 'pointer',
            opacity: disabled ? 0.5 : 1,
            border: 'none',
            '&:hover': {
              backgroundColor: disabled ? '#282e37' : '#1a1d23'
            },
            '&:focus': {
              outline: '2px solid #007bff',
              outlineOffset: '2px'
            }
          }}
          onClick={disabled ? undefined : handleClick}
        >
          <AddIcon size="lg" style={{ color: 'white', display: 'block', width: '20px', height: '20px' }} />
        </Box>
      </FAWTooltip>

      <Menu
        anchorEl={anchorEl}
        open={open}
        onClose={handleClose}
        anchorOrigin={{
          vertical: 'bottom',
          horizontal: 'right',
        }}
        transformOrigin={{
          vertical: 'top',
          horizontal: 'right',
        }}
        PaperProps={{
          sx: {
            mt: 1,
            minWidth: 200,
            boxShadow: '0px 4px 20px rgba(0, 0, 0, 0.15)',
            borderRadius: '8px',
            border: '1px solid #e0e0e0'
          }
        }}
        // Accessibility improvements
        disableAutoFocusItem={false}
        autoFocus={false}
        MenuListProps={{
          'aria-labelledby': 'add-task-button',
          role: 'menu'
        }}
      >
        {taskTypes.map((task) => (
          <MenuItem
            key={task.type}
            onClick={() => handleAddTask(task.type)}
            sx={{
              py: 1.5,
              px: 2,
              '&:hover': {
                backgroundColor: '#f5f5f5'
              }
            }}
          >
            <ListItemIcon sx={{ minWidth: 40 }}>
              {task.icon}
            </ListItemIcon>
            <ListItemText 
              primary={task.label}
              primaryTypographyProps={{
                fontSize: '14px',
                fontWeight: 500
              }}
            />
          </MenuItem>
        ))}
      </Menu>
    </>
  );
};

export default AddTaskDropdown;