import React, { useState, useRef, Fragment } from "react";
import { COLORS } from "../../../Helpers/Const";
import { colors } from "../../../utils/designTokens";

const Editor = ({ value, handleChange }) => {
  const [val, setVal] = useState(value);
  const [isEditMode, setIsEditMode] = useState(false);
  const ref = useRef();

  ref.current = value;

  return (
    <Fragment>
      {isEditMode ? (
        <input
          type="text"
          value={val}
          onChange={(e) => setVal(e.target.value)}
          onBlur={() => {
            if (val && val.length > 0) {
              handleChange({ value: val, prevValue: ref.current });
            }
            setIsEditMode(false);
            setVal(ref.current);
          }}
          style={{
            backgroundColor: COLORS.LIGHT_BLUE,
            height: "15px",
            border: "none",
            maxWidth: "120px",
            color: colors.type.default || "#000",
            paddingLeft: "5px",
            paddingRight: "5px",
          }}
        />
      ) : (
        <span onClick={() => setIsEditMode(true)}>{ref.current}</span>
      )}
    </Fragment>
  );
};

export default Editor;
