/**
 * Form data initialization utility for WorkflowTaskDetail component
 */

/**
 * Converts ASP.NET SelectList to React dropdown options format
 * @param {object} selectList - ASP.NET SelectList object
 * @returns {array} - Array of options with value and text properties
 */
const convertSelectListToOptions = (selectList) => {
  if (!selectList) return [];
  
  // Handle different SelectList serialization formats
  if (Array.isArray(selectList)) {
    // If it's already an array, return as is
    return selectList;
  }
  
  if (selectList.Items && Array.isArray(selectList.Items)) {
    // If it has Items property, convert each item
    return selectList.Items.map(item => ({
      value: item.Value || item.value || '',
      text: item.Text || item.text || item.label || ''
    }));
  }
  
  if (selectList.SelectedValue !== undefined) {
    // If it's a simple SelectList with SelectedValue
    return [];
  }
  
  // Fallback: try to extract from any enumerable properties
  if (typeof selectList === 'object') {
    const options = [];
    for (const key in selectList) {
      if (selectList.hasOwnProperty(key) && typeof selectList[key] === 'object') {
        const item = selectList[key];
        if (item.Value !== undefined || item.value !== undefined) {
          options.push({
            value: item.Value || item.value || '',
            text: item.Text || item.text || item.label || ''
          });
        }
      }
    }
    return options;
  }
  
  return [];
};

/**
 * Initializes form data from task detail object
 * @param {object} taskDetail - Task detail object from API
 * @returns {object} - Initialized form data object
 */
export const initializeFormData = (taskDetail) => {
  if (!taskDetail) {
    return getDefaultFormData();
  }


  return {
    // Basic fields
    id: taskDetail.Id || taskDetail.id || '',
    Name: taskDetail.isNewlyCreated ? '' : taskDetail.Name || '', // Keep Name empty initially - user must enter it
    Description: taskDetail.isNewlyCreated ? '' : (taskDetail.Description || taskDetail.description || ''), // Follow same pattern as Name
    Type: taskDetail.Type || '',
    Status: taskDetail.Status || '',
    Duration: taskDetail.Duration || 0,
    Order: taskDetail.Order || 0,
    WorkQueueId: taskDetail.WorkQueueId || '',
    ContainerId: taskDetail.ContainerId || '',
    ParentWorkflowTaskDefinitionId: taskDetail.ParentWorkflowTaskDefinitionId || '',
    LockId: taskDetail.LockId || 0,
    SettingsXML: taskDetail.SettingsXML || '',
    
    // Boolean flags
    IsRequired: taskDetail.IsRequired || false,
    SLADays: taskDetail.SLADays || 0,
    IsPhase: taskDetail.IsPhase || false,
    IsSnippetTask: taskDetail.IsSnippetTask || false,
    ShowCaseStatusDropdown: taskDetail.ShowCaseStatusDropdown || true,
    AllowEditTaskName: taskDetail.AllowEditTaskName || false,
    NewlyCreated: taskDetail.NewlyCreated || false,
    IsPrecondition: taskDetail.IsPrecondition || false,
    ShowCheckBox: taskDetail.ShowCheckBox || true,
    Highlighted: taskDetail.Highlighted || false,
    EvaluateAllConditions: taskDetail.EvaluateAllConditions || false,
    IsAutoComplete: taskDetail.IsAutoComplete || false,
    HasRouteTo: taskDetail.HasRouteTo || taskDetail.hasRouteTo || false,
    
    // String fields
    ControllerName: taskDetail.ControllerName || 'WorkflowDef',
    SendAlertsTo: taskDetail.SendAlertsTo || '',
    WorkflowDefinitionTypeCode: taskDetail.WorkflowDefinitionTypeCode || '',
    WorkflowDefinitionType: taskDetail.WorkflowDefinitionType || 'WorkflowDefinition',
    ActionType: taskDetail.ActionType || '', // Keep only the capitalized version for backend
    ThirdPartyApprovalStatus: taskDetail.ThirdPartyApprovalStatus || '',
    InternalOwnerQueueId: taskDetail.InternalOwnerQueueId || '',
    FormToSendId: taskDetail.FormToSendId || '',
    FormToSendRecipientCode: taskDetail.FormToSendRecipientCode || '',
    FormToSendEmail: taskDetail.FormToSendEmail || '',
    FormToSendLanguageCode: taskDetail.FormToSendLanguageCode || '',
    NotificationWorkQueueId: taskDetail.NotificationWorkQueueId || '',
    NotificationDistributionList: taskDetail.NotificationDistributionList || '',
    NotificationDefinitionId: taskDetail.NotificationDefinitionId || '',
    NotificationLanguageCode: taskDetail.NotificationLanguageCode || '',
    Icon: taskDetail.Icon || '',
    
    // JSON fields required by backend
    SecurimateFormLanguagesByFormIdJson: taskDetail.SecurimateFormLanguagesByFormIdJson || '{}',
    FormNamesByIdJson: taskDetail.FormNamesByIdJson || '{"":"--SELECT--"}',
    
    // Array fields
    ThirdPartyNotificationFieldCodes: taskDetail.ThirdPartyNotificationFieldCodes || [],
    UserDefinedFields: taskDetail.UserDefinedFields || [],
    UserDefinedFieldsAll: taskDetail.UserDefinedFieldsAll || [], // Use backend naming
    ThirdPartyFields: taskDetail.ThirdPartyFields || [],
    ThirdPartyFieldsAll: taskDetail.ThirdPartyFieldsAll || [], // Use backend naming
    RelatedFields: taskDetail.RelatedFields || [],
    RelatedFieldsAll: taskDetail.RelatedFieldsAll || [], // Use backend naming
    Statuses: convertSelectListToOptions(taskDetail.Statuses) || [],
    WorkQueues: convertSelectListToOptions(taskDetail.WorkQueues) || [],
    Actions: taskDetail.Actions || [], // Use backend naming
    ThirdPartyApprovalStatuses: taskDetail.ThirdPartyApprovalStatuses || [], // Use backend naming
    SecurimateFormSubmissionSelection: taskDetail.SecurimateFormSubmissionSelection || [], // Use backend naming
    RecipientSelection: taskDetail.RecipientSelection || [], // Use backend naming
    FormLanguageSelection: taskDetail.FormLanguageSelection || [], // Use backend naming
    NotificationWorkQueueSelection: taskDetail.NotificationWorkQueueSelection || [],
    ThirdPartyNotificationSelection: taskDetail.ThirdPartyNotificationSelection || [],
    NotificationTypeSelection: taskDetail.NotificationTypeSelection || [],
    NotificationLanguageSelection: taskDetail.NotificationLanguageSelection || [],
    NotificationControls: taskDetail.NotificationControls || [], // Use backend naming
    ConditionalSnippetRulesJson: taskDetail.ConditionalSnippetRulesJson || [],
    Categories: taskDetail.Categories || [],
    FormNames: taskDetail.FormNames || [],
  };
};

